(function() {
var he_ch_1_Verses = [
  {num:1,words:[["Ma o lenei faauta,", "And now behold,"], ["sa oo i le amataga o le fasefulu o tausaga o le nofoaiga a faamasino i le nuu o Nifae,", "it came to pass in the commencement of the fortieth year of the reign of the judges over the people of Nephi,"], ["na amata ai ona i ai o se faigata tuga i totonu o tagata sa Nifaē.", "there began to be a serious difficulty among the people of the Nephites."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["ua maliu Paorana ,", "Pahoran had died,"], ["ma ua alu i le ala o le lalolagi uma;", "and gone the way of all the earth;"], ["o lea na amata ai ona i ai o se finauga tuga e faatatau i se e tatau ona mauaina le nofoa-faamasino i le au uso,", "therefore there began to be a serious contention concerning who should have the judgment– seat among the brethren,"], ["o e o atalii ia o Paorana.", "who were the sons of Pahoran."]]},
  {num:3,words:[["O lenei o igoa nei o i latou o e na finau mo le nofoa-faamasino,", "Now these are their names who did contend for the judgment– seat,"], ["o e foi na mafua ai ona finau o le nuu:", "who did also cause the people to contend:"], ["o Paorana,", "Pahoran,"], ["Paanati,", "Paanchi,"], ["ma Pakumenae.", "and Pacumeni."]]},
  {num:4,words:[["O lenei e le o atalii uma nei o Paorana,", "Now these are not all the sons of Pahoran,"], ["(ona sa ia te ia ni atalii e toatele),", "(for he had many) but these are they who did contend for the judgment– seat;"], ["ae o i latou ia na finau mo le nofoa-faamasino;", "therefore,"], ["o lea na latou faatutupu ai ni vaega se tolu i totonu o le nuu.", "they did cause three divisions among the people."]]},
  {num:5,words:[["E ui i lea,", "Nevertheless,"], ["sa oo ina tofia Paorana e le leo o le nuu e avea ma faamasino sili ma se kovana i luga o le nuu o Nifae.", "it came to pass that Pahoran was appointed by the voice of the people to be chief judge and a governor over the people of Nephi."]]},
  {num:6,words:[["Ma sa oo ina ua iloa e Pakumenae ua le mafai ona ia maua o le nofoa-faamasino,", "And it came to pass that Pacumeni, when he saw that he could not obtain the judgment– seat,"], ["sa ia aufaatasi ma le leo o le nuu.", "he did unite with the voice of the people."]]},
  {num:7,words:[["Ae faauta,", "But behold,"], ["o Paanati,", "Paanchi,"], ["ma le vaega lena o le nuu o e na mananao e tatau ona avea o ia ma o latou kovana,", "and that part of the people that were desirous that he should be their governor, was exceedingly wroth;"], ["sa feita tele;", "therefore,"], ["o lea sa ia faia ai ia taitai ese ia tagata i upu faaviivii ia tutu ae e fouvale faasaga i o latou uso.", "he was about to flatter away those people to rise up in rebellion against their brethren."]]},
  {num:8,words:[["Ma sa oo ina ole'ā faia e ia lenei mea,", "And it came to pass as he was about to do this,"], ["faauta,", "behold,"], ["sa ave o ia,", "he was taken,"], ["ma faamasinoina e tusa ma le leo o le nuu,", "and was tried according to the voice of the people,"], ["ma sa faasalaina ai i le oti;", "and condemned unto death;"], ["ona sa ia tulai ae i le fouvale ma saili e faaumatia le saolotoga o le nuu.", "for he had raised up in rebellion and sought to destroy the liberty of the people."]]},
  {num:9,words:[["O lenei ina ua vaai i latou ia o tagata o e na mananao ia avea o ia mo o latou kovana ua faasalaina o ia i le oti,", "Now when those people who were desirous that he should be their governor saw that he was condemned unto death,"], ["o lea sa latou feita,", "therefore they were angry,"], ["ma faauta,", "and behold,"], ["sa latou auina atu se tasi e igoa ia Kisakumena,", "they sent forth one Kishkumen,"], ["i le nofoa-faamasino lava o Paorana,", "even to the judgment– seat of Pahoran,"], ["ma fasioti Paorana ao nofo o ia i luga o le nofoa-faamasino.", "and murdered Pahoran as he sat upon the judgment–seat."]]},
  {num:10,words:[["Ma sa tuliloa o ia e auauna a Paorana;", "And he was pursued by the servants of Pahoran;"], ["ae faauta, sa saosaoa tele le sola a Kisakumena,", "but behold,"], ["sa le mafai ai e se tagata ona maua o ia.", "so speedy was the flight of Kishkumen that no man could overtake him."]]},
  {num:11,words:[["Ma sa alu atu o ia ia i latou o e na auina atu o ia,", "And he went unto those that sent him,"], ["ma sa latou osia uma se feagaiga,", "and they all entered into a covenant,"], ["ioe,", "yea,"], ["ua latou tauto i lo latou Tufuga tumau-faavavau,", "swearing by their everlasting Maker,"], ["o le a latou le taua i se tasi o Kisakumena na fasiotia Paorana.", "that they would tell no man that Kishkumen had murdered Pahoran."]]},
  {num:12,words:[["O lea,", "Therefore,"], ["sa le iloa Kisakumena i totonu o tagata o Nifae,", "Kishkumen was not known among the people of Nephi,"], ["ona sa ofu faanana o ia i le taimi na ia fasiotia ai Paorana. Ma o Kisakumena ma lana vaega,", "for he was in disguise at the time that he murdered Pahoran. And Kishkumen and his band,"], ["o e na osia le feagaiga faatasi ma ia,", "who had covenanted with him,"], ["sa latou faafefiloi i latou lava i totonu o tagata,", "did mingle themselves among the people,"], ["i se ala sa le mafai ai ona maua i latou uma;", "in a manner that they all could not be found;"], ["ae o le toatele o i latou na maua sa faasalaina i le oti .", "but as many as were found were condemned unto death."]]},
  {num:13,words:[["Ma o lenei faauta,", "And now behold,"], ["sa tofia Pakumenae,", "Pacumeni was appointed,"], ["e tusa ma le leo o le nuu,", "according to the voice of the people,"], ["e avea o se faamasino sili ma se kovana i luga o le nuu,", "to be a chief judge and a governor over the people,"], ["e nofo e sui i lona uso o Paorana;", "to reign in the stead of his brother Pahoran;"], ["ma sa tusa ai lona suitulagaga ma lana aia tatau. Ma o nei mea uma sa faia i le lona fasefulu o tausaga o le nofoaiga a faamasino;", "and it was according to his right. And all this was done in the fortieth year of the reign of the judges;"], ["ma sa faaiuina le tausaga.", "and it had an end."]]},
  {num:14,words:[["Ma sa oo i le lona fasefulu ma le tasi o tausaga o le nofoaiga a faamasino,", "And it came to pass in the forty and first year of the reign of the judges,"], ["sa faapotopoto faatasi e sa Lamanā se autau o tagata e le mafaitaulia,", "that the Lamanites had gathered together an innumerable army of men,"], ["ma sa latou faaauupegaina i latou i pelu,", "and armed them with swords,"], ["ma simetea,", "and with cimeters and with bows,"], ["ma aufana, ma ufanafana,", "and with arrows,"], ["ma pulou-tau,", "and with head– plates,"], ["ma ufifatafata,", "and with breastplates,"], ["ma talita o ituaiga uiga eseese uma.", "and with all manner of shields of every kind."]]},
  {num:15,words:[["Ma sa latou toe o mai i lalo ina ia latou sii mai le taua e faasaga ia sa Nifaē. Ma sa taitaiina i latou e se tagata na igoa ia Korianetuma;", "And they came down again that they might pitch battle against the Nephites. And they were led by a man whose name was Coriantumr;"], ["ma o ia o se e tupuga mai ia Sara'emila;", "and he was a descendant of Zarahemla;"], ["ma o ia o se na faatuiese mai totonu o sa Nifaē;", "and he was a dissenter from among the Nephites;"], ["ma o ia o se tagata sa tino ese ma le malosi.", "and he was a large and a mighty man."]]},
  {num:16,words:[["O lea,", "Therefore,"], ["o le tupu o sa Lamanā,", "the king of the Lamanites,"], ["o lona igoa o Tupalota,", "whose name was Tubaloth,"], ["o le atalii o ia o Amorona ,", "who was the son of Ammoron,"], ["sa manatu o Korianetuma,", "supposing that Coriantumr,"], ["ona o ia o se tagata malosi,", "being a mighty man,"], ["e mafai ona tu atu o ia e faasaga ia sa Nifaē,", "could stand against the Nephites,"], ["i lona malosi ma lona atamai tele foi,", "with his strength and also with his great wisdom,"], ["e oo ina maua ai e ia le pule i tagata sa Nifaē i le auina atu o ia—", "insomuch that by sending him forth he should gain power over the Nephites—"]]},
  {num:17,words:[["O lea na ia faaosoina ai i latou i le ita,", "Therefore he did stir them up to anger,"], ["ma sa ia faapotopoto faatasi ana autau,", "and he did gather together his armies,"], ["ma sa ia tofia Korianetuma e avea ma o latou taitai,", "and he did appoint Coriantumr to be their leader,"], ["ma sa ia faatonuina ia latou savavali ane i lalo i le laueleele o Sara'emila e tau faasaga i tagata sa Nifaē.", "and did cause that they should march down to the land of Zarahemla to battle against the Nephites."]]},
  {num:18,words:[["Ma sa oo ona o finauga e tele ma faigatā e tele sa i ai i le malo,", "And it came to pass that because of so much contention and so much difficulty in the government,"], ["sa latou le tuuina ai ni leoleo ia lava i le laueleele o Sara'emila;", "that they had not kept sufficient guards in the land of Zarahemla;"], ["ona sa latou manatu ua fefefe sa Lamanā e o mai i le moa o o latou laueleele e osofaia lena aai tele o Sara'emila.", "for they had supposed that the Lamanites durst not come into the heart of their lands to attack that great city Zarahemla."]]},
  {num:19,words:[["Peitai sa oo ina savali mai Korianetuma i luma o lana autau toatele,", "But it came to pass that Coriantumr did march forth at the head of his numerous host,"], ["ma o mai i luga o tagata o le aai,", "and came upon the inhabitants of the city,"], ["ma sa televave tele mai la latou savaliga sa leai se taimi mo sa Nifaē e faapotopoto faatasi ai a latou autau.", "and their march was with such exceedingly great speed that there  was no time for the Nephites to gather together their armies."]]},
  {num:20,words:[["O lea na sala ai i lalo e Korianetuma le leoleoga i le faitotoa o le aai,", "Therefore Coriantumr did cut down the watch by the entrance of the city,"], ["ma savavali mai faatasi ma lana autau atoa i totonu o le aai,", "and did march forth with his whole army into the city,"], ["ma sa latou fasiotia tagata uma o e na tetee atu ia te i latou,", "and they did slay everyone who did oppose them,"], ["sa oo ina latou maua le aai atoa.", "insomuch that they did take possession of the whole city."]]},
  {num:21,words:[["Ma sa oo ina o Pakumenae,", "And it came to pass that Pacumeni,"], ["o le sa faamasino sili,", "who was the chief judge,"], ["ua sola i luma o Korianetuma,", "did flee before Coriantumr,"], ["seia oo atu i pa o le aai. Ma sa oo ina taia o ia e Korianetuma faalagolago i le pa,", "even to the walls of the city. And it came to pass that Coriantumr did smite him against the wall,"], ["sa oo ai ina oti o ia. Ma sa faapea ona iu o aso o Pakumenae.", "insomuch that he died. And thus ended the days of Pacumeni."]]},
  {num:22,words:[["Ma o lenei,", "And now when Coriantumr saw that he was in possession of the city of Zarahemla,"], ["ina ua vaai Korianetuma ua ia mauaina le aai o Sara'emila,", "and saw that the Nephites had fled before them,"], ["ma vaai atu ua sosola sa Nifaē i o latou luma,", "and were slain,"], ["ma ua fasiotia, ma avea,", "and were taken,"], ["ma ua lafo i le falepuipui,", "and were cast into prison,"], ["ma ua ia maua le olo e sili ona malosi i le laueleele atoa,", "and that he had obtained the possession of the strongest hold in all the land,"], ["sa faalototeleina lona loto sa oo ina a alu o ia e faasaga i le laueleele atoa.", "his heart took courage insomuch that he was about to go forth against all the land."]]},
  {num:23,words:[["Ma o lenei sa le nofo o ia i le laueleele o Sara'emila,", "And now he did not tarry in the land of Zarahemla,"], ["ae sa savali atu o ia faatasi ma se autau toatele,", "but he did march forth with a large army,"], ["e agai moni atu i le aai o Nuumau;", "even towards the city of Bountiful;"], ["ona o lona lotomau o le alu atu ma sala atu lona ala i le pelu,", "for it was his determination to go forth and cut his way through with the sword,"], ["ina ia mafai ona ia maua o vaega i matu o le laueleele.", "that he might obtain the north parts of the land."]]},
  {num:24,words:[["Ma,", "And,"], ["i le manatu o lo latou malosi silisili sa i le ogatotonu o le laueleele,", "supposing that their greatest strength was in the center of the land,"], ["o lea na ia savali atu ai,", "therefore he did march forth,"], ["ma le tuu atu ia te i latou se taimi latou te faapotopoto faatasi ai i latou lava vagana ai i ni tino toaitiiti;", "giving them no time to assemble themselves together save it were in small bodies;"], ["ma o le ala lenei na latou pauu ai i o latou luga ma sala i latou i lalo i le eleele.", "and in this manner they did fall upon them and cut them down to the earth."]]},
  {num:25,words:[["Ae faauta,", "But behold,"], ["o lenei savaliga a Korianetuma e ala atu i le ogatotonu o le laueleele na tuuina atu ai ia Moronaea se mea lelei tele atu i luga o i latou,", "this march of Coriantumr through the center of the land gave Moronihah great advantage over them,"], ["e ui i le toatele naua o sa Nifaē o e ua fasiotia.", "notwithstanding the greatness of the number of the Nephites who were slain."]]},
  {num:26,words:[["Aua faauta,", "For behold,"], ["na manatu Moronaea ua fefefe sa Lamanā e o mai i le ogatotonu o le laueleele,", "Moronihah had supposed that the Lamanites durst not come into the center of the land,"], ["ae o le a latou osofaia aai o loo i ai faataamilo i tuaoi e pei ona sa latou faia seia oo mai i le taimi nei;", "but that they would attack the cities round about in the borders as they had hitherto done;"], ["o lea na faatonu ai e Moronaea ia tuu a latou autau malolosi e tausia vaega na faataamilo latalata i tuaoi.", "therefore Moronihah had caused that their strong armies should maintain those parts round about by the borders."]]},
  {num:27,words:[["Peitai faauta,", "But behold,"], ["sa le fefefe sa Lamanā e tusa ma lona manao,", "the Lamanites were not frightened according to his desire,"], ["ae ua latou o mai i le ogatotonu o le laueleele,", "but they had come into the center of the land,"], ["ma ua latou ave le aai laumua,", "and had taken the capital city which was the city of Zarahemla,"], ["o le aai lea o Sara'emila, ma ua savavali e ala mai i vaega sili ona tauluulu o le laueleele,", "and were marching through the most capital parts of the land,"], ["ma fasiotia tagata i se fasiga tele,", "slaying the people with a great slaughter,"], ["e aofia ai tane,", "both men,"], ["o fafine,", "women,"], ["ma tamaiti,", "and children,"], ["ma latou ave mo i latou le tele o aai ma le tele o olo malolosi.", "taking possession of many cities and of many strongholds."]]},
  {num:28,words:[["Ae ina ua iloa e Moronaea lenei mea,", "But when Moronihah had discovered this,"], ["sa ia auina vave atu loa Liae ma se autau e taamilo ane e sisio mai i latou ae latou te lei oo atu i le laueleele o Nuumau.", "he immediately sent forth Lehi with an army round about to head them before they should come to the land Bountiful."]]},
  {num:29,words:[["Ma sa faapea ona ia faia;", "And thus he did;"], ["ma sa ia sisio mai i latou ae latou te lei oo atu i le laueleele o Nuumau,", "and he did head them before they came to the land Bountiful,"], ["ma tau ma i latou,", "and gave unto them battle,"], ["sa oo ina amata ona latou toe solomuli i tua agai i le laueleele o Sara'emila.", "insomuch that they began to retreat back towards the land of Zarahemla."]]},
  {num:30,words:[["Ma sa oo ina sisio mai i latou e Moronaea i la latou solomuliga,", "And it came to pass that Moronihah did head them in their retreat,"], ["ma sa tau ma i latou,", "and did give unto them battle,"], ["sa oo ina avea ma taua faamasaa toto tele;", "insomuch that it became an exceedingly bloody battle;"], ["ioe,", "yea,"], ["e toatele na fasiotia,", "many were slain,"], ["ma i totonu o le aofai o e na fasiotia na maua ai foi Korianetuma .", "and among the number who were slain Coriantumr was also found."]]},
  {num:31,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["sa le mafai ona solomuli sa Lamanā i soo se itu,", "the Lamanites could not retreat either way,"], ["po o i le itu i matu,", "neither on the north,"], ["po o i le itu i saute,", "nor on the south,"], ["po o i le itu i sasae,", "nor on the east,"], ["po o i le itu i sisifo,", "nor on the west,"], ["ona sa siomia i latou i itu uma e sa Nifaē.", "for they were surrounded on every hand by the Nephites."]]},
  {num:32,words:[["Ma sa faapea ona lafo e Korianetuma sa Lamanā i le totonugalemu o sa Nifaē,", "And thus had Coriantumr plunged the Lamanites into the midst of the Nephites,"], ["sa oo ina maua i latou i le pule a sa Nifaē,", "insomuch that they were in the power of the Nephites,"], ["ma o ia lava ia ua fasiotia,", "and he himself was slain,"], ["ma sa tuu mai e sa Lamanā i latou lava i lima o sa Nifaē.", "and the Lamanites did yield themselves into the hands of the Nephites."]]},
  {num:33,words:[["Ma sa oo ina toe maua e Moronaea le aai o Sara'emila,", "And it came to pass that Moronihah took possession of the city of Zarahemla again,"], ["ma sa ia faatonuina ia o ese atu i fafo o le laueleele i le filemu sa Lamanā o e na ave faapagotaina.", "and caused that the Lamanites who had been taken prisoners should depart out of the land in peace."]]},
  {num:34,words:[["Ma sa faapea ona iu o le lona fasefulu ma le tasi o tausaga o le nofoaiga a faamasino.", "And thus ended the forty and first year of the reign of the judges."]]},
];
renderVerseSet(he_ch_1_Verses, 'he-ch1-verses');

var he_ch_2_Verses = [
  {num:1,words:[["Ma sa oo i le lona fasefulu ma le lua o tausaga o le nofoaiga a faamasino,", "And it came to pass in the forty and second year of the reign of the judges,"], ["ina ua uma ona toe faatuina e Moronaea le filemu i le va o sa Nifaē ma sa Lamanā,", "after Moronihah had established again peace between the Nephites and the Lamanites,"], ["faauta, sa leai se tasi e nofo i le nofoa-faamasino;", "behold there was no one to fill the judgment– seat;"], ["o lea na amata ai ona toe i ai o se finauga i totonu o le nuu e uiga i le e tatau ona nofo i le nofoa-faamasino.", "therefore there began to be a contention again among the people concerning who should fill the judgment – seat."]]},
  {num:2,words:[["Ma sa oo ina tofia Helamana,", "And it came to pass that Helaman,"], ["o le o le atalii o Helamana,", "who was the son of Helaman,"], ["i le leo o le nuu,", "was appointed to fill the judgment– seat,"], ["e nofo i le nofoa-faamasino.", "by the voice of the people."]]},
  {num:3,words:[["Ae faauta,", "But behold,"], ["o Kisakumena ,", "Kishkumen,"], ["o le na fasiotia Paorana,", "who had murdered Pahoran,"], ["sa nofo lamalama o ia e faaumatia foi ia Helamana;", "did lay wait to destroy Helaman also;"], ["ma sa lagolagoina o ia e lana vaega,", "and he was upheld by his band,"], ["o e na ulu i se feagaiga ia leai se tasi ia ona iloa lona amioleaga.", "who had entered into a covenant that no one should know his wickedness."]]},
  {num:4,words:[["Ona sa i ai se tasi e igoa ia Katianetona ,", "For there was one Gadianton,"], ["o le sa matua silisili ona atamai i upu e tele,", "who was exceedingly expert in many words,"], ["ma i lona faiva foi,", "and also in his craft,"], ["o le faia lea o le galuega faalilolilo o le fasioti tagata ma le faomea;", "to carry on the secret work of murder and of robbery;"], ["o lea na avea ai o ia ma taitai o le vaega a Kisakumena.", "therefore he became the leader of the band of Kishkumen."]]},
  {num:5,words:[["O lea na ia olegia ai i latou,", "Therefore he did flatter them,"], ["ma Kisakumena foi,", "and also Kishkumen,"], ["afai latou te faanofoina o ia i le nofoa-faamasino o le a ia tuu atu ia te i latou o e ua auai i lana vaega ia tuu i latou i le mana ma le pule i totonu o le nuu;", "that if they would place him in the judgment– seat he would grant unto those who belonged to his band that they should be placed in power and authority among the people;"], ["o lea na saili ai Kisakumena e fasioti Helamana.", "therefore Kishkumen sought to destroy Helaman."]]},
  {num:6,words:[["Ma sa oo ina a'o alu atu o ia agai i le nofoa-faamasino e fasioti Helamana,", "And it came to pass as he went forth towards the judgment– seat to destroy Helaman,"], ["faauta,", "behold  one of the servants of Helaman,"], ["e i ai se tasi o auauna a Helamana, sa i fafo i le po,", "having been out by night,"], ["ma sa ia maua,", "and having obtained,"], ["e ala i le ofu faanana,", "through disguise,"], ["se malamalama e uiga i fuafuaga ia na faia e lenei vaega e fasioti Helamana—", "a knowledge of those plans which had been laid by this band to destroy Helaman—"]]},
  {num:7,words:[["Ma sa oo ina fetaiai o ia ma Kisakumena,", "And it came to pass that he met Kishkumen,"], ["ma ia tuu atu ia te ia se faailoga;", "and he gave unto him a sign;"], ["o lea na faailoa mai ai e Kisakumena ia te ia le mea ua manao i ai o ia, e manao na te taitai atu o ia i le nofoa-faamasino,", "therefore Kishkumen made known unto him the object of his desire,"], ["ina ia mafai ona ia fasiotia Helamana.", "desiring that he would conduct him to the judgment– seat that he might murder Helaman."]]},
  {num:8,words:[["Ma ina ua iloa e le auauna a Helamana le loto atoa o Kisakumena,", "And when the servant of Helaman had known all the heart of Kishkumen,"], ["ma o lona faamoemoe o le fasioti tagata lea,", "and how that it was his object to murder,"], ["ma o le faamoemoe foi lea o i latou uma o e na auai i lana vaega e fasioti tagata,", "and also that it was the object of all those who belonged to his band to murder,"], ["ma faomea,", "and to rob,"], ["ma maua le pule, (ma o la latou fuafuaga faalilolilo lenei,", "and to gain power,"], ["ma la latou pulepulega),", "(and this was their secret plan,"], ["sa fai atu le auauna a Helamana ia Kisakumena:", "and their combination) the servant of Helaman said unto Kishkumen:"], ["Ta o atu ia i le nofoa-faamasino.", "Let us go forth unto the judgment– seat."]]},
  {num:9,words:[["O lenei sa fiafia tele Kisakumena i lenei mea,", "Now this did please Kishkumen exceedingly,"], ["ona sa manatu o ia o le a ia faataunuuina lana fuafuaga;", "for he did suppose that he should accomplish his design;"], ["ae faauta,", "but behold, the servant of Helaman,"], ["a'o laua o atu i le nofoa-faamasino,", "as they were going forth unto the judgment– seat,"], ["sa tui e le auauna a Helamana ia Kisakumena seia tau i le fatu,", "did stab Kishkumen even to the heart,"], ["sa oo ina pau o ia i lalo ua oti e aunoa ma se leo.", "that he fell dead without a groan."], ["Ma sa momoe atu o ia ma tau atu ia Helamana mea uma sa ia vaaia,", "And he ran and told Helaman all the things which he had seen,"], ["ma faalogo i ai,", "and heard,"], ["ma ia faia.", "and done."]]},
  {num:10,words:[["Ma sa oo ina auina atu e Helamana ni tagata e tapu'e mai lenei vaega o tagata faomea ma fasioti tagata faalilolilo,", "And it came to pass that Helaman did send forth to take this band of robbers and secret murderers,"], ["ina ia fasiotia i latou e tusa ai ma le tulafono.", "that they might be executed according to the law."]]},
  {num:11,words:[["Ae faauta,", "But behold,"], ["ina ua iloa e Katianetona ua le foi mai Kisakumena sa fefe o ia nei faaumatia o ia;", "when Gadianton had found that Kishkumen did not return he feared lest that he should be destroyed;"], ["o lea na ia faatonu atu ai i lana vaega ia mulimuli atu ia te ia.", "therefore he caused that his band should follow him."], ["Ma ua alu la latou solaaga i fafo mai le laueleele,", "And they took their flight out of the land,"], ["i se ala lilo,", "by a secret way,"], ["i totonu o le vao; ma o lea ina ua auina atu e Helamana ni tagata e tapu'e i latou,", "into the wilderness;"], ["sa le mafai ona maua i latou i se mea.", "and thus when Helaman sent forth to take them they could nowhere be found."]]},
  {num:12,words:[["Ma o le a tala atu ni isi mea e uiga i lenei Katianetona i se taimi o mulimuli mai. Ma sa faapea ona faaiuina o le lona fasefulu ma le lua o tausaga o le nofoaiga a faamasino i le nuu o Nifae.", "And more of this Gadianton shall be spoken hereafter. And thus ended the forty and second year of the reign of the judges over the people of Nephi."]]},
  {num:13,words:[["Ma faauta,", "And behold,"], ["o le faaiuga o lenei tusi,", "in the end of this book ye shall see that this Gadianton did prove the overthrow,"], ["o le a outou vaai ai o lenei Katianetona na pogai ai le faatoilaloina, ioe,", "yea,"], ["le toetoe lava o le faafanoga atoa o le nuu o Nifae.", "almost the entire destruction of the people of Nephi."]]},
  {num:14,words:[["Faauta e le o faatatau lau tala i le iuga o le tusi a Helamana,", "Behold I do not mean the end of the book of Helaman,"], ["ae o le uiga o lau tala o le iuga o le tusi a Nifae,", "but I mean the end of the book of Nephi,"], ["lea na ou aumai ai le tala atoa lea ua ou tusia.", "from which I have taken all the account which I have written."]]},
];
renderVerseSet(he_ch_2_Verses, 'he-ch2-verses');

var he_ch_3_Verses = [
  {num:1,words:[["Ma o lenei,", "And now it came to pass in the forty and third year of the reign of the judges,"], ["sa oo i le lona fasefulu ma le tolu o tausaga o le nofoaiga a faamasino,", "there was no contention among the people of Nephi save it were a little pride which was in the church,"], ["sa leai ni finauga i totonu o le nuu o Nifae vagana ai sina faamaualuga laitiiti sa i ai i totonu o le ekalesia, lea na mafua mai ai ni faatuiesega itiiti i totonu o le nuu,", "which did cause some little dissensions among the people,"], ["o ni mataupu sa faaleleia i le faaiuga o le lona fasefulu ma le tolu o tausaga.", "which affairs were settled in the ending of the forty and third year."]]},
  {num:2,words:[["Ma sa leai se finauga i totonu o le nuu i le lona fasefulu ma le fa o tausaga;", "And there was no contention among the people in the forty and fourth year;"], ["pe sa i ai foi se finauga tele i le lona fasefulu ma le lima o tausaga.", "neither was there much contention in the forty and fifth year."]]},
  {num:3,words:[["Ma sa oo i le lona fasefulu ma le ono o tausaga,", "And it came to pass in the forty and sixth,"], ["ioe,", "yea,"], ["sa i ai finauga e tele ma faatuiesega e tele;", "there was much contention and many dissensions;"], ["ia na toatele naua e na o ese atu ai i fafo mai le laueleele o Sara'emila,", "in the which there were an exceed– ingly great many who departed out of the land of Zarahemla,"], ["ma o atu i le laueleele i matu e fai mo o latou tofi le laueleele.", "and went forth unto the land northward to inherit the land."]]},
  {num:4,words:[["Ma sa latou malaga atu i se mea mamao tele lava,", "And they did travel to an exceedingly great distance,"], ["sa oo ina latou tau atu i vaituloto tetele ma vaitafe e tele.", "insomuch that they came to large bodies of water and many rivers."]]},
  {num:5,words:[["Ioe,", "Yea,"], ["sa oo ina latou salalau atu i vaega uma o le laueleele,", "and even they did spread forth into all parts of the land,"], ["i soo se vaega sa lei faatafunaina ma aunoa ma laau matua,", "into whatever parts it had not been rendered desolate and without timber,"], ["ona o le toatele o tagata o e sa faia muamua mo o latou tofi le laueleele.", "because of the many inhabitants who had before inherited the land."]]},
  {num:6,words:[["Ma o lenei,", "And now no part of the land was desolate,"], ["sa leai se vaega o le laueleele sa faatafunaina, vagana ai laau matua;", "save it were for timber;"], ["ae ona o le tele o le faafanoga o tagata o e sa aina muamua le laueleele o lea na taua ai o tafuna .", "but because of the greatness of the destruction of the people who had before inhabited the land it was called desolate."]]},
  {num:7,words:[["Ma ona sa itiiti laau matua sa i ai i luga o le laueleele,", "And there being but little timber upon the face of the land,"], ["e ui i lea o tagata o e na o atu i ai sa oo ina atamamai tele i le faaaogaina o le sima;", "nevertheless the people who went forth became exceedingly expert in the working of cement;"], ["o lea na latou fausia ai fale i le sima,", "therefore they did build houses of cement,"], ["ia na latou nonofo ai.", "in the which they did dwell."]]},
  {num:8,words:[["Ma sa oo ina latou uluola ma salalau atu,", "And it came to pass that they did multiply and spread,"], ["ma o atu mai le laueleele i saute i le laueleele i matu,", "and did go forth from the land south ward to the land northward,"], ["ma salalau atu sa oo ina amata ona ufitia ia te i latou luga o le eleele atoa,", "and did spread insomuch that they began to cover the face of the whole earth,"], ["mai le sami i saute i le sami i matu,", "from the sea south to the sea north,"], ["mai le sami i sisifo i le sami i sasae.", "from the sea west to the sea east."]]},
  {num:9,words:[["Ma o tagata o e sa i le laueleele i matu,", "And the people who were in the land northward did dwell in tents,"], ["sa nonofo i faleie,", "and in houses of cement,"], ["ma i fale sima,", "and they did suffer whatsoever tree should spring up upon the face of the land that it should grow up,"], ["ma sa latou tuu soo se laau e totogo ae i luga o le laueleele ia tupu ae,", "that in time they might have timber to build their houses,"], ["ina ia latou maua ai i se taimi laau e fau ai o latou fale, ioe,", "yea,"], ["o latou aai,", "their cities,"], ["o latou malumalu,", "and their temples,"], ["ma o latou sunako,", "and their synagogues,"], ["ma o latou falesa,", "and their sanctuaries,"], ["ma o latou fale uiga eseese uma.", "and all manner of their buildings."]]},
  {num:10,words:[["Ma sa oo talu ai ona sa tau le maua tele laau matua i le laueleele i matu,", "And it came to pass as timber was exceedingly scarce in the land northward,"], ["o lea sa latou auina atu ai le tele e ala i vaa .", "they did send forth much by the way of shipping."]]},
  {num:11,words:[["Ma sa faapea ona latou faia ia mafai ai e tagata i le laueleele i matu ona latou fausia o aai e tele,", "And thus they did enable the people in the land northward that they might build many cities,"], ["i laau ma i le sima.", "both of wood and of cement."]]},
  {num:12,words:[["Ma sa oo ina sa i ai le toatele o tagata o le nuu o Amona,", "And it came to pass that there were many of the people of Ammon,"], ["o e o ni sa Lamanā i lo latou fananau mai,", "who were Lamanites by birth,"], ["na o atu foi i lenei laueleele.", "did also go forth into this land."]]},
  {num:13,words:[["Ma o lenei e tele talafaamaumau na tausia e uiga i le taualumaga a nei tagata,", "And now there are many records kept of the proceedings of this people,"], ["e le toatele o nei tagata,", "by many of this people,"], ["ia ua faapitoa ma tetele lava,", "which are particular and very large,"], ["e uiga ia te i latou.", "concerning them."]]},
  {num:14,words:[["Ae faauta,", "But behold,"], ["o se tasi vaeselau o taualumaga a nei tagata,", "a hundredth part of the proceedings of this people,"], ["ioe,", "yea,"], ["o le tala e uiga i sa Lamanā ma sa Nifaē,", "the account of the Lamanites and of the Nephites,"], ["ma a latou taua,", "and their wars,"], ["ma finauga,", "and contentions,"], ["ma faatuiesega,", "and dissensions,"], ["ma a latou talaiga,", "and their preaching,"], ["ma a latou valoaga,", "and their prophecies,"], ["ma a latou felauaiga i vaa ma lo latou fausiaina o vaa,", "and their  shipping and their building of ships,"], ["ma lo latou fausiaina o malumalu ,", "and their building of temples,"], ["ma sunako ma o latou falesa;", "and of synagogues and their sanctuaries,"], ["ma lo latou amiotonu,", "and their righteousness,"], ["ma lo latou amioleaga,", "and their wickedness,"], ["ma a latou fasiotiga tagata,", "and their murders,"], ["ma a latou faomeaga,", "and their robbings,"], ["ma a latou vetega,", "and their plundering,"], ["ma mea inosia ma faitaaga uiga eseese uma,", "and all manner of abominations and whoredoms,"], ["e le mafai ona tuu i totonu o lenei tusi.", "cannot be contained in this work."]]},
  {num:15,words:[["Ae faauta,", "But behold,"], ["e tele tusi o i ai ma talafaamaumau e tele o ituaiga eseese,", "there are many books and many records of every kind,"], ["ma sa tausia faapitoa i latou e tagata sa Nifaē.", "and they have been kept chiefly by the Nephites."]]},
  {num:16,words:[["Ma sa tuulima faasolo mai i lalo nei talafaamaumau mai le tasi tupulaga i le isi tupulaga e tagata sa Nifae,", "And they have been handed down from one generation to another by the Nephites,"], ["seia oo ina latou pauu atu i le solitulafono ma fasiotia,", "even until they have fallen into transgression and have been murdered,"], ["veteina,", "plundered,"], ["ma tutulia,", "and hunted,"], ["ma esiesi,", "and driven forth,"], ["ma fasia,", "and slain,"], ["ma faataapeapeina i luga o le eleele,", "and scattered upon the face of the earth, and mixed with the Lamanites until they are no more called the Nephites,"], ["ma fefiloi ma sa Lamanā seia oo ina lē toe taua i latou o ni sa Nifaē,", "becoming wicked,"], ["ona ua amioleaga ma aivao,", "and wild,"], ["ma feai,", "and ferocious,"], ["ioe,", "yea,"], ["ua avea lava ma ni sa Lamanā.", "even becoming Lamanites."]]},
  {num:17,words:[["Ma o lenei ou te toe foi atu i lau tala;", "And now I return again to mine account;"], ["o lea,", "therefore,"], ["o mea na ou fai atu ai ua tuanai atu ina ua mavae lea ona i ai o finauga tetele,", "what I have spoken had passed after there had been great contentions,"], ["ma faalavelave,", "and disturbances,"], ["ma taua,", "and wars,"], ["ma faatuiesega,", "and dissensions,"], ["i totonu o le nuu o Nifae.", "among the people of Nephi."]]},
  {num:18,words:[["Ua faaiuina le lona fasefulu ma le ono o tausaga o le nofoaiga a faamasino;", "The forty and sixth year of the reign of the judges ended;"]]},
  {num:19,words:[["Ma sa oo sa i ai pea finauga tetele i le laueleele,", "And it came to pass that there was still great contention in the land,"], ["ioe,", "yea,"], ["e oo lava i le lona fasefulu ma le fitu o tausaga,", "even in the forty and seventh year,"], ["ma le lona fasefulu ma le valu foi o tausaga.", "and also in the forty and eighth year."]]},
  {num:20,words:[["E ui i lea sa nofo Helamana i le nofoa-faamasino ma le faamasinotonu ma le fai mea tutusa;", "Nevertheless Helaman did fill the judgment– seat with justice and equity;"], ["ioe,", "yea,"], ["sa ia tausisi e tausi tulafono,", "he did observe to keep the statutes,"], ["ma faamasinoga,", "and the judgments,"], ["ma poloaiga a le Atua;", "and the commandments of God;"], ["ma sa ia faia le mea sao i le silafaga a le Atua e le aunoa;", "and he did do that which was right in the sight of God continually;"], ["ma sa ia savali i ala o lona tamā,", "and he did walk after the ways of his father,"], ["sa oo ina manuia o ia i le laueleele.", "insomuch that he did prosper in the land."]]},
  {num:21,words:[["Ma sa oo ina i ai ia te ia ni atalii se toalua. Sa ia tuu atu i le ulumatua le igoa o Nifae ,", "And it came to pass that he had two sons. He gave unto the eldest the name of Nephi,"], ["ma i le laitiiti,", "and unto the youngest,"], ["le igoa o Liae . Ma sa amata ona laua tutupu ae i le Alii.", "the name of Lehi. And they began to grow up unto the Lord."]]},
  {num:22,words:[["Ma sa oo ina amata ona taofia o taua ma finauga,", "And it came to pass that the wars and contentions began to cease,"], ["i se vaega itiiti,", "in a small degree,"], ["i totonu o tagata sa Nifaē,", "among the people of the Nephites,"], ["i le taufaaiuga o le lona fasefulu ma le valu o tausaga o le nofoaiga a faamasino i le nuu o Nifae.", "in the latter end of the forty and eighth year of the reign of the judges over the people of Nephi."]]},
  {num:23,words:[["Ma sa oo i le lona fasefulu ma le iva o tausaga o le nofoaiga a faamasino,", "And it came to pass in the forty and ninth year of the reign of the judges,"], ["sa i ai le filemu aveaveai pea sa faatuina i le laueleele,", "there was continual peace established in the land,"], ["i mea uma, vagana ai pulepulega faalilolilo ia na faatutu e Katianetona le faomea i vaega sili ona aina o le laueleele,", "all save it were the secret combinations which Gadianton the robber had established in the more settled parts of the land,"], ["ia sa le iloa i le taimi lena e i latou o e sa i le ao o le malo;", "which at that time were not known unto those who were at the head of government;"], ["o lea sa le faaumatia ese ai i latou mai le laueleele.", "therefore they were not destroyed out of the land."]]},
  {num:24,words:[["Ma sa oo i lenei lava tausaga sa i ai le manuia tele naua i le ekalesia, sa oo ina i ai le afe ma afe o e na latou faaauai i latou lava i le ekalesia,", "And it came to pass that in this same year there was exceedingly great prosperity in the church,"], ["ma sa papatisoina i le salamo.", "insomuch that there were thousands  who did join themselves unto the church and were baptized unto repentance."]]},
  {num:25,words:[["Ma sa matua tele naua le manuia o le ekalesia,", "And so great was the prosperity of the church,"], ["ma matua tele naua faamanuiaga na sasaa ifo i luga o tagata,", "and so many the blessings which were poured out upon the people,"], ["e oo i faitaulaga sili ma aoao sa le mafuatiaina lo latou ofo tele.", "that even the high priests and the teachers were themselves astonished beyond measure."]]},
  {num:26,words:[["Ma sa oo ina manuia lava le galuega a le Alii i le papatisoina ma le faatasia i le ekalesia a le Atua,", "And it came to pass that the work of the Lord did prosper unto the baptizing and uniting to the church of God,"], ["o agaga e toatele,", "many souls,"], ["ioe,", "yea,"], ["e oo lava i le atu sefulu o afe.", "even tens of thousands."]]},
  {num:27,words:[["Ua faapea ona mafai ona tatou vaai ai e alofa mutimutivale le Alii ia te i latou uma o e e valaau atu i lona suafa paia,", "Thus we may see that the Lord is merciful unto all who will, in the sincerity of their hearts,"], ["ma le faamaoni o o latou loto.", "call upon his holy name."]]},
  {num:28,words:[["Ioe,", "Yea,"], ["ua faapea ona tatou vaai ai ua tatala le faitotoa o le lagi i tagata uma ,", "thus we see that the gate of heaven is open unto all,"], ["ioe ia i latou lava o e e talitonu i le suafa o Iesu Keriso,", "even to those who will believe on the name of Jesus Christ,"], ["o le o le Alo o le Atua.", "who is the Son of God."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["ua tatou vaai e mafai e soo se tasi e manao i ai ona piimau i luga i le afioga a le Atua,", "we see that whosoever will may lay hold upon the word of God,"], ["lea ua vave ma mamana, lea o le a veteina ai le poto leaga ma mailei ma fuafuaga uma a le tiapolo,", "which is quick and powerful,"], ["ma taitai atu ai le tagata o Keriso i le ala lauitiiti ma vaapiapi ,", "which shall divide asunder all the cunning and the snares and the wiles of the devil,"], ["i luga atu o le vanu pagatia tumau-faavavau lea ua saunia e tofatumoanaina ai e e amioleaga—", "and lead the man of Christ in a strait and narrow course across that everlasting gulf of misery which is prepared to engulf the wicked—"]]},
  {num:30,words:[["Ma faatulaueleele o latou agaga,", "And land their souls,"], ["ioe,", "yea,"], ["o latou agaga ola pea,", "their immortal souls,"], ["i le aao taumatau o le Atua i le malo o le lagi,", "at the right hand of God in the kingdom of heaven,"], ["e nonofo i lalo faatasi ma Aperaamo,", "to sit down with Abraham,"], ["ma Isaako,", "and Isaac,"], ["ma faatasi ma Iakopo,", "and with Jacob,"], ["ma faatasi ma o tatou tamā paia uma,", "and with all our holy fathers,"], ["e le toe o atu i fafo.", "to go no more out."]]},
  {num:31,words:[["Ma sa i ai i lenei tausaga olioliga faifai pea i le laueleele o Sara'emila,", "And in this year there was continual rejoicing in the land of Zarahemla,"], ["ma i itu laueleele uma faataamilo ai,", "and in all the regions round about,"], ["e oo lava i le laueleele atoa lea sa maua e sa Nifaē.", "even in all the land which was possessed by the Nephites."]]},
  {num:32,words:[["Ma sa oo ina i ai le filemu ma le olioli tele naua i le vaega na totoe o le lona fasefulu ma le iva o tausaga;", "And it came to pass that there was peace and exceedingly great joy in the remainder of the forty and ninth year;"], ["ioe,", "yea,"], ["ma sa i ai foi le filemu ma le olioli tele faifai pea i le lona limasefulu o tausaga o le nofoaiga a faamasino.", "and also there was continual peace and great joy in the fiftieth year of the reign of the judges."]]},
  {num:33,words:[["Ma sa i ai foi le filemu i le lona limasefulu ma le tasi o tausaga o le nofoaiga a faamasino,", "And in the fifty and first year of the reign of the judges there was peace also,"], ["vagana ai le faamaualuga lea na amata ona ulu mai i totonu o le ekalesia—e le o le ekalesia a le Atua,", "save it were the pride which began to enter into the church—not into the church of God,"], ["ae i totonu o loto o tagata o e na fai mai ua latou auai i le ekalesia a le Atua—", "but into the hearts of the people who professed to belong to the church of God—"]]},
  {num:34,words:[["Ma sa faafefeteina i latou i luga i le faamaualuga ,", "And they were lifted up in pride,"], ["e oo lava i le latou sauaina o le toatele o o latou uso. O lenei o se mea leaga tele lenei mea,", "even to the persecution of many of their brethren. Now this was a great evil,"], ["lea na mafua ai ona mafatia o le toatele o le vaega sili ona lotomaualalalo o tagata i sauaga tetele,", "which did cause the more humble part of the people to suffer great persecutions,"], ["ma latou asa atu ai i puapuaga e tele.", "and to wade through much affliction."]]},
  {num:35,words:[["E ui i lea,", "Nevertheless they did fast and pray oft,"], ["sa latou anapopogi ma tatalo soo,", "and did wax stronger and stronger in their humility,"], ["ma sa faasolo malolosi ma atili malolosi ai i lo latou lotomaualalalo ,", "and firmer and firmer in the faith of Christ,"], ["ma mausali ma atili mausali ai i le faatuatua ia Keriso, seia oo ina faatutumuina o latou agaga i le olioli ma le faamafanafanaga,", "unto the filling their souls with joy and consolation,"], ["ioe,", "yea,"], ["seia oo ina faamamaina ma faapaiaina o latou loto,", "even to the purifying and the sanctification of their hearts,"], ["o le faapaiaga lea e oo mai ona o lo latou tuu atu o o latou loto i le Atua.", "which sanctification cometh because of their yielding their hearts unto God."]]},
  {num:36,words:[["Ma sa oo ina faaiuina foi le lona limasefulu ma le lua o tausaga i le filemu,", "And it came to pass that the fifty and second year ended in peace also,"], ["vagana ai le faamaualuga tele lea ua ulu i totonu o loto o tagata;", "save it were the exceedingly great pride which had gotten into the hearts of the people;"], ["ma o le pogai ona o a latou oa ua tele naua ma lo latou manuia i luga o le laueleele;", "and it was because of their exceedingly great riches and their prosperity in the land;"], ["ma sa tupu ae i luga o i latou mai lea aso i lea aso.", "and it did grow upon them from day to day."]]},
  {num:37,words:[["Ma sa oo i le lona limasefulu ma le tolu o tausaga o le nofoaiga a faamasino,", "And it came to pass in the fifty and third year of the reign of the judges,"], ["ua maliu Helamana,", "Helaman died,"], ["ma sa amata ona nofo o lona atalii matua o Nifae e suitulaga ia te ia. Ma sa oo ina nofo o ia i le nofoa-faamasino ma le faamasinotonu ma le fai mea tutusa;", "and his eldest son Nephi began to reign in his stead. And it came to pass that he did fill the judgment– seat with justice and equity;"], ["ioe,", "yea,"], ["sa ia tausi poloaiga a le Atua,", "he did keep the commandments of God,"], ["ma sa savali o ia i ala o lona tamā.", "and did walk in the ways of his father."]]},
];
renderVerseSet(he_ch_3_Verses, 'he-ch3-verses');

var he_ch_4_Verses = [
  {num:1,words:[["Ma sa oo i le lona limasefulu ma le fa o tausaga,", "And it came to pass in the fifty and fourth year there were many dissensions in the church,"], ["sa i ai faatuiesega e tele i le ekalesia, ma sa i ai foi se finauga i totonu o tagata,", "and there was also a contention among the people,"], ["sa oo ina i ai le faamasaa toto tele.", "insomuch that there was much bloodshed."]]},
  {num:2,words:[["Ma sa fasia ma tutuli ese i fafo mai le laueleele le vaega faatuiese,", "And the rebellious part were slain and driven out of the land,"], ["ma sa latou o atu i le tupu o sa Lamanā.", "and they did go unto the king of the Lamanites."]]},
  {num:3,words:[["Ma sa oo ina latou taumafai e faaoso sa Lamanā ia o atu e tau faasaga ia sa Nifaē;", "And it came to pass that they did endeavor to stir up the Lamanites to war against the Nephites;"], ["ae faauta,", "but behold,"], ["sa matua fefefe lava sa Lamanā,", "the Lamanites were exceedingly afraid,"], ["sa oo ina latou le faalogo i upu a tagata faatuiese na.", "insomuch that they would not hearken to the words of those dissenters."]]},
  {num:4,words:[["Ae sa oo i le lona limasefulu ma le ono o tausaga o le nofoaiga a faamasino,", "But it came to pass in the fifty and sixth year of the reign of the judges,"], ["sa i ai ni tagata faatuiese o e na o ese atu mai sa Nifaē i sa Lamanā;", "there were dissenters who went up from the Nephites unto the Lamanites;"], ["ma sa latou manumalo faatasi ma isi na i le faaosoina o i latou i le ita e faasaga ia sa Nifaē;", "and they succeeded with those others in stirring them up to anger against the Nephites;"], ["ma sa latou sauni i le tausaga atoa lena mo le taua.", "and they were all that year preparing for war."]]},
  {num:5,words:[["Ma o le lona limasefulu ma le fitu tausaga na latou o mai ai i lalo i le taua e faasaga ia sa Nifaē,", "And in the fifty and seventh year they did come down against the Nephites to battle,"], ["ma sa latou amataina le galuega o le oti;", "and they did commence the work of death;"], ["ioe,", "yea,"], ["sa oo ina latou manumalo ai i le lona limasefulu ma le valu o tausaga o le nofoaiga a faamasino i lo latou mauaina o le laueleele o Sara'emila;", "insomuch that in the fifty and eighth year of the reign of the judges they succeeded in obtaining possession of the land of Zarahemla;"], ["ioe,", "yea,"], ["ma laueleele uma lava,", "and also all the lands,"], ["e oo lava i le laueleele lea sa latalata ane i le laueleele o Nuumau.", "even unto the land which was near the land Bountiful."]]},
  {num:6,words:[["Ma sa tutulia sa Nifaē ma autau a Moronaea seia oo mai i le laueleele o Nuumau;", "And the Nephites and the armies of Moroni– hah were driven even into the land of Bountiful;"]]},
  {num:7,words:[["Ma o iina na latou fauolo ai e tetee ia sa Lamanā,", "And there they did fortify against the Lamanites,"], ["mai le sami i sisifo,", "from the west sea,"], ["e oo atu i sasae; o lona mamao e tusa ma se malaga a se tagata sa Nifaē i le aso atoa,", "even unto the east;"], ["i luga o le laina na latou fauoloina,", "it being a day’s journey for a Nephite,"], ["ma tuu ai a latou autau e puipui ai lo latou laueleele i matu.", "on the line which they had fortified and stationed their armies to defend their north country."]]},
  {num:8,words:[["Ma sa faapea ona maua e na tagata faatuiese o sa Nifaē,", "And thus those dissenters of the Nephites,"], ["i le fesoasoani a se autau toatele a sa Lamanā,", "with the help of a numerous army of the Lamanites,"], ["mea uma a sa Nifaē ia sa i le laueleele i saute. Ma o nei mea uma sa faia i le lona limasefulu ma le valu ma le lona limasefulu ma le iva o tausaga o le nofoaiga a faamasino.", "had obtained all the possession of the Nephites which was in the land southward. And all this was done in the fifty and eighth and ninth years of the reign of the judges."]]},
  {num:9,words:[["Ma sa oo i le tausaga e onosefulu o le nofoaiga a faamasino,", "And it came to pass in the sixtieth year of the reign of the judges,"], ["sa manumalo ai Moronaea ma ana autau i le maua mai o vaega e tele o le laueleele;", "Moronihah did succeed with  his armies in obtaining many parts of the land;"], ["ioe,", "yea,"], ["sa latou toe maua mai aai e tele ia sa pauu atu i lima o sa Lamanā.", "they regained many cities which had fallen into the hands of the Lamanites."]]},
  {num:10,words:[["Ma sa oo i le tausaga e onosefulu ma le tasi o le nofoaiga a faamasino na latou manumalo ai i le toe maua mai e oo i le afa o o latou laueleele uma.", "And it came to pass in the sixty and first year of the reign of the judges they succeeded in regaining even the half of all their possessions."]]},
  {num:11,words:[["O lenei o lea toesega tele mai ia sa Nifaē,", "Now this great loss of the Nephites,"], ["ma le fasiga tele lea na i ai i totonu ia te i latou,", "and the great slaughter which was among them,"], ["semanu e le tupu mai pe a na leai a latou amioleaga ma a latou mea inosia ia sa i ai i totonu a i te i latou;", "would not have happened had it not been for their wickedness and their abomination which was among them;"], ["ioe,", "yea,"], ["ma sa i ai foi ia mea i totonu o i latou o e na fai mai ua latou auai i le ekalesia a le Atua.", "and it was among those also who professed to belong to the church of God."]]},
  {num:12,words:[["Ma sa oo mai ia mea ona o le faamaualuluga o o latou loto,", "And it was because of the pride of their hearts,"], ["ona o a latou oa e tele naua,", "because of their exceeding riches,"], ["ioe,", "yea,"], ["na oo mai ona o lo latou faasaua i e matitiva ,", "it was because of their oppression to the poor,"], ["i le taofi o a latou meaai mai i e fia aai,", "withholding their food from the hungry,"], ["i le taofi o o latou ofu mai i e ua le lavalava,", "withholding their clothing from the naked,"], ["ma le fepoina o alafau o o latou uso lotomaualalalo,", "and smiting their humble brethren upon the cheek,"], ["faatauemu i mea ua paia,", "making a mock of that which was sacred,"], ["ma faafitia le agaga o le valoaga ma faaaliga,", "denying the spirit of prophecy and of revelation,"], ["ma fasioti tagata,", "murdering,"], ["ma fai le vete,", "plundering,"], ["ma pepelo,", "lying,"], ["gaoi,", "stealing,"], ["mulilulua,", "commit– ting adultery,"], ["ma tutu ae i finauga tetele,", "rising up in great contentions,"], ["ma sosola ese atu i le laueleele o Nifae,", "and deserting away into the land of Nephi,"], ["i tagata sa Lamanā—", "among the Lamanites—"]]},
  {num:13,words:[["Ma ona o lenei a latou amioleaga tele,", "And because of this their great wickedness,"], ["ma lo latou mitamitavale i lo latou lava malosi,", "and their boastings in their own strength,"], ["na tuua ai i latou e faalagolago i lo latou lava malosi;", "they were left in their own strength;"], ["o lea na latou le manuia ai,", "therefore they did not prosper,"], ["ae ua faapuapuagatia ai ma taia,", "but were afflicted and smitten,"], ["ma tutulia i luma o sa Lamanā,", "and driven before the Lamanites,"], ["seia oo ina toetoe lava a aveesea o latou laueleele uma.", "until they had lost possession of almost all their lands."]]},
  {num:14,words:[["Ae faauta,", "But behold,"], ["sa talai atu e Moronaea mea e tele i tagata ona o lo latou amioletonu,", "Moronihah did preach many things unto the people because of their iniquity,"], ["ma sa faapea foi ona talai atu e Nifae ma Liae,", "and also Nephi and Lehi,"], ["o e o atalii o Helamana,", "who were the sons of Helaman,"], ["mea e tele i tagata,", "did preach many things unto the people,"], ["ioe,", "yea,"], ["ma sa laua vavalo atu mea e tele ia te i latou e uiga ia latou amioletonu,", "and did prophesy many things unto them concerning their iniquities,"], ["ma mea o le a oo mai ia te i latou pe afai latou te le salamo ia latou agasala.", "and what should come unto them if they did not repent of their sins."]]},
  {num:15,words:[["Ma sa oo ina latou salamo,", "And it came to pass that they did repent,"], ["ma o le tulaga na oo i ai o lo latou salamo sa faapea foi ona amata ona latou manuia ai.", "and inasmuch as they did repent they did begin to prosper."]]},
  {num:16,words:[["Ona ua vaai atu Moronaea ua latou salamo sa ia taumafai e taitai atu i latou mai lea nofoaga i lea nofoaga,", "For when Moronihah saw that they did repent he did venture to lead them forth from place to place,"], ["ma mai lea aai i lea aai,", "and from city to city,"], ["seia oo ina latou toe maua mai le afa o a latou meatotino ma le afa o o latou laueleele uma.", "even until they had regained the one half of their property and the one– half of all their lands."]]},
  {num:17,words:[["Ma sa faapea ona faaiuina o le lona onosefulu ma le tasi o tausaga o le nofoaiga a faamasino.", "And thus ended the sixty and first year of the reign of the judges."]]},
  {num:18,words:[["Ma sa oo i le lona onosefulu ma le lua o tausaga o le nofoaiga a faamasino,", "And it came to pass in the sixty and second year of the reign of the judges,"], ["sa le mafai e Moronaea ona toe maua ni isi laueleele i luga o sa Lamanā.", "that Moronihah could obtain no more possessions over the Lamanites."]]},
  {num:19,words:[["O lea na latou tuu ai la latou fuafuaga ia maua mai le vaega na totoe o o latou laueleele,", "Therefore they did abandon their design to obtain the remainder of their lands,"], ["ona sa matua toatele tele sa Lamanā sa le mafai e sa Nifaē ona toe maua se mana i luga o i latou;", "for so numerous were the Lamanites that it became impossible for the Nephites to obtain more power over them;"], ["o lea na faaaoga ai e Moronaea ana autau uma i le taofiga o vaega na na ia avea.", "therefore Moronihah did employ all his armies in maintaining those parts which he had taken."]]},
  {num:20,words:[["Ma sa oo ina sa matatau tele sa Nifaē ona o le toatele tele o le aofai o sa Lamanā,", "And it came to pass,"], ["nei faatoilaloina i latou,", "because of the greatness of the number of the Lamanites the Nephites were in great fear,"], ["ma soli i lalo,", "lest they should be overpowered, and trodden down,"], ["ma fasiotia,", "and slain,"], ["ma faaumatia.", "and destroyed."]]},
  {num:21,words:[["Ioe,", "Yea,"], ["sa amata ona latou manatua valoaga a Alema,", "they began to remember the prophecies of Alma,"], ["ma upu foi a Mosaea;", "and also the words of Mosiah;"], ["ma sa latou vaai sa avea i latou ma ni tagata ua maaa,", "and they saw that they had been a stiffnecked people,"], ["ma sa latou tuu faameanoa poloaiga a le Atua;", "and that they had set at naught the commandments of God."]]},
  {num:22,words:[["Ma sa latou suia ma solia i lalo i o latou vae tulafono a Mosaea,", "And that they had altered and trampled under their feet the laws of Mosiah,"], ["po o mea ia na poloaiina ai o ia e le Alii e tuu atu i tagata;", "or that which the Lord commanded him to give unto the people;"], ["ma sa latou vaai ua faaeleeleaina a latou tulafono,", "and they saw that their laws had become corrupted,"], ["ma ua avea i latou ma tagata amioleaga,", "and that they had become a wicked people,"], ["ua oo ina latou amioleaga e pei lava o sa Lamanā.", "insomuch that they were wicked even like unto the Lamanites."]]},
  {num:23,words:[["Ma ona o lo latou amioletonu sa amata ona faaitiitia le ekalesia;", "And because of their iniquity the church had begun to dwindle;"], ["ma ua amata ona latou le talitonu i le agaga o valoaga ma le agaga o faaaliga;", "and they began to disbelieve in the spirit of prophecy and in the spirit of revelation;"], ["ma ua sisila totoa mai faafeagai ma o latou mata faamasinoga a le Atua.", "and the judgments of God did stare them in the face."]]},
  {num:24,words:[["Ma sa latou vaai ua latou vaivai ,", "And they saw that they had become weak,"], ["e pei o o latou uso,", "like unto their brethren,"], ["o sa Lamanā, ma ua le toe faasaoina i latou e le Agaga o le Alii;", "the Lamanites,"], ["ioe,", "and that the Spirit of the Lord did no more preserve them;"], ["ua alu ese mai ia te i latou,", "yea,"], ["aua e le afio le Agaga o le Alii i malumalu le paia—", "it had withdrawn from them because the Spirit of the Lord doth not dwell in unholy temples—"]]},
  {num:25,words:[["O lea na le toe faasaoina ai i latou e le Atua i lona mana faavavega ma le mafaatusalia,", "Therefore the Lord did cease to preserve them by his miraculous and matchless power,"], ["ona ua latou pauu atu i se tulaga o le le talitonu ma le amioleaga tele;", "for they had fallen into a state of unbelief and awful wickedness;"], ["ma sa latou vaai ua sili atu ona toatele o sa Lamanā nai lo i latou,", "and they saw that the Lamanites were exceedingly more numerous than they,"], ["ma e vagana ua latou pipii atu i le Alii lo latou Atua,", "and except they should cleave unto the Lord their God,"], ["o le a le maalofia lo latou fano.", "they must unavoidably perish."]]},
  {num:26,words:[["Aua faauta,", "For behold,"], ["ua latou vaai ua tutusa lava le malolosi o sa Lamanā ma lo latou malolosi,", "they saw that the strength of the Lamanites was as great as their strength,"], ["e oo lava i le tagata i le tagata. Ma sa faapea ona latou pauu atu i lenei solitulafono tele;", "even man for man. And thus had they fallen into this great transgression;"], ["ioe,", "yea,"], ["ua faapea ona latou vaivai,", "thus had they become weak,"], ["ona o lo latou solitulafono,", "because of their transgression,"], ["i se va e lei tele ni tausaga.", "in the space of not many years."]]},
];
renderVerseSet(he_ch_4_Verses, 'he-ch4-verses');

var he_ch_5_Verses = [
  {num:1,words:[["Ma sa oo i lenei lava tausaga,", "And it came to pass that in this same year,"], ["faauta,", "behold,"], ["sa tuu atu ai e Nifae le nofoa-faamasino i se tagata na igoa ia Sesorama.", "Nephi delivered up the judgment– seat to a man whose name was Cezoram."]]},
  {num:2,words:[["Ona o a latou tulafono ma o latou malo sa faatutuina i le leo o tagata,", "For as their laws and their governments were established by the voice of the people,"], ["ma o i latou o e na filifilia le leaga na sili atu ona toatele nai lo i latou o e na filifilia le lelei,", "and they who chose evil were more numerous than they who chose good,"], ["o lea na latou matua ai mo le faafanoga,", "therefore they were ripening for destruction,"], ["ona ua faaeleeleaina tulafono.", "for the laws had become corrupted."]]},
  {num:3,words:[["Ioe,", "Yea,"], ["ma sa le ona pau lea;", "and this was not all;"], ["ua avea i latou ma tagata ua maaa,", "they were a stiffnecked people,"], ["ua oo ina le mafai ona pulea o i latou i le tulafono po o le faamasinotonu,", "insomuch that they could not be governed by the law nor justice,"], ["ua nao le faaumatiaina ai o i latou.", "save it were to their destruction."]]},
  {num:4,words:[["Ma sa oo ina faanoanoa Nifae ona o lo latou amioletonu;", "And it came to pass that Nephi had become weary because of their iniquity;"], ["ma sa ia tuu atu ai le nofoa-faamasino,", "and he yielded up the judgment– seat,"], ["ma ia ave i ona luga e talai atu le afioga a le Atua i ona aso uma na totoe,", "and took it upon him to  preach the word of God all the remainder of his days,"], ["ma lona uso foi o Liae,", "and his brother Lehi also,"], ["i ona aso uma na totoe;", "all the remainder of his days;"]]},
  {num:5,words:[["Ona sa laua manatua upu na fai mai ai lo laua tamā o Helamana ia te i laua. Ma o upu nei na ia fai mai ai:", "For they remembered the words which their father Helaman spake unto them. And these are the words which he spake:"]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ou atalii e,", "my sons,"], ["ou te manao ia oulua manatua e tausi poloaiga a le Atua;", "I desire that ye should remember to keep the commandments of God;"], ["ma ou te manao ia oulua tau atu i tagata nei upu.", "and I would that ye should declare unto the people these words."], ["Faauta,", "Behold,"], ["ua ou tuu atu ia te oulua igoa o o tatou uluai matua ,", "I have given unto you the names of our first parents who came out of the land of Jerusalem;"], ["o e na o mai i fafo mai le laueleele o Ierusalema;", "and this I have done that when you remember your names ye may remember them;"], ["ma ua ou faia lenei mea ina a oulua manatua o oulua igoa ia oulua manatua ai i laua; ma a oulua manatua i laua ia oulua manatua a laua galuega;", "and when ye remember them ye may remember their works;"], ["ma a oulua manatua a laua galuega ia oulua iloa ai ua taua,", "and when ye remember their works ye may know how that it is said,"], ["ma ua tusia foi,", "and also written,"], ["e faapea na lelei .", "that they were good."]]},
  {num:7,words:[["O lea,", "Therefore,"], ["ou atalii e,", "my sons,"], ["ou te manao ina ia oulua faia le mea ua lelei,", "I would that ye should do that which is good, that it may be said of you,"], ["ina ia taua ma tusia e uiga ia te oulua,", "and also written,"], ["e pei ona taua ma tusia e uiga ia te i laua.", "even as it has been said and written of them."]]},
  {num:8,words:[["Ma o lenei ou atalii e,", "And now my sons,"], ["faauta,", "behold I have somewhat more to desire of you,"], ["ua ia te au ni isi mea e tele teisi atu ou te manao ai ia te oulua,", "which desire is,"], ["ma o lea manao o le,", "that ye may not do these things that ye may boast,"], ["ia oulua le faia nei mea ina ia oulua mitamita ai,", "but that ye may do these things to lay up for yourselves a treasure in heaven,"], ["ae ia oulua faia nei mea ina ia mafai ai ona oulua teuina mo oulua lava se oa i le lagi, ioe,", "yea,"], ["lea ua faavavau,", "which is eternal,"], ["ma lea e le mavae atu;", "and which fadeth not away;"], ["ioe,", "yea,"], ["ina ia mafai ona oulua maua lena meaalofa taua silisili o le ola faavavau,", "that ye may have that precious gift of eternal life,"], ["lea ua tatou maua se pogai tatou te manatu ai ua tuuina atu i o tatou tamā.", "which we have reason to suppose hath been given to our fathers."]]},
  {num:9,words:[["E,", "O remember,"], ["ia manatua,", "remember,"], ["ia manatua,", "my sons,"], ["ou atalii e,", "the words which king Benjamin spake unto his people;"], ["upu na tautala atu ai le tupu o Peniamina i lona nuu; ioe,", "yea,"], ["ia manatua ua leai se isi ala po o ni auala e mafai ona faaolaina ai le tagata,", "remember that there is no other way nor means whereby man can be saved,"], ["ua nao i le toto togiola o Iesu Keriso,", "only through the atoning blood of Jesus Christ,"], ["o le o le a afio mai;", "who shall come,"], ["ioe,", "yea,"], ["ia manatua e afio mai o ia e togiola le lalolagi .", "remember that he cometh to redeem the world."]]},
  {num:10,words:[["Ma ia manatua foi upu na tautala atu ai Amoleka ia Seseroma,", "And remember also the words which Amulek spake unto Zeezrom,"], ["i le aai o Amonaea;", "in the city of Ammonihah;"], ["ona sa fai atu o ia ia te ia e moni o le a afio mai le Alii e togiola lona nuu,", "for he said unto him that the Lord surely should come to redeem his people,"], ["ae o le a le afio mai o ia e togiola i latou ia latou agasala,", "but that he should not come to redeem them in their sins,"], ["ae e togiola i latou mai ia latou agasala.", "but to redeem them from their sins."]]},
  {num:11,words:[["Ma ua ia te ia le mana na tuuina mai ia te ia mai le Tamā e togiola ai i latou mai ia latou agasala ona o le salamo;", "And he hath power given unto him from the Father to redeem them from their sins because of repentance;"], ["o lea na ia auina mai ai ana agelu e talai mai tala o tuutuuga o le salamo,", "therefore he hath sent his angels to declare the tidings of the conditions of repentance,"], ["lea e aumai ai i latou i le mana o le Togiola,", "which bringeth unto the power of the Redeemer,"], ["mo le olataga o o latou agaga.", "unto the salvation of their souls."]]},
  {num:12,words:[["Ma o lenei,", "And now,"], ["ou atalii e,", "my sons,"], ["ia manatua,", "remember,"], ["ia manatua o luga lava o le papa o lo tatou Togiola,", "remember that it is upon the rock of our Redeemer,"], ["o le o Keriso lea,", "who is Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["e ao ina oulua atinae ai lo oulua faavae ;", "that ye must build your foundation;"], ["ina ia pe a auina mai e le tiapolo ana matagi malolosi,", "that when the devil shall send forth his mighty winds,"], ["ioe,", "yea,"], ["ana ufanafana i le asiosio,", "his shafts in the whirl wind,"], ["ioe,", "yea,"], ["pe a pesi mai ia te oulua ana uatoa uma ma lana afa malosi,", "when all his hail and his mighty storm shall beat upon you,"], ["o le a leai sona mana i luga o oulua e toso ifo ai oulua i lalo i le to o le pagatia ma le malaia e le gata,", "it shall have no power over you to drag you down to the gulf of misery and endless wo,"], ["ona o le papa lea ua oulua atinae ai i luga,", "because of the rock upon which ye are built,"], ["o le faavae mautinoa lea,", "which is a sure foundation,"], ["o se faavae lea afai e atiae ai tagata e le mafai lava ona pauu i latou.", "a  foundation whereon if men build they cannot fall."]]},
  {num:13,words:[["Ma sa oo ina o upu ia sa aoao atu e Helamana i ona atalii;", "And it came to pass that these were the words which Helaman taught to his sons;"], ["ioe,", "yea,"], ["e tele mea sa ia aoao atu ia te i laua ia ua le tusia,", "he did teach them many things which are not written,"], ["ma le tele foi o mea ua tusia.", "and also many things which are written."]]},
  {num:14,words:[["Ma sa laua manatua ana upu;", "And they did remember his words;"], ["ma o lea na laua o atu ai,", "and therefore they went forth,"], ["i le tausi i poloaiga a le Atua,", "keeping the commandments of God,"], ["e aoao atu le afioga a le Atua i totonu o tagata uma o Nifae,", "to teach the word of God among all the people of Nephi,"], ["e amata mai i le aai o Nuumau;", "beginning at the city Bountiful;"]]},
  {num:15,words:[["Ma mai iina i le aai o Kita,", "And from thenceforth to the city of Gid;"], ["ma mai le aai o Kita i le aai o Moleka;", "and from the city of Gid to the city of Mulek;"]]},
  {num:16,words:[["Ma mai lava i le tasi aai i le isi,", "And even from one city to another,"], ["seia oo ina laua o atu i totonu o tagata uma o Nifae o e sa i le laueleele i saute;", "until they had gone forth among all the people of Nephi who were in the land southward;"], ["ma mai iina i le laueleele o Sara'emila,", "and from thence into the land of Zarahemla,"], ["i totonu o sa Lamanā.", "among the Lamanites."]]},
  {num:17,words:[["Ma sa oo ina laua talai atu ma le mana tele,", "And it came to pass that they did preach with great power,"], ["sa oo ina laua faamaasiasiina le toatele o i latou o tagata faatuiese o e na o ese atu mai sa Nifaē,", "insomuch that they did confound many of those dissenters who had gone over from the Nephites,"], ["sa oo ina latou o mai i luma ma tautau mai a latou agasala, ma papatisoina i le salamo,", "insomuch that they came forth and did confess their sins and were baptized unto repentance,"], ["ma toe foi vave atu i sa Nifaē e taumafai e toe faalelei ia te i latou sese na latou faia.", "and immediately returned to the Nephites to endeavor to repair unto them the wrongs which they had done."]]},
  {num:18,words:[["Ma sa oo ina talai atu Nifae ma Liae i sa Lamanā ma le mana tele ma le pule,", "And it came to pass that Nephi and Lehi did preach unto the Lamanites with such great power and authority,"], ["ona sa tuuina mai ia te i laua le mana ma le pule ia mafai ona laua tautatala atu ai,", "for they had power and authority, given unto them that they might speak,"], ["ma sa tuuina mai foi ia te i laua mea e tatau ona la tautatala atu ai.", "and they also had what they should speak given unto them—"]]},
  {num:19,words:[["O lea na laua tautala atu ai i le ofo tele o sa Lamanā,", "Therefore they did speak unto the great astonishment of the Lamanites,"], ["i le faatalitonuina o i latou,", "to the convincing them,"], ["sa oo ina papatisoina i le salamo le valu afe o sa Lamanā o e sa i le laueleele o Sara'emila ma taamilo ai,", "insomuch that there were eight thousand of the Lamanites who were in the land of Zarahemla and round about baptized unto repentance,"], ["ma ua talitonu i le leaga o uputuu a o latou tamā.", "and were convinced of the wickedness of the traditions of their fathers."]]},
  {num:20,words:[["Ma sa oo ina faasolo atu Nifae ma Liae mai iina e o atu i le laueleele o Nifae.", "And it came to pass that Nephi and Lehi did proceed from thence to go to the land of Nephi."]]},
  {num:21,words:[["Ma sa oo ina ave i laua e se autau a sa Lamanā ma ua lafo i le falepuipui ;", "And it came to pass that they were taken by an army of the Lamanites and cast into prison;"], ["ioe,", "yea,"], ["i le falepuipui lava lea sa lafo i ai i totonu Amona ma ona uso e auauna a Limae.", "even in that same prison in which Ammon and his brethren were cast by the servants of Limhi."]]},
  {num:22,words:[["Ma ina ua mavae ona lafoina o i laua i le falepuipui i aso e tele e aunoa ma se meaai,", "And after they had been cast into prison many days without food,"], ["faauta,", "behold,"], ["sa latou o atu i le falepuipui e ave i laua ina ia latou fasioti ia te i laua.", "they went forth into the prison to take them that they might slay them."]]},
  {num:23,words:[["Ma sa oo ina siosiomia faataamilo Nifae ma Liae e peiseai i se afi ,", "And it came to pass that Nephi and Lehi were encircled about as if by fire,"], ["sa oo ina latou fefefe latou te fetagofi atu o latou lima i luga ia te i laua i le matatau nei o latou mu. E ui i lea,", "even insomuch that they durst not lay their hands upon them for fear lest they should be burned. Nevertheless,"], ["sa lei mu Nifae ma Liae;", "Nephi and Lehi were not burned;"], ["ma sa laua tutu e peiseai i totonu o se afi ma ua le mu.", "and they were as standing in the midst of fire and were not burned."]]},
  {num:24,words:[["Ma ina ua laua vaai ua siosiomia faataamilo i laua i se afi faaniutu,", "And when they saw that they were encircled about with a pillar of fire,"], ["ma ua laua le mu ai,", "and that it burned them not,"], ["sa faalototeteleina o laua loto.", "their hearts did take courage."]]},
  {num:25,words:[["Ona sa laua vaai atu ua fefefe sa Lamanā e fetagofi mai o latou lima ia te i laua;", "For they saw that the Lamanites durst not lay their hands upon them;"], ["pe sa latou totoa e o mai faalatalata mai ia te i laua,", "neither durst they come near unto them,"], ["ae sa tutu e peiseai ua taia i latou i le gugu i le ofo.", "but stood as if they were struck dumb with amazement."]]},
  {num:26,words:[["Ma sa oo ina tutu atu Nifae ma Liae ma amata ona tautatala atu ia te i latou,", "And it came to pass that Nephi and Lehi did stand forth and began to speak unto them,"], ["ua fai atu:", "saying:"], ["Aua tou te matatau, aua faauta,", "Fear not,"], ["o le Atua lava ua ia faaali mai ia te outou lenei mea ofoofogia,", "for behold,"], ["lea ua faaali atu ai ia te outou,", "it is God that has shown unto you this marvelous thing,"], ["e le mafai ona fetagofi mai o outou lima ia i maua e fasioti i maua.", "in the which is shown unto you that ye cannot lay your hands on us to slay us."]]},
  {num:27,words:[["Ma faauta,", "And behold,"], ["ina ua uma ona laua fai atu o ia upu,", "when they had said these words,"], ["sa matua luluina le eleele,", "the earth shook exceedingly,"], ["ma sa luluina puipui o le falepuipui e peiseai a solo i le eleele;", "and the walls of the prison did shake as if they were about to tumble to the earth;"], ["ae faauta,", "but behold,"], ["sa lei solo i latou.", "they did not fall."], ["Ma faauta, o i latou o e sa i ai i le falepuipui,", "And behold,"], ["o sa Lamanā ia ma sa Nifaē o e o tagata sa faatuiese.", "they that were in the prison were Lamanites and Nephites who were dissenters."]]},
  {num:28,words:[["Ma sa oo ina faamalumaluina i latou i se ao o le pogisa ,", "And it came to pass that they were overshadowed with a cloud of darkness,"], ["ma sa oo mai i o latou luga se matau tele.", "and an awful solemn fear came upon them."]]},
  {num:29,words:[["Ma sa oo ina oo mai se siufofoga e peiseai ua mai i luga ae o le ao o le pogisa,", "And it came to pass that there came a voice as if it were above the cloud of darkness,"], ["ua fetalai mai:", "saying:"], ["Ia outou salamo ia, ia outou salamo ia,", "Repent ye,"], ["ma aua tou te toe saili e faaumatia au auauna,", "repent ye,"], ["o e ua ou auina atu ia te outou e talai atu tala lelei.", "and seek no more to destroy my servants whom I have sent unto you to declare good tidings."]]},
  {num:30,words:[["Ma sa oo ina ua latou faalogoina lenei leo,", "And it came to pass when they heard this voice,"], ["ma sa latou iloa sa le o se leo o le faititili,", "and beheld that it was not a voice of thunder,"], ["pe o se leo foi o se vavao tele,", "neither was it a voice of a great tumultuous noise,"], ["ae faauta,", "but behold,"], ["o se siufofoga filemu o le fimalie atoatoa,", "it was a still voice of perfect mildness,"], ["sa peiseai o se musumusu,", "as if it had been a whisper,"], ["ma sa ati e oo atu i totonu lava o le agaga—", "and it did pierce even to the very soul—"]]},
  {num:31,words:[["Ma e ui i le fimalie o le siufofoga,", "And notwithstanding the mildness of the voice,"], ["faauta, sa matua luluina tele ai le eleele,", "behold the earth shook exceedingly,"], ["ma sa oo ina toe tetete puipui o le falepuipui,", "and the walls of the prison trembled again,"], ["e peiseai a solo i le eleele;", "as if it were about to tumble to the earth;"], ["ma faauta,", "and behold the cloud of darkness,"], ["o le ao o le pogisa, lea sa faamalumaluina ai i latou,", "which had overshadowed them,"], ["sa le matafi ese—", "did not disperse—"]]},
  {num:32,words:[["Ma faauta sa toe oo mai le siufofoga,", "And behold the voice came again,"], ["ua fetalai mai:", "saying:"], ["Ia outou salamo ia,", "Repent ye,"], ["ia outou salamo ia,", "repent ye,"], ["ona ua latalata mai le malo o le lagi;", "for the kingdom of heaven is at hand;"], ["ma aua nei tou toe saili e faaumatia au auauna. Ma sa oo ina toe luluina le eleele,", "and seek no more to destroy my servants. And it came to pass that the earth shook again,"], ["ma sa tetete puipui.", "and the walls trembled."]]},
  {num:33,words:[["Ma sa toe fetalai mai foi le siufofoga i le taimi lona tolu,", "And also again the third time the voice came,"], ["ma sa fetalai mai ia te i latou i upu ofoofogia e le mafai e se tagata ona tautala ai;", "and did speak unto them marvelous words which cannot be uttered by man;"], ["ma sa toe tetete puipui o le falepuipui,", "and the walls did tremble again,"], ["ma sa luluina le eleele e peiseai a vaevaeina.", "and the earth shook as if it were about to divide asunder."]]},
  {num:34,words:[["Ma sa oo ina le mafai e tagata sa Lamanā ona sosola ese ona o le ao o le pogisa lea sa faamalumalu mai ia te i latou;", "And it came to pass that the Lamanites could not flee because of the cloud of darkness which did overshadow them;"], ["ioe,", "yea,"], ["ma sa le mafai foi ona latou gaoioi ona o le matau na oo mai i luga o i latou.", "and also they were immovable because of the fear which did come upon them."]]},
  {num:35,words:[["O lenei sa i ai se tasi i totonu ia te i latou o se sa Nifaē i lona fanau mai,", "Now there was one among them who was a Nephite by birth,"], ["o le sa auai i se taimi i le ekalesia a le Atua ae sa faatuiese mai ia te i latou.", "who had once belonged to the church of God but had dissented from them."]]},
  {num:36,words:[["Ma sa oo ina faliu atu o ia,", "And it came to pass that he turned him about,"], ["ma faauta,", "and behold,"], ["sa ia vaaia fofoga o Nifae ma Liae e ala atu i le ao o le pogisa;", "he saw through the cloud of  darkness the faces of Nephi and Lehi;"], ["ma faauta,", "and behold,"], ["ua susulu tele lava,", "they did shine exceedingly,"], ["ua pei lava o fofoga o ni agelu. Ma sa vaai atu o ia ua tetepa ae o laua mata i le lagi;", "even as the faces of angels. And he beheld that they did lift their eyes to heaven;"], ["ma sa foliga mai i laua e peiseai o tautatala pe o sii atu o laua leo i se tagata o laua vaai atu i ai.", "and they were in the attitude as if talking or lifting their voices to some being whom they beheld."]]},
  {num:37,words:[["Ma sa oo ina alaga atu lenei tagata i le motu o tagata,", "And it came to pass that this man did cry unto the multitude,"], ["ina ia latou liliu ma vaai. Ma faauta,", "that they might turn and look. And behold,"], ["sa tuuina mai ia te i latou se mana sa mafai ai ona latou liliu ma vaai atu;", "there was power given unto them that they did turn and look;"], ["ma sa latou iloa atu fofoga o Nifae ma Liae.", "and they did behold the faces of Nephi and Lehi."]]},
  {num:38,words:[["Ma sa latou fai mai i le tagata:", "And they said unto the man:"], ["Faauta,", "Behold,"], ["o le a le uiga o nei mea uma,", "what do all these things mean,"], ["ma o ai o loo fetautalatalaai ma nei tagata?", "and who is it with whom these men do converse?"]]},
  {num:39,words:[["O lenei o le igoa o le tagata o Aminatapu. Ma sa fai atu Aminatapu ia te i latou:", "Now the man’s name was Aminadab. And Aminadab said unto them:"], ["O loo fetautalatalaai i laua ma agelu a le Atua.", "They do converse with the angels of God."]]},
  {num:40,words:[["Ma sa oo ina fai mai tagata sa Lamanā ia te ia:", "And it came to pass that the Lamanites said unto him:"], ["Se a se mea matou te faia,", "What shall we do,"], ["ina ia mafai ai ona aveese o lenei ao o le pogisa mai le faamalumalu mai ia te i matou?", "that this cloud of darkness may be removed from over shadowing us?"]]},
  {num:41,words:[["Ma sa fai atu Aminatapu ia te i latou:", "And Aminadab said unto them:"], ["E ao ina outou salamo ,", "You must repent,"], ["ma faatoga atu i le siufofoga,", "and cry unto the voice,"], ["seia oo ina outou maua le faatuatua ia Keriso,", "even until ye shall have faith in Christ,"], ["o le na aoao atu ia te outou e Alema,", "who was taught unto you by Alma,"], ["ma Amoleka,", "and Amulek,"], ["ma Seseroma;", "and Zeezrom;"], ["ma a outou faia lenei mea,", "and when ye shall do this,"], ["o le a aveesea le ao o le pogisa mai le faamalumalu mai ia te outou.", "the cloud of darkness shall be removed from overshadowing you."]]},
  {num:42,words:[["Ma sa oo ina amata ona latou faatoga uma atu i le siufofoga o ia o le na luluina le eleele;", "And it came to pass that they all did begin to cry unto the voice of him who had shaken the earth;"], ["ioe,", "yea,"], ["sa latou faatoga atu seia oo lava ina matafi ese le ao o le pogisa.", "they did cry even until the cloud of darkness was dispersed."]]},
  {num:43,words:[["Ma sa oo ina ua latou vaavaai solo atu,", "And it came to pass that when they cast their eyes about,"], ["ma vaai ua matafiese le ao o le pogisa mai le faamalumalu mai ia te i latou,", "and saw that the cloud of darkness was dispersed from overshadowing them,"], ["faauta, sa latou vaai ua siosiomia faataamilo i latou,", "behold,"], ["ioe,", "they saw that they were encircled about,"], ["o tagata taitoatasi,", "yea every soul,"], ["i se afi faaniutu.", "by a pillar of fire."]]},
  {num:44,words:[["Ma sa i ai Nifae ma Liae i totonugalemu o i latou;", "And Nephi and Lehi were in the midst of them;"], ["ioe,", "yea,"], ["sa siosiomia faataamilo i laua;", "they were encircled about;"], ["ioe,", "yea,"], ["sa peiseai sa i ai i laua i totonu o se afi mumu,", "they were as if in the midst of a flaming fire,"], ["ae sa le afaina ai i laua,", "yet it did harm them not,"], ["pe sa mu ai foi luga o puipui o le falepuipui;", "neither did it take hold upon the walls of the prison;"], ["ma sa faatumuina i laua i lena olioli lea ua le magagana ma ua tumu i le mamalu.", "and they were filled with that joy which is unspeakable and full of glory."]]},
  {num:45,words:[["Ma faauta,", "And behold,"], ["sa afio mai i lalo le Agaga Paia o le Atua mai le lagi,", "the Holy Spirit of God did come down from heaven,"], ["ma ua ulu i totonu o o latou loto,", "and did enter into their hearts,"], ["ma sa faatumulia i latou e peiseai i le afi,", "and they were filled as if with fire,"], ["ma sa mafai ona latou tautatala mai i upu ofoofogia.", "and they could speak forth marvelous words."]]},
  {num:46,words:[["Ma sa oo ina oo mai se siufofoga ia te i latou,", "And it came to pass that there came a voice unto them,"], ["ioe,", "yea,"], ["o se siufofoga malie,", "a pleasant voice,"], ["e peiseai o se musumusu mai,", "as if it were a whisper,"], ["ua fetalai mai:", "saying:"]]},
  {num:47,words:[["Filemu ,", "Peace,"], ["ia ia te outou le filemu,", "peace be unto you,"], ["ona o lo outou faatuatua i la'u Pele Lelei,", "because of your faith in my Well Beloved,"], ["o le sa i ai mai le faavaega o le lalolagi.", "who was from the foundation of the world."]]},
  {num:48,words:[["Ma o lenei,", "And now,"], ["ina ua latou faalogoina lenei mea, sa latou tetepa ae o latou mata,", "when they heard this they cast up their eyes as if to behold from whence the voice came;"], ["e peiseai e vaai atu i le mea na sau mai ai le siufofoga;", "and behold,"], ["ma faauta, sa latou vaai atu ua avanoa le lagi ;", "they saw the heavens open;"], ["ma ua afifio mai agelu i lalo mai le lagi ma auauna mai ia te i latou.", "and angels came down out of heaven and ministered unto them."]]},
  {num:49,words:[["Ma e tusa e tolu selau tagata sa i ai,", "And there were about three hundred souls who saw and heard these things;"], ["o e na vaai ma faalogo i nei mea; ma sa poloaiina i latou ia o atu ma aua le ofo,", "and they were bidden to go forth and marvel not,"], ["pe latou te masalosalo.", "neither should they doubt."]]},
  {num:50,words:[["Ma sa oo ina latou o atu ma sa auauna atu i tagata,", "And it came to pass that they did go forth,"], ["ma talai atu i itu laueleele faataamilo atoa mea uma sa latou faalogo ma vaai i ai,", "and did minister unto the people,"], ["sa oo ina talitonu le vaega tele atu o sa Lamanā i ia mea,", "declaring through out all the regions round about all the things which they had heard and seen, insomuch that the more part of the Lamanites were convinced of them,"], ["ona o le tetele o faamaoniga ia na latou maua.", "because of the greatness of the evidences which they had received."]]},
  {num:51,words:[["Ma o le toatele o i latou o e na talitonu sa latou tuu i lalo a latou auupega o taua,", "And as many as were convinced did lay down their weapons of war,"], ["ma lo latou inoino foi ma uputuu a o latou tamā.", "and also their hatred and the tradition of their fathers."]]},
  {num:52,words:[["Ma sa oo ina latou tuu atu i sa Nifaē laueleele e a latou.", "And it came to pass that they did yield up unto the Nephites the lands of their possession."]]},
];
renderVerseSet(he_ch_5_Verses, 'he-ch5-verses');

var he_ch_6_Verses = [
  {num:1,words:[["Ma sa oo ina ua faaiuina le lona onosefulu ma le lua o tausaga o le nofoaiga a faamasino,", "And it came to pass that when the sixty and second year of the reign of the judges had ended,"], ["sa tutupu mai nei mea uma, ma ua avea sa Lamanā,", "all these things had happened and the Lamanites had become,"], ["le toatele lea o i latou,", "the more part of them,"], ["ma tagata amiotonu, sa oo ina sili atu lo latou amiotonu nai lo sa Nifaē,", "a righteous people,"], ["ona o lo latou maumausali ma lo latou maumaututu i le faatuatua.", "insomuch that their righteousness did exceed that of the Nephites because of their firmness and their steadiness in the faith."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["sa i ai le toatele o sa Nifaē o e sa faamaaa ma le salamo ma amioleaga tele,", "there were many of the Nephites who had become hardened and impenitent and grossly wicked,"], ["sa oo ina latou teena le afioga a le Atua ma talaiga ma perofetaga uma na oo mai i totonu ia te i latou.", "insomuch that they did reject the word of God and all the preaching and prophesying which did come among them."]]},
  {num:3,words:[["E ui i lea,", "Nevertheless,"], ["sa maua e tagata o le ekalesia le olioli tele ona o le liliu mai o sa Lamanā,", "the people of the church did have great joy because of the conversion of the Lamanites,"], ["ioe,", "yea,"], ["ona o le ekalesia a le Atua,", "because of the church of God,"], ["lea sa faatuina i totonu ia te i latou.", "which had been established among them."], ["Ma sa latou faaaumea le tasi i le isi, ma olioli le tasi ma le isi,", "And they did fellowship one with another and did rejoice one with another,"], ["ma sa latou maua le olioli tele.", "and did have great joy."]]},
  {num:4,words:[["Ma sa oo ina o ane i lalo le toatele o sa Lamanā i le laueleele o Sara'emila,", "And it came to pass that many of the Lamanites did come down into the land of Zarahemla,"], ["ma talai atu i sa Nifaē le ala o lo latou liliu mai,", "and did declare unto the people of the Nephites the manner of their conversion,"], ["ma apoapoai atu ia te i latou ia faatuatua ma salamo.", "and did exhort them to faith and repentance."]]},
  {num:5,words:[["Ioe,", "Yea,"], ["ma e toatele i latou sa talai atu ma le mana tele ma le pule,", "and many did preach with exceedingly great power and authority,"], ["sa oo ina ave ifo ai i lalo le toatele o i latou i le loloto o le lotomaualalo,", "unto the bringing down many of them into the depths of humility,"], ["ia avea o ni soo lotomaualalalo o le Atua ma le Tamai Mamoe.", "to be the humble followers of God and the Lamb."]]},
  {num:6,words:[["Ma sa oo ina o atu le toatele o sa Lamanā i le laueleele i matu;", "And it came to pass that many of the Lamanites did go into the land northward;"], ["ma sa o atu foi Nifae ma Liae i le laueleele i matu,", "and also Nephi and Lehi went into the land north ward,"], ["e talai atu i tagata. Ma sa faapea ona iu o le lona onosefulu ma le tolu o tausaga.", "to preach unto the people. And thus ended the sixty and third year."]]},
  {num:7,words:[["Ma faauta,", "And behold,"], ["sa i ai le filemu i le laueleele atoa,", "there was peace in all the land,"], ["sa oo ina mafai ona o atu o sa Nifae i soo se vaega o le laueleele sa latou loto i ai,", "insomuch that the Nephites did go into whatsoever part of the land they would,"], ["pe i totonu o sa Nifaē po o sa Lamanā.", "whether among the Nephites or the Lamanites."]]},
  {num:8,words:[["Ma sa oo ina mafai foi e sa Lamanā ona o atu i soo se mea sa latou loto i ai,", "And it came to pass that the Lamanites did also go whithersoever they would,"], ["pe i totonu o sa Lamanā po o sa Nifaē;", "whether it were among the Lamanites or among the Nephites;"], ["ma sa faapea ona latou mafuta saoloto ai o le tasi i le isi,", "and thus they did have free intercourse one with  another,"], ["e faatau mai ma faatau atu,", "to buy and to sell,"], ["ma saili oloa,", "and to get gain,"], ["e tusa ma o latou manao.", "according to their desire."]]},
  {num:9,words:[["Ma sa oo ina latou matua mauoa tele lava,", "And it came to pass that they became exceedingly rich,"], ["o sa Lamanā uma ma sa Nifaē;", "both the Lamanites and the Nephites;"], ["ma sa latou maua se mau tele lava o auro,", "and they did have an exceeding plenty of gold,"], ["ma ario,", "and of silver,"], ["ma uamea taua eseese uma,", "and of all manner of precious metals,"], ["i le laueleele uma i saute ma le laueleele i matu.", "both in the land south and in the land north."]]},
  {num:10,words:[["O lenei o le laueleele i saute sa taua o Liae,", "Now the land south was called Lehi and the land north was called Mulek,"], ["ma o le laueleele i matu sa taua o Moleka ,", "which was after the son of Zedekiah;"], ["lea sa faaigoa i le atalii o Setekaia; ona sa aumai Moleka e le Alii i le laueleele i matu,", "for the Lord did bring Mulek into the land north,"], ["ma Liae i le laueleele i saute.", "and Lehi into the land south."]]},
  {num:11,words:[["Ma faauta,", "And behold,"], ["sa i ai auro eseese uma i nei laueleele uma e lua,", "there was all manner of gold in both these lands,"], ["ma ario,", "and of silver,"], ["ma ituaiga uma o 'oa taua eseese;", "and of precious ore of every kind;"], ["ma sa i ai foi tagata faigaluega tomai eseese i gaosiga,", "and there were also curious workmen,"], ["o e sa latou galueaiina ma faamamaina ituaiga uma o oa;", "who did work all kinds of ore and did refine it;"], ["ma sa faapea ona latou mauoa.", "and thus they did become rich."]]},
  {num:12,words:[["Sa latou totoina saito e tele,", "They did raise grain in abundance,"], ["i matu uma ma saute;", "both in the north and in the south;"], ["ma sa latou uluola tele lava,", "and they did flourish exceedingly,"], ["i matu uma ma saute. Ma sa latou fanafanau ma faasolo malolosi tele lava i le laueleele. Ma sa latou faia lafu ma fagaga e tele,", "both in the north and in the south. And they did multiply and wax exceedingly strong in the land. And they did raise many flocks and herds,"], ["ioe,", "yea,"], ["o manu pepeti e tele.", "many fatlings."]]},
  {num:13,words:[["Faauta o o latou fafine sa galulue ma milo,", "Behold their women did toil and spin,"], ["ma sa latou faia ie uiga eseese uma,", "and did make all manner of cloth,"], ["o ie lino-miloa lelei ma ie o ituaiga eseese uma,", "of fine– twined linen and cloth of every kind,"], ["e faaoofu ai lo latou le lavalava. Ma sa faapea ona mavae atu o le lona onosefulu ma le fa o tausaga i le filemu.", "to clothe their nakedness. And thus the sixty and fourth year did pass away in peace."]]},
  {num:14,words:[["Ma i le tausaga e onosefulu ma le lima sa latou maua ai foi le olioli tele ma le filemu,", "And in the sixty and fifth year they did also have great joy and peace,"], ["ioe,", "yea,"], ["ma talaiga e tele ma valoaga e tele e faatatau i mea o le a oo mai. Ma sa faapea ona mavae atu o le tausaga e onosefulu ma le lima.", "much preaching and many prophecies concerning that which was to come. And thus passed away the sixty and fifth year."]]},
  {num:15,words:[["Ma sa oo i le tausaga e onosefulu ma le ono o le nofoaiga a faamasino,", "And it came to pass that in the sixty and sixth year of the reign of the judges,"], ["faauta,", "behold,"], ["sa fasiotia Sesorama e se lima e le iloa ao nofo o ia i le nofoa-faamasino.", "Cezoram was murdered by an unknown hand as he sat upon the judgment– seat."], ["Ma sa oo ina o lena lava tausaga e tasi na fasiotia ai foi lona atalii,", "And it came to pass that in the same year, that his son,"], ["o le na tofia e le nuu e suitulaga ia te ia.", "who had been appointed by the people in his stead, was also murdered."], ["Ma sa faapea ona iu o le tausaga e onosefulu ma le ono.", "And thus ended the sixty and sixth year."]]},
  {num:16,words:[["Ma o le amataga o le tausaga e onosefulu ma le fitu sa toe amata ai ona tuputupu ae le amioleaga tele lava o tagata.", "And in the commencement of the sixty and seventh year the people began to grow exceedingly wicked again."]]},
  {num:17,words:[["Aua faauta,", "For behold,"], ["sa umi ona faamanuiaina i latou e le Alii i oa o le lalolagi sa le faaosoina i latou i le ita,", "the Lord had blessed them so long with the riches of the world that they had not been stirred up to anger,"], ["i taua,", "to wars,"], ["po o i le faamasaa toto;", "nor to bloodshed;"], ["o lea sa amata ai ona latou fuli atu o latou loto ia latou oa;", "therefore they began to set their hearts upon their riches;"], ["ioe,", "yea,"], ["sa amata ona latou saili ia maua le oa ina ia mafai ona latou sili ae i luga o le tasi;", "they began to seek to get gain that they might be lifted up one above another;"], ["o lea na amata ai ona latou faia o fasiotiga tagata faalilolilo ,", "therefore they began to commit secret murders,"], ["ma faomea ma vete,", "and to rob and to plunder,"], ["ina ia latou maua ai oa.", "that they might get gain."]]},
  {num:18,words:[["Ma o lenei faauta,", "And now behold,"], ["o ia tagata fasioti tagata ma tagata na faia vetega,", "those murderers and plunderers were a band who had been formed by Kishkumen and Gadianton. And now it had come to pass that there were many,"], ["o se vaega o tagata o e na faavae e Kisakumena ma Katianetona . Ma o lenei sa oo ina toatele tagata o le vaega a Katianetona,", "even among the Nephites,"], ["i totonu lava o sa Nifaē. Peitai faauta,", "of Gadianton’s band. But behold,"], ["sa sili atu lo latou toatele i le vaega aupito sili atu ona amioleaga o sa Lamanā. Ma sa taua i latou o le au faomea ma le au fasioti tagata a Katianetona.", "they were more numerous among the more wicked part of the Lamanites. And they were called Gadianton’s robbers and murderers."]]},
  {num:19,words:[["Ma o i latou ia na fasiotia le faamasino sili o Sesorama,", "And it was they who did murder the chief judge Cezoram,"], ["ma lona atalii,", "and his son,"], ["ao i ai i le nofoa-faamasino;", "while in the judgment– seat;"], ["ma faauta,", "and behold,"], ["sa le maua i latou.", "they were not found."]]},
  {num:20,words:[["Ma o lenei sa oo ina ua iloa e sa Lamanā ua i ai ni tagata faomea i totonu ia te i latou, sa latou faanoanoa tele lava;", "And now it came to pass that when the Lamanites found that there were robbers among them they were exceedingly sorrowful;"], ["ma sa latou faaaoga ala uma i lo latou malosi e faaumatia ai i latou mai luga o le lalolagi.", "and they did use every means in their power to destroy them off the face of the earth."]]},
  {num:21,words:[["Ae faauta,", "But behold,"], ["sa faaosoina e Satani loto o le vaega toatele atu o sa Nifaē,", "Satan did stir up the hearts of the more part of the Nephites,"], ["sa oo ina latou aufaatasi ma ia vaega o tagata faomea,", "insomuch that they did unite with those bands of robbers,"], ["ma latou ulu atu ia latou feagaiga ma a latou tautoga,", "and did enter into their covenants and their oaths,"], ["o le a latou puipuia ma faasaoina le tasi i soo se tulaga faigata e tuu i ai i latou,", "that they would protect and preserve one another in whatsoever difficult circumstances they should be placed,"], ["ina ia latou le mafatia ia latou fasiotiga tagata,", "that they should not suffer for their murders,"], ["ma a latou vetega,", "and their plunderings,"], ["ma a latou gaoiga.", "and their stealings."]]},
  {num:22,words:[["Ma sa oo ina sa i ai ni a latou faailoga,", "And it came to pass that they did have their signs,"], ["ioe,", "yea,"], ["ni a latou faailoga faalilolilo,", "their secret signs,"], ["ma a latou upu faalilolilo;", "and their secret words;"], ["ma sa latou faia nei mea ina ia latou iloa ai se uso o le ua uma ona ulu i le feagaiga,", "and this that they might distinguish a brother who had entered into the covenant,"], ["ina ia le faatiga ia te ia lona uso i soo se amioleaga na te faia,", "that whatsoever wickedness his brother should do he should not be injured by his brother,"], ["po o i latou o e ua auai i lana vaega,", "nor by those who did belong to his band,"], ["o e ua latou osia lenei feagaiga.", "who had taken this covenant."]]},
  {num:23,words:[["Ma sa faapea ona latou faia ina ia mafai ona latou fasioti tagata,", "And thus they might murder,"], ["ma vete,", "and plunder,"], ["ma gaoi,", "and steal,"], ["ma fai le faitaaga ma amioleaga eseese uma,", "and commit whoredoms and all manner of wickedness,"], ["sa le tusa ma tulafono a lo latou atunuu ma tulafono foi a lo latou Atua.", "contrary to the laws of their country and also the laws of their God."]]},
  {num:24,words:[["Ma o soo se tasi o i latou o e na auai i la latou vaega na te faaali atu i le lalolagi a latou amioleaga ma a latou mea inosia,", "And whosoever of those who belonged to their band should reveal unto the world of their wickedness and their abominations,"], ["e faamasinoina,", "should be tried,"], ["e le tusa ai ma tulafono a lo latou atunuu,", "not according to the laws of their country,"], ["ae tusa ai ma tulafono a lo latou amioleaga,", "but according to the laws of their wickedness,"], ["ia na tuuina mai e Katianetona ma Kisakumena.", "which had been given by Gadianton and Kishkumen."]]},
  {num:25,words:[["Ma o lenei faauta,", "Now behold,"], ["o tautoga ma feagaiga faalilolilo ia na poloai atu ai Alema i lona atalii ia aua nei oo atu i le lalolagi,", "it is these secret oaths and covenants which Alma commanded his son should not go forth unto the world,"], ["nei avea ma ala e ave ifo ai tagata i lalo i le faafanoga.", "lest they should be a means of bringing down the people unto destruction."]]},
  {num:26,words:[["O lenei faauta,", "Now behold,"], ["o ia tautoga ma feagaiga faalilolilo sa lei oo mai ia Katianetona mai talafaamaumau ia na tuu atu ia Helamana;", "those secret oaths and covenants did not come forth unto Gadianton from the records which were delivered unto Helaman;"], ["ae faauta,", "but behold,"], ["o ia mea na tuu i le loto o Katianetona e lena tagata e tasi o le na ia tosina o tatou uluai matua ina ia aai i le fua o le laau na faasaina—", "they were put into the heart of Gadianton by that same being who did entice our first parents to partake of the forbidden fruit—"]]},
  {num:27,words:[["Ioe,", "Yea,"], ["lena lava tagata e tasi o le na taupulepule ma Kaino ,", "that same being who did plot with Cain,"], ["e faapea afai na te fasiotia lona uso o Apelu o le a le iloa lava e le lalolagi.", "that if he would murder his brother Abel it should not be known unto the world."], ["Ma sa taupulepule o ia faatasi ma Kaino ma e na mulimuli ia te ia, mai lena taimi seia oo i luma.", "And he did plot with Cain and his followers from that time forth."]]},
  {num:28,words:[["O lenei foi o le tagata lava lena e tasi na ia tuu i loto o tagata ia latou fausia se olo ia lava le maualuga ina ia mafai ona latou o ae ai i le lagi. Ma o le tagata lava lena e tasi o le na ia taitaiseseina tagata o e na o mai mai lena olo i le laueleele lenei;", "And also it is that same being who put it into the hearts of the people to build a tower  sufficiently high that they might get to heaven. And it was that same being who led on the people who came from that tower into this land;"], ["o le na ia faasalalauina galuega o le pouliuli ma mea inosia i luga o le laueleele atoa,", "who spread the works of darkness and abominations over all the face of the land,"], ["seia oo lava ina ia toso ifo i lalo tagata i se faafanoga atoa ,", "until he dragged the people down to an entire destruction,"], ["ma se seoli tumau-faavavau.", "and to an everlasting hell."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["o le tagata lava lena e tasi o le na tuuina i le loto o Katianetona e fai pea le galuega o le pouliuli,", "it is that same being who put it into the heart of Gadianton to still carry on the work of darkness,"], ["ma le fasioti tagata faalilolilo;", "and of secret murder;"], ["ma ua ia aumaia i luma mai i le amataga o le tagata seia oo mai lava i lalo i lenei taimi.", "and he has brought it forth from the beginning of man even down to this time."]]},
  {num:30,words:[["Ma faauta,", "And behold,"], ["o ia lea o le o le tupuga o agasala uma.", "it is he who is the author of all sin."], ["Ma faauta,", "And behold,"], ["o loo faia pea e ia ana galuega o le pouliuli ma le fasioti tagata faalilolilo,", "he doth carry on his works of darkness and secret murder,"], ["ma ia tuulima faasolo mai i lalo a latou taupulepulega,", "and doth hand down their plots,"], ["ma a latou tautoga, ma a latou feagaiga,", "and their oaths,"], ["ma a latou fuafuaga o le amioleaga matautia,", "and their covenants,"], ["mai lea tupulaga i lea tupulaga,", "and their plans of awful wickedness,"], ["e tusa ma le mafai ona ia umia o loto o le fanauga a tagata.", "from generation to generation according as he can get hold upon the hearts of the children of men."]]},
  {num:31,words:[["Ma o lenei faauta,", "And now behold,"], ["sa ia umia loto o tagata sa Nifaē;", "he had got great hold upon the hearts of the Nephites;"], ["ioe,", "yea,"], ["sa oo ina avea i latou ma tagata amioleaga tele lava;", "insomuch that they had become exceedingly wicked;"], ["ioe,", "yea,"], ["o le vaega tele o i latou sa liliu ese mai le ala o le amiotonu,", "the more part of them had turned out of the way of righteousness,"], ["ma sa latou soli i lalo o o latou vae poloaiga a le Atua,", "and did trample under their feet the commandments of God,"], ["ma ua liliu atu i o latou lava ala,", "and did turn unto their own ways,"], ["ma sa latou atiae tupua mo i latou mai ia latou auro ma a latou ario.", "and did build up unto themselves idols of their gold and their silver."]]},
  {num:32,words:[["Ma sa oo ina o nei amioletonu uma sa oo mai ia te i latou i le va o ni tausaga sa lei tele,", "And it came to pass that all these iniquities did come unto them in the space of not many years,"], ["o le vaega tele o ia mea na oo mai ia te i latou i le lona onosefulu ma le fitu o tausaga o le nofoaiga a faamasino i le nuu o Nifae.", "insomuch that a more part of it had come unto them in the sixty and seventh year of the reign of the judges over the people of Nephi."]]},
  {num:33,words:[["Ma sa latou tutupu i lo latou amioletonu i le lona onosefulu ma le valu foi o tausaga, i le faanoanoa tele ma le auega o e na amiotonu.", "And they did grow in their iniquities in the sixty and eighth year also."]]},
  {num:34,words:[["Ma ua faapea ona tatou vaai ai sa amata ona faaitiitia sa Nifaē i e le talitonu,", "And thus we see that the Nephites did begin to dwindle in unbelief,"], ["ma tutupu i le amioleaga ma mea inosia,", "and grow in wickedness and abominations,"], ["ao sa Lamanā sa amata ona tutupu tele lava i le malamalama o lo latou Atua;", "while the Lamanites began to grow exceedingly in the knowledge of their God;"], ["ioe,", "yea,"], ["sa amata ona latou tausia ana tulafono ma poloaiga,", "they did begin to keep his statutes and commandments,"], ["ma savavali i le upumoni ma le amiosao i ona luma.", "and to walk in truth and uprightness before him."]]},
  {num:35,words:[["Ma ua faapea ona tatou vaai ai ua amata ona alu ese o le Agaga o le Alii mai sa Nifaē,", "And thus we see that the Spirit of the Lord began to withdraw from the Nephites,"], ["ona o le amioleaga ma le maaa o o latou loto.", "because of the wickedness and the hardness of their hearts."]]},
  {num:36,words:[["Ma ua faapea ona tatou vaai ai ua amata ona liligi ifo e le Alii lona Agaga i luga o sa Lamanā,", "And thus we see that the Lord began to pour out his Spirit upon the Lamanites,"], ["ona o lo latou augofie ma lo latou fia talitonu i ana fetalaiga.", "because of their easiness and willingness to believe in his words."]]},
  {num:37,words:[["Ma sa oo ina sailia e sa Lamanā le vaega a le au faomea a Katianetona;", "And it came to pass that the Lamanites did hunt the band of robbers of Gadianton;"], ["ma sa latou talai atu le afioga a le Atua i le vaega sili ona amioleaga o i latou,", "and they did preach the word of God among the more wicked part of them,"], ["sa oo ina faaumatia aiai lenei vaega o le au faomea mai totonu o sa Lamanā.", "insomuch that this band of robbers was utterly destroyed from among the Lamanites."]]},
  {num:38,words:[["Ma sa oo i le tasi itu,", "And it came to pass on the other hand,"], ["sa atiae ma lagolagoina i latou e sa Nifaē,", "that the Nephites did build them up and support them,"], ["e amata mai i le vaega sili ona amioleaga o i latou,", "beginning at the more wicked part of them,"], ["seia oo ina latou ufitia le laueleele atoa o sa Nifaē,", "until  they had overspread all the land of the Nephites,"], ["ma latou faaseseina le vaega tele o e amiotonu seia oo ina latou o ifo i lalo e talitonu ia latou galuega ma aai ia latou vete,", "and had seduced the more part of the righteous until they had come down to believe in their works and partake of their spoils,"], ["ma aufaatasi ma i latou ia latou fasiotiga tagata ma pulega faalilolilo.", "and to join with them in their secret murders and combinations."]]},
  {num:39,words:[["Ma sa faapea ona latou maua o le pulega atoa o le malo,", "And thus they did obtain the sole management of the government,"], ["sa oo ina latou solia i lalo o o latou vae ma taia ma faasaua ma fuli o latou tua i e ua matitiva ma e agamalu,", "insomuch that they did trample under their feet and smite and rend and turn their backs upon the poor and the meek,"], ["ma soo lotomaualalalo o le Atua.", "and the humble followers of God."]]},
  {num:40,words:[["Ma ua faapea ona tatou vaai ua latou i ai i se tulaga leaga matautia,", "And thus we see that they were in an awful state,"], ["ma ua matutua mo se faaumatiaga tumau-faavavau.", "and ripening for an everlasting destruction."]]},
  {num:41,words:[["Ma sa oo ina faapea ona iu o le tausaga e onosefulu ma le valu o le nofoaiga a faamasino i le nuu o Nifae.", "And it came to pass that thus ended the sixty and eighth year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(he_ch_6_Verses, 'he-ch6-verses');

var he_ch_7_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina o le tausaga e onosefulu ma le iva o le nofoaiga a faamasino i sa Nifaē,", "now it came to pass in the sixty and ninth year of the reign of the judges over the people of the Nephites,"], ["na toe foi mai ai Nifae,", "that Nephi,"], ["le atalii o Helamana,", "the son of Helaman,"], ["i le laueleele o Sara'emila mai le laueleele i matu.", "returned to the land of Zarahemla from the land northward."]]},
  {num:2,words:[["Ona sa alu atu o ia i fafo i totonu o tagata o e sa i le laueleele i matu,", "For he had been forth among the people who were in the land northward,"], ["ma ia talai atu le afioga a le Atua ia te i latou,", "and did preach the word of God unto them,"], ["ma sa ia vavalo atu mea e tele ia te i latou;", "and did prophesy many things unto them;"]]},
  {num:3,words:[["Ma sa latou teena ana upu uma,", "And they did reject all his words,"], ["sa oo ina le mafai ona nofo o ia i totonu ia te i latou,", "insomuch that he could not stay among them,"], ["ae sa toe foi mai o ia i le laueleele na ia fanau mai ai.", "but returned again unto the land of his nativity."]]},
  {num:4,words:[["Ma ina ua vaai atu ua i ai tagata i se tulaga o le amioleaga matautia faapea,", "And seeing the people in a state of such awful wickedness,"], ["ma ua nofoia e ia au faomea a Katianetona nofoa-faamasin—ona sa latou fao faamalosi le mana ma le pule o le laueleele;", "and those Gadianton robbers filling the judgment– seats—having usurped the power and authority of the land;"], ["ma tuu ese poloaiga a le Atua,", "laying aside the commandments of God,"], ["ma e leai sina mea itiiti na sao ai lea mea i ona luma;", "and not in the least aright before him;"], ["ua latou le faia se mea tonu i le fanauga a tagata;", "doing no justice unto the children of men;"]]},
  {num:5,words:[["Ua latou tausalaina e amiotonu ona o lo latou amiotonu;", "Condemning the righteous because of their righteousness;"], ["ua latou tuu e ua sala ma e ua amioleaga e le faasalaina ona o a latou tupe;", "letting the guilty and the wicked go unpunished because of their money;"], ["o lenei foi ina ia latou umia tofiga i le ao o le malo,", "and moreover to be held in office at the head of government,"], ["latou te pule ma fai ai e tusa ma o latou loto,", "to rule and do according to their wills,"], ["ina ia latou maua le oa ma le mamalu o le lalolagi ,", "that they might get gain and glory of the world,"], ["ma,", "and,"], ["o lenei foi,", "moreover,"], ["ina ia sili ona faigofie ai ia te i latou ona faia le mulilua,", "that they might the more easily commit adultery,"], ["ma gaoi,", "and steal,"], ["ma fasioti,", "and kill,"], ["ma faia e tusa ma o latou lava loto—", "and do according to their own wills—"]]},
  {num:6,words:[["O lenei,", "Now this great iniquity had come upon the Nephites,"], ["o lenei amioletonu tele sa oo mai i luga o sa Nifaē,", "in the space of not many years;"], ["i le va o ni tausaga sa lei tele; ma ina ua vaai atu i ai Nifae,", "and when Nephi saw it,"], ["sa malena ae lona loto ma le faanoanoa i totonu o lona fatafata;", "his heart was swollen with sorrow within his breast;"], ["ma sa alaga o ia i le tiga o lona agaga:", "and he did exclaim in the agony of his soul:"]]},
  {num:7,words:[["E,", "Oh,"], ["maumau pe a na mafai ona oo mai ou aso i aso muamua na sau ai lou tamā o Nifae i fafo mai le laueleele o Ierusalema,", "that I could have had my days in the days when my father Nephi first came out of the land of Jerusalem,"], ["po ua mafai ona ou olioli faatasi ma ia i le laueleele na folafolaina;", "that I could have joyed with him in the promised land;"], ["o aso na sa faigofie ai ona tauanauina ona tagata,", "then were his people easy to be entreated,"], ["ia tutumau e tausi poloaiga a le Atua,", "firm to keep the commandments of God,"], ["ma gese ona taitaiina e fai le amioletonu;", "and slow to be led to do iniquity;"], ["ma sa vavave ona latou faalogo atu i afioga a le Alii—", "and  they were quick to hearken unto the words of the Lord—"]]},
  {num:8,words:[["Ioe,", "Yea,"], ["a na mafai ona oo mai ou aso i na aso,", "if my days could have been in those days,"], ["po ua olioli lo'u agaga i le amiotonu o o'u uso.", "then would my soul have had joy in the righteousness of my brethren."]]},
  {num:9,words:[["Ae faauta,", "But behold,"], ["ua tofia a'u o o'u aso nei aso,", "I am consigned that these are my days,"], ["ma ia faatumuina lou agaga i le faanoanoa ona o lenei amioleaga a o'u uso.", "and that my soul shall be filled with sorrow because of this the wickedness of my brethren."]]},
  {num:10,words:[["Ma faauta,", "And behold,"], ["o lenei sa oo i luga o se olo lea sa i le faatoaga a Nifae,", "now it came to pass that it was upon a tower, which was in the garden of Nephi,"], ["sa i tafatafa o le alatele lea sa tau atu i le maketi tele sa i le aai o Sara'emila;", "which was by the highway which led to the chief market,"], ["o lea,", "which was in the city of Zara– hemla;"], ["sa punou ifo Nifae i luga o le olo lea sa i lana faatoaga,", "therefore, Nephi had bowed himself upon the tower which was in his garden,"], ["o se olo lea sa tu latalata foi i le faitotoa o le faatoaga lea sa alu ane ai le alatele.", "which tower was also near unto the garden gate by which led the highway."]]},
  {num:11,words:[["Ma sa oo ina sa i ai ni tagata faapitoa sa ui ane ma vaai atu ia Nifae ao ia sasaa atu lona agaga i le Atua i luga o le olo;", "And it came to pass that there were certain men passing by and saw Nephi as he was pouring out his soul unto God upon the tower;"], ["ma sa latou taufetuli ma tau atu i tagata le mea na latou vaaia,", "and they ran and told the people what they had seen,"], ["ma sa o mai faatasi tagata i motu ina ia latou iloa le pogai o lea faanoanoa tele mo le amioleaga o le nuu.", "and the people came together in multitudes that they might know the cause of so great mourning for the wickedness of the people."]]},
  {num:12,words:[["Ma o lenei,", "And now,"], ["ina ua tulai Nifae sa ia vaai atu i motu o tagata o e ua faapotopoto mai faatasi.", "when Nephi arose he beheld the multitudes of people who had gathered together."]]},
  {num:13,words:[["Ma sa oo ina tatala e ia lona fofoga ma fai atu ia te i latou:", "And it came to pass that he opened his mouth and said unto them:"], ["Faauta,", "Behold,"], ["aisea ua outou faapotopoto faatasi ai outou lava? Ina ia ou tau atu ea ia te outou a outou amioletonu?", "why have ye gathered yourselves together? That I may tell you of your iniquities?"]]},
  {num:14,words:[["Ioe,", "Yea,"], ["ona ua ou alu ae i luga o lou olo ina ia mafai ona ou sasaa atu o lou agaga i lou Atua,", "because I have got upon my tower that I might pour out my soul unto my God,"], ["ona o le faanoanoa tele o lou loto,", "because of the exceeding sorrow of my heart,"], ["lea ona o a outou amioletonu!", "which is because of your iniquities!"]]},
  {num:15,words:[["Ma ona o lou faanoanoa ma lau auega ua outou faapotopoto faatasi ai outou lava,", "And because of my mourning and lamentation ye have gathered yourselves together,"], ["ma outou ofo ai;", "and do marvel;"], ["ioe,", "yea,"], ["ma ua i ai ia te outou se mea ua tatau tele ai ona outou ofo;", "and ye have great need to marvel;"], ["ioe,", "yea,"], ["e tatau ona outou ofo ona ua tuu ese atu outou ua maua ai e le tiapolo se uu malosi i o outou loto.", "ye ought to marvel because ye are given away that the devil has got so great hold upon your hearts."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["pe ua mafai faapefea ea ona outou tuu i faatosinaga a ia o le ua saili e lafo ese o outou agaga i lalo i le pagatia tumau-faavavau ma le malaia e le gata?", "how could you have given way to the enticing of him who is seeking to hurl away your souls down to everlasting misery and endless wo?"]]},
  {num:17,words:[["E,", "O repent ye,"], ["ia outou salamo, ia outou salamo! Aisea ea ua outou fia feoti ai? Ia outou liliu mai ia,", "repent ye! Why will ye die? Turn ye,"], ["ia outou liliu mai ia i le Alii lo outou Atua.", "turn ye unto the Lord your God."], ["Aisea ea ua ia tuulafoaiina ai outou?", "Why has he forsaken you?"]]},
  {num:18,words:[["Ona ua outou faamaaa o outou loto;", "It is because you have hardened your hearts;"], ["ioe,", "yea,"], ["ua outou le fia faalogo i le siufofoga o le leoleo mamoe lelei;", "ye will not hearken unto the voice of the good shepherd;"], ["ioe,", "yea,"], ["ua outou faaonoono ia te ia ia toatamai e faasaga mai ia te outou.", "ye have provoked him to anger against you."]]},
  {num:19,words:[["Ma faauta,", "And behold,"], ["i lo le faapotopotoina o outou,", "instead of gathering you,"], ["vagana ai o le a outou salamo,", "except ye will repent,"], ["faauta,", "behold,"], ["o le a ia faasalalauina outou o le a avea ai outou ma meaai mo uli ma manu aivao.", "he shall scatter you forth that ye shall become meat for dogs and wild beasts."]]},
  {num:20,words:[["E,", "O,"], ["pe ua mafai faapefea ona outou faagaloina lo outou Atua i lea lava aso ua ia laveaiina ai outou?", "how could you have forgotten your God in the very day that he has delivered you?"]]},
  {num:21,words:[["Ae faauta,", "But behold,"], ["ua outou faia lenei mea e maua ai oa,", "it is to get gain,"], ["ina ia viia ai outou e tagata,", "to be praised of men,"], ["ioe,", "yea,"], ["ma ina ia mafai ona outou maua ai o le auro ma le ario. Ma ua outou tuu o outou loto i luga o oa ma mea le aoga a lenei lalolagi ,", "and that ye might get gold and silver. And ye have set your hearts upon the riches and the vain things of this world,"], ["ia ua outou fasioti tagata ai,", "for the which ye do murder,"], ["ma vete,", "and plunder,"], ["ma gaoi,", "and steal,"], ["ma molimau pepelo ai e faasaga i o outou tuaoi,", "and bear false witness against your neighbor,"], ["ma fai amioletonu uiga eseese uma.", "and do all manner of iniquity."]]},
  {num:22,words:[["Ma o le pogai lenei o le a oo mai ai le malaia ia te outou vagana ai ua outou salamo. Aua afai tou te le salamo,", "And for this cause wo shall come unto you except ye shall repent. For if ye will not repent,"], ["faauta,", "behold,"], ["o le aai tele lenei,", "this great city,"], ["ma aai tetele uma foi faataamilo ai,", "and also all those great cities which are round about,"], ["ia o loo i ai i le laueleele ua tatou umia,", "which are in the land of our possession,"], ["o le a aveesea o le a outou le maua ai se nofoaga i totonu o i latou;", "shall be taken away that ye shall have no place in them;"], ["ona faauta,", "for behold,"], ["o le a le tuuina mai e le Alii ia te outou le malosi ,", "the Lord will not grant unto you strength,"], ["e pei ona ia faia e oo mai i le taimi nei,", "as he has hitherto done,"], ["tou te tetee faasaga atu ai i o outou fili.", "to withstand against your enemies."]]},
  {num:23,words:[["Aua faauta,", "For behold,"], ["ua faapea ona fetalai mai o le Alii:", "thus saith the Lord:"], ["O le a ou le faaali atu lou malosi i e amioleaga,", "I will not show unto the wicked of my strength,"], ["i le tasi ia sili atu le tasi,", "to one more than the other,"], ["vagana ai ia te i latou o e salamo ia latou agasala,", "save it be unto those that repent of their sins,"], ["ma faalogo mai i au upu. O lenei o lea,", "and hearken unto my words. Now therefore,"], ["ou uso e,", "I would that ye should behold,"], ["ou te manao ia outou iloa,", "my brethren,"], ["o le a sili atu ona lelei mo sa Lamanā nai lo outou vagana ai ua outou salamo.", "that it shall be better for the Lamanites than for you except ye shall repent."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["ua sili atu ona latou amiotonu nai lo outou,", "they are more righteous than you,"], ["ona ua latou le agasala e faasaga i le malamalama tele lea ua outou maua;", "for they have not sinned against that great knowledge which ye have received;"], ["o lea o le a alofa mutimutivale tele ai le Alii ia te i latou;", "therefore the Lord will be merciful unto them;"], ["ioe,", "yea,"], ["o le a ia faalevalevaina o latou aso ma faatoateleina a latou fanau,", "he will lengthen out their days and increase their seed,"], ["e oo lava pe a faaumatiaina atoa oe vagana ai ua e salamo.", "even when thou shalt be utterly destroyed except thou shalt repent."]]},
  {num:25,words:[["Ioe,", "Yea,"], ["oi talofa ia te outou ona o lena mea inosia tele ua oo mai i o outou luga;", "wo be unto you because of that great abomination which has come among you;"], ["ma ua outou faaaufaatasi atu i ai outou lava,", "and ye have united yourselves unto it,"], ["ioe,", "yea,"], ["i lena vaega faalilolilo lea na faatuina e Katianetona!", "to that secret band which was established by Gadianton!"]]},
  {num:26,words:[["Ioe,", "Yea,"], ["o le a oo mai le malaia ia te outou ona o lena faamaualuga ua outou tuu e ulu mai i o outou loto,", "wo shall come unto you because of that pride which ye have suffered to enter your hearts,"], ["lea ua faafefeteina ai outou i luga ia sili atu i lo le mea ua lelei ona o a outou oa ua silisili ona tele!", "which has lifted you up beyond that which is good because of your exceedingly great riches!"]]},
  {num:27,words:[["Ioe,", "Yea,"], ["oi talofa ia te outou ona o lo outou amioleaga ma a outou mea inosia!", "wo be unto you because of your wickedness and abominations!"]]},
  {num:28,words:[["Ma e vagana ai ua outou salamo o le a outou fano;", "And except ye repent ye shall perish;"], ["ioe,", "yea,"], ["e oo lava i o outou laueleele o le a aveesea mai ia te outou,", "even your lands shall be taken from you,"], ["ma o le a faaumatia ese outou mai luga o le lalolagi.", "and ye shall be destroyed from off the face of the earth."]]},
  {num:29,words:[["Faauta o lenei,", "Behold now,"], ["ou te le fai atu au lava ia,", "I do not say that these things shall be,"], ["o le a oo mai nei mea,", "of myself,"], ["ona e le o au na ou iloa ai nei mea; ae faauta,", "because it is not of myself that I know these things;"], ["ua ou iloa ua moni nei mea,", "but behold,"], ["ona o le Alii le Atua na ia faaalia mai nei mea ia te au,", "I know that these things are true because the Lord God has made them known unto me,"], ["o lea ou te molimau atu ai o le a faataunuuina lava.", "therefore I testify that they shall be."]]},
];
renderVerseSet(he_ch_7_Verses, 'he-ch7-verses');

var he_ch_8_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona fai atu e Nifae o nei upu,", "And now it came to pass that when Nephi had said these words,"], ["faauta,", "behold,"], ["sa i ai tagata o e o ni faamasino,", "there were men who were judges,"], ["ma o e foi sa auai i le vaega faalilolilo a Katianetona,", "who also belonged to the secret band of Gadianton,"], ["sa feita i latou,", "and they were angry,"], ["ma sa latou alalaga tetee faasaga ia te ia,", "and they cried out against him,"], ["ua fai atu i tagata:", "saying unto the people:"], ["Aisea tatou te le pue ai lenei tagata ma aumai o ia,", "Why do ye not seize upon this man and  bring him forth,"], ["ina ia faasalaina o ia e tusa ma le solitulafono lea ua ia faia?", "that he may be condemned according to the crime which he has done?"]]},
  {num:2,words:[["Aisea tou te vaai atu ai i lenei tagata,", "Why seest thou this man,"], ["ma faalogo atu ia te ia o faifai e faasaga i lenei nuu ma faasaga i la tatou tulafono?", "and hearest him revile against this people and against our law?"]]},
  {num:3,words:[["Aua faauta,", "For behold,"], ["sa tautala atu Nifae ia te i latou e uiga i le leaga o la latou tulafono;", "Nephi had spoken unto them concerning the corruptness of their law;"], ["ioe,", "yea,"], ["e tele mea na tautala atu ai Nifae ia ua le mafai ona tusia;", "many things did Nephi speak which cannot be written;"], ["ma sa leai se mea sa tautala atu ai o ia sa le tusa ai ma poloaiga a le Atua.", "and nothing did he speak which was contrary to the commandments of God."]]},
  {num:4,words:[["Ma sa feita ia faamasino ia te ia ona sa tautala atu o ia ma le manino ia te i latou e faatatau ia latou galuega faalilolilo o le pouliuli;", "And those judges were angry with him because he spake plainly unto them concerning their secret works of darkness;"], ["e ui i lea,", "nevertheless,"], ["sa latou fefefe e fetagofi atu o latou lima ia te ia,", "they durst not lay their own hands upon him,"], ["ona sa latou matatau i le nuu nei o latou alalaga tetee mai faasaga ia te i latou.", "for they feared the people lest they should cry out against them."]]},
  {num:5,words:[["O lea na latou alalaga atu ai i tagata,", "Therefore they did cry unto the people,"], ["fai mai:", "saying:"], ["Aisea ua outou tuu ai lenei tagata e faifai faasaga mai ia i tatou? Aua faauta ua tausalaina e ia lenei nuu atoa,", "Why do you suffer this man to revile against us? For behold he doth condemn ll this people,"], ["e oo lava i le faaumatiaina;", "even unto destruction;"], ["ioe,", "yea,"], ["ma e faapea foi o o tatou aai tetele nei o le a aveesea mai ia i tatou,", "and also that these our great cities shall be taken from us,"], ["ma o le a tatou le maua ai se nofoaga i totonu o i latou.", "that we shall have no place in them."]]},
  {num:6,words:[["Ma o lenei ua tatou iloa e le mafai ona oo mai o lenei mea,", "And now we know that this is impossible,"], ["aua faauta,", "for behold,"], ["ua tatou malolosi,", "we are powerful,"], ["ma ua tetele o tatou aai,", "and our cities great,"], ["o lea e le mafai ai e o tatou fili ona maua se mana i luga o i tatou.", "therefore our enemies can have no power over us."]]},
  {num:7,words:[["Ma sa oo ina faapea ona latou faaoso o tagata ia feita e faasaga ia Nifae,", "Yea, behold it is now even at your doors;"], ["ma faatutupu finauga i totonu ia te i latou;", "yea,"], ["ona sa i ai ni isi o e sa alalaga mai:", "go ye in unto the judgment– seat, and search;"], ["Ia tuu pea ia lenei tagata,", "and behold, your judge is murdered,"], ["ona o ia o se tagata lelei,", "and he lieth in his blood;"], ["ma o mea na na ia fai mai ai o le a taunuu moni vagana ai ua tatou salamo;", "and he hath been murdered by his brother, who seeketh to sit in the judgment– seat."]]},
  {num:8,words:[["Ioe,", "Yea,"], ["faauta,", "behold,"], ["o le a oo mai ia te i tatou faamasinoga uma ia na ia molimau mai ai ia i tatou;", "all the judgments will come upon us which he has testified unto us;"], ["ona ua tatou iloa ua sao lana molimau ia te i tatou e uiga ia tatou amioletonu. Ma faauta ua tele i latou,", "for we know that he has testified aright unto us concerning our iniquities. And behold they are many,"], ["ma ua ia iloa foi mea uma o le a pauu mai ia te i tatou e pei ona ia iloa e uiga ia tatou amioletonu;", "and he knoweth as well all things which shall befall us as he knoweth of our iniquities;"]]},
  {num:9,words:[["Ioe,", "Yea,"], ["ma faauta,", "and behold,"], ["a na fai e le o ia o se perofeta po ua le mafai e ia ona molimau mai e uiga i ia mea.", "if he had not been a prophet he could not have testified concerning those things."]]},
  {num:10,words:[["Ma sa oo ina faamalolosia tagata uma na o e na saili e faaumatia Nifae ona o lo latou fefefe,", "And it came to pass that those people who sought to destroy Nephi were compelled because of their fear,"], ["sa latou le fetagofi atu ai o latou lima ia te ia;", "that they did not lay their hands on him;"], ["o lea na toe amata ai ona ia tautala atu ia te i latou,", "therefore he began again to speak unto them,"], ["ina ua vaai atu ua ia maua le lagolagoina i manatu o ni isi,", "seeing that he had gained favor in the eyes of some,"], ["sa oo ina fefefe le vaega na totoe o i latou.", "insomuch that the remainder of them did fear."]]},
  {num:11,words:[["O lea na faamalosia ai o ia e tautala atili atu ia te i latou ua fai atu:", "Therefore he was constrained to speak more unto them saying:"], ["Faauta,", "Behold,"], ["ou uso e,", "my brethren,"], ["tou te lei faitau ea sa tuuina mai e le Atua le mana i se tagata e toatasi,", "have ye not read that God gave power unto one man,"], ["o Mose lava lea,", "even Moses,"], ["e taia ai i luga o vai o le Sami Ulaula,", "to smite upon the waters of the Red Sea,"], ["ma vavae ai i le tasi itu ma le isi itu,", "and they parted hither and thither,"], ["sa oo ina ui mai ai Isaraelu,", "insomuch that the Israelites,"], ["o e o o tatou tamā,", "who were our fathers,"], ["i luga o le eleele matutu,", "came through upon dry ground,"], ["ma faaoo ai vai i luga o autau a Aikupito ma tofatumoanaina ai i latou.", "and the waters closed upon the armies of the Egyptians and swallowed them up?"]]},
  {num:12,words:[["Ma o lenei faauta,", "And now behold,"], ["afai na tuu mai e le Atua i lenei tagata se mana faapena,", "if God gave unto this man such power,"], ["aisea ea la tou te finau ai i totonu ia te outou lava,", "then why should ye dispute among yourselves,"], ["ma fai mai e lei tuuina mai e ia ia te au se mana e mafai ai ona ou iloa e uiga i faamasinoga ia o le a oo mai i luga o outou vagana ai ua outou salamo?", "and say that he hath given unto me  no power whereby I may know concerning the judgments that shall come upon you except ye repent?"]]},
  {num:13,words:[["Ae faauta,", "But,"], ["ua le nao au upu ua outou teena,", "behold,"], ["ae ua outou teena foi upu uma ia na tautala i ai o tatou tamā,", "ye not only deny my words,"], ["ma upu foi na tautala i ai lenei tagata,", "but ye also deny all the words which have been spoken by our fathers,"], ["o Mose,", "and also the words which were spoken by this man, Moses,"], ["o le na tuuina mai ia te ia se mana tele faapea;", "who had such great power given unto him,"], ["ioe,", "yea,"], ["o upu ia na ia tautala i ai e uiga i le afio mai o le Mesia.", "the words which he hath spoken concerning the coming of the Messiah."]]},
  {num:14,words:[["Ioe,", "Yea,"], ["na te lei molimau mai ea o le a afio mai le Alo o le Atua? Ma e pei ona sa sii i luga e ia le gata apamemea i le vao,", "did he not bear record that the Son of God should come? And as he lifted up the brazen serpent in the wilderness,"], ["o le a faapea lava ona sii i luga o ia o le o le a afio mai.", "even so shall he be lifted up who should come."]]},
  {num:15,words:[["Ma e pei ona ola le toatele o e na vaai ae i luga i lena gata,", "And as many as should look upon that serpent should live,"], ["o le a faapea lava ona mafai ona ola o le toatele o e e vaai ae i luga ma le faatuatua i le Alo o le Atua,", "even so as many as should look upon the Son of God with faith,"], ["ma ua i ai le agaga salamo,", "having a contrite spirit, might live,"], ["i lena lava ola ua faavavau.", "even unto that life which is eternal."]]},
  {num:16,words:[["Ma o lenei faauta,", "And now behold,"], ["ua le nao Mose na molimau e uiga i nei mea,", "Moses did not only testify of these things,"], ["ae o perofeta paia uma foi,", "but also all the holy prophets,"], ["mai i ona aso e oo atu i aso o Aperaamo.", "from his days even to the days of Abraham."]]},
  {num:17,words:[["Ioe,", "Yea,"], ["ma faauta,", "and behold,"], ["sa vaai Aperaamo i lona afio mai,", "Abraham saw of his coming,"], ["ma sa faatumuina o ia i le fiafia ma sa olioli.", "and was filled with gladness and did rejoice."]]},
  {num:18,words:[["Ioe,", "Yea,"], ["ma faauta,", "and behold I say unto you,"], ["ou te fai atu ia te outou, sa le gata ina iloa e Aperaamo e uiga i nei mea,", "that Abraham not only knew of these things,"], ["ae sa i ai le toatele ae lei oo i aso o Aperaamo o e na valaauina i le faatulagaga a le Atua;", "but there were many before the days of Abraham who were called by the order of God;"], ["ioe,", "yea,"], ["e tusa lava ma le faatulagaga a lona Alo,", "even after the order of his Son;"], ["na latou iloaina; ma sa faia lenei mea ona sa tatau ona faaalia o ia mea i tagata,", "and this that it should be shown unto the people,"], ["i le tele o afe o tausaga ae lei oo i lona afio mai,", "a great many thousand years before his coming,"], ["o le a oo mai lava le togiola ia te i latou.", "that even redemption should come unto them."]]},
  {num:19,words:[["Ma o lenei ou te manao ina ia outou iloa,", "And now I would that ye should know,"], ["talu mai aso o Aperaamo sa i ai lava perofeta e toatele na molimau mai i nei mea;", "that even since the days of Abraham there have been many prophets that have testified these things;"], ["ioe,", "yea,"], ["faauta,", "behold,"], ["na molimau mai ai le perofeta o Senosa ma le lotoa;", "the prophet Zenos did testify boldly;"], ["o se mea na fasiotia ai o ia.", "for the which he was slain."]]},
  {num:20,words:[["Ma faauta,", "And behold,"], ["o Senoka foi,", "also Zenock,"], ["ma Esaia foi,", "and also Ezias,"], ["ma Isaia foi,", "and also Isaiah,"], ["ma Ieremia ,", "and Jeremiah,"], ["(o Ieremaia o le perofeta lava lea e tasi na molimau mai e uiga i le faaumatiaga o Ierusalema ) ma o lenei ua tatou iloa ua faaumatia Ierusalema e tusa ma upu a Ieremia. O lea la aisea o le a le afio mai ai le Alo o le Atua,", "(Jeremiah being that same prophet who testified of the destruction of Jerusalem) and now we know that Jerusalem was destroyed according to the words of Jeremiah. O then why not the Son of God come,"], ["e tusa ma lana valoaga?", "according to his prophecy?"]]},
  {num:21,words:[["Ma o lenei tou te masalogia ea ua faaumatiaina Ierusalema ? Tou te fai mai ea e lei fasiotia atalii uma o Setekaia,", "And now will you dispute that Jerusalem was destroyed? Will ye say that the sons of Zedekiah were not slain,"], ["o i latou uma ia vagana ai Moleka ? Ioe,", "all except it were Mulek? Yea,"], ["ma tou te le o vaai ea ua faatasi le fanau a Setekaia ma i tatou,", "and do ye not behold that the seed of Zedekiah are with us,"], ["ma sa tutuli ese i latou i fafo mai le laueleele o Ierusalema? Ae faauta,", "and they were driven out of the land of Jerusalem? But behold,"], ["ua le ona pau lea—", "this is not all—"]]},
  {num:22,words:[["Sa tuli ese lo tatou tamā o Liae i fafo mai Ierusalema ona sa ia molimau atu e uiga i nei mea. Sa molimau foi Nifae e uiga i nei mea,", "Our father Lehi was driven out of Jerusalem because he testified of these things. Nephi also testified of these things,"], ["ma sa toetoe foi o o tatou tamā uma,", "and also almost all of our fathers,"], ["seia oo mai lava i lalo i le taimi nei;", "even down to this time;"], ["ioe,", "yea,"], ["sa latou molimau mai e uiga i le afio mai o Keriso,", "they have testified of the coming of Christ,"], ["ma sa tulimatai i luma,", "and have looked forward,"], ["ma olioli i lona aso o le a oo mai.", "and have rejoiced in his day which is to come."]]},
  {num:23,words:[["Ma faauta,", "And behold,"], ["o ia o le Atua,", "he is God,"], ["ma ua faatasi o ia ma i latou,", "and he is with them,"], ["ma sa ia faaali mai o ia lava ia te i latou,", "and he did manifest himself unto them,"], ["ma ua ia togiolaina i latou;", "that they were redeemed by him;"], ["ma sa latou avatu ai ia te ia le viiga,", "and they gave unto him glory,"], ["ona o lena mea o le a oo mai.", "because of that which is to come."]]},
  {num:24,words:[["Ma o lenei,", "And now,"], ["ona ua outou iloa nei mea ma ua le mafai ona outou faafitia vagana ai ua outou pepelo,", "seeing ye know these things and cannot deny them except ye shall lie,"], ["o lea ua outou agasala ai i lenei mea,", "therefore in this ye have sinned,"], ["ona ua outou teena nei mea uma,", "for ye have rejected all these things,"], ["e ui i le tele o faamaoniga ua outou maua;", "notwithstanding so many evidences which ye have received;"], ["ioe,", "yea,"], ["ua outou maua lava mea uma,", "even ye have received all things,"], ["o mea o i le lagi,", "both things in heaven,"], ["ma mea uma ua i ai i le lalolagi,", "and all things which are in the earth,"], ["o se molimau ua moni i latou.", "as a witness that they are true."]]},
  {num:25,words:[["Ae faauta,", "But behold,"], ["ua outou teena le upumoni,", "ye have rejected the truth,"], ["ma fouvale faasaga i lo outou Atua paia;", "and rebelled against your holy God;"], ["ma e oo lava i lenei taimi,", "and even at this time,"], ["nai lo le teuina mo outou lava o oa i le lagi,", "instead of laying up for yourselves treasures in heaven,"], ["e le pala ai se mea,", "where nothing doth corrupt,"], ["ma o se mea e le mafai ona oo atu i ai se mea eleelea,", "and where nothing can come which is unclean,"], ["ua outou faaputuina mo outou lava le toasa mo le aso o le faamasinoga .", "ye are heaping up for yourselves wrath against the day of judgment."]]},
  {num:26,words:[["Ioe,", "Yea,"], ["e oo lava i le taimi nei o loo outou matutua ae, ona o a outou fasiotiga tagata,", "even at this time ye are ripening,"], ["ma lo outou faitaaga ma amioleaga,", "because of your murders and your fornication and wickedness,"], ["mo le faafanoga tumau-faavavau;", "for everlasting destruction;"], ["ioe, ma e vagana ai ua outou salamo,", "yea,"], ["o le a lata ona oo mai ia te outou.", "and except ye repent it will come unto you soon."]]},
  {num:27,words:[["Ioe,", "yea"], ["faauta,", "behold"], ["ua i ai nei lava", "therein this indeed"], ["i o outou faitotoa;", "in ye all gate"], ["ioe,", "yea"], ["ina outou o atu ia i le nofoa-faamasino,", "let ye all to in the nofoa-faamasino"], ["ma suesue;", "and suesue"], ["ma", "and"], ["faauta,", "behold"], ["ua fasiotia lo outou faamasino,", "slain your a judge"], ["ma o loo taatia o ia i lona toto;", "and taatia he in his blood"], ["ma", "and"], ["sa fasiotia o ia", "slain he"], ["e lona uso,", "by his a relative of the same generation and gender"], ["o le ua saili", "the seek"], ["e nofo", "to dwell"], ["i le nofoa-faamasino.", "in the nofoa-faamasino"]]},
  {num:28,words:[["Ma faauta,", "And behold,"], ["ua auai i laua uma i la outou vaega faalilolilo,", "they both belong to your secret band,"], ["o lona 'autu o Katianetona ma le ua leaga o le ua saili e faaumatia agaga o tagata.", "whose author is Gadianton and the evil one who seeketh to destroy the souls of men."]]},
];
renderVerseSet(he_ch_8_Verses, 'he-ch8-verses');

var he_ch_9_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina ua uma ona fai atu e Nifae o nei upu,", "now it came to pass that when Nephi had spoken these words,"], ["sa i ai ni tagata o e sa i totonu ia te i latou sa taufetuli atu i le nofoa-faamasino;", "certain men who were among them ran to the judgment– seat;"], ["ioe,", "yea,"], ["e toalima i latou o e na o atu,", "even there were five who went,"], ["ma sa latou fai ifo i totonu ia te i latou lava,", "and they said among themselves,"], ["ao latou o atu:", "as they went:"]]},
  {num:2,words:[["Faauta,", "Behold,"], ["o le a tatou iloa moni nei pe o lenei tagata o se perofeta ma pe na poloaiina o ia e le Atua e vavalo mai ni mea ofoofogia faapea ia te i tatou. Faauta,", "now we will know of a surety whether this man be a prophet and God hath commanded him to prophesy such marvelous things unto us. Behold,"], ["tatou te le talitonu na ia poloaiina o ia;", "we do not believe that he hath;"], ["ioe,", "yea,"], ["tatou te le talitonu o ia o se perofeta;", "we do not believe that he is a prophet;"], ["e ui i lea,", "nevertheless,"], ["afai e moni lenei mea na ia fai mai ai e uiga i le faamasino sili,", "if this thing which he has said concerning the chief judge be true,"], ["e faapea ua oti o ia,", "that he be dead,"], ["ona tatou talitonu ai lea ua moni isi upu na ia fai mai ai.", "then will we believe that the other words which he has spoken are true."]]},
  {num:3,words:[["Ma sa oo ai lea ina latou taufetuli atu ma lo latou malosi,", "And it came to pass that they ran in their might,"], ["ma ua oo atu ai i le nofoa-faamasino;", "and came in unto the judgment– seat;"], ["ma faauta,", "and behold,"], ["ua pa'ū le faamasino i le eleele,", "the chief judge had fallen to the earth,"], ["ma sa taoto i lona toto.", "and did lie in his blood."]]},
  {num:4,words:[["Ma o lenei faauta,", "And now behold,"], ["ina ua latou vaai i lenei mea,", "when they saw this they were astonished exceedingly,"], ["sa latou ofo tele, sa oo ina latou pauu i le eleele;", "insomuch that they fell to the earth;"], ["ona sa latou le talitonu i upu na tautala i ai Nifae e uiga i le faamasino sili.", "for they had not believed the words which Nephi had spoken concerning the chief judge."]]},
  {num:5,words:[["Ae o lenei,", "But now,"], ["ina ua latou vaai,", "when they saw they believed,"], ["ua latou talitonu, ma sa oo mai le matatau i luga o i latou nei oo mai i luga o le nuu faamasinoga uma na tautala i ai Nifae;", "and fear came upon them lest all the judgments which Nephi had spoken should come upon the people;"], ["o lea na latou gatetete ai,", "therefore they did quake,"], ["ma pauu i le eleele.", "and had fallen to the earth."]]},
  {num:6,words:[["O lenei,", "Now,"], ["i le taimi lava ina ua uma ona fasiotia o le faamasin—ona sa tui o ia e lona uso sa ofu faalilolilo,", "immediately when the judge had been murdered—he being stabbed by his brother by a garb of secrecy,"], ["ma sa sola o ia,", "and he fled,"], ["ma sa taufetuli atu auauna ma tau atu i tagata,", "and the servants ran and told the people,"], ["ma alalaga atu ua i ai se fasiotiga tagata i totonu ia te i latou;", "raising the cry of murder among them;"]]},
  {num:7,words:[["Ma faauta sa faapotopoto ane faatasi e tagata i latou lava i le mea na i ai le nofoa-faamasino—ma faauta, i lo latou ofo tele,", "And behold the people did gather themselves together unto the place of the judgment– seat—and behold,"], ["sa latou vaai atu i tagata na e toalima o e ua pauu i le eleele.", "to their astonishment they saw those five men who had fallen to the earth."]]},
  {num:8,words:[["Ma o lenei faauta,", "And now behold,"], ["sa le iloa e tagata se mea e uiga i le motu o tagata o e sa faapotopoto faatasi i le faatoaga a Nifae;", "the people knew nothing concerning the multitude who had gathered together at the garden of Nephi;"], ["o lea na latou fai ane ai i totonu ia te i latou lava:", "therefore they said among themselves:"], ["O tagata nei o i latou ia o e na fasiotia le faamasino,", "These men are they who have murdered the judge,"], ["ma ua taia i latou e le Atua ina ia le mafai ona latou sosola ese mai ia te i tatou.", "and God has smitten them that they could not flee from us."]]},
  {num:9,words:[["Ma sa oo ina latou pupue i latou,", "And it came to pass that they laid hold on them,"], ["ma saisai i latou ma lafo i latou i le falepuipui. Ma sa i ai se folafolaga sa auina atu lautele ua fasiotia le faamasino,", "and bound them and cast them into prison. And there was a proclamation sent abroad that the judge was slain,"], ["ma ua ave e na fasiotia o ia ma lafo i le falepuipui.", "and that the murderers had been taken and were cast into prison."]]},
  {num:10,words:[["Ma sa oo i le aso na sosoo ai sa faapotopoto faatasi le nuu e faanoanoa ma anapopogi ,", "And it came to pass that on the morrow the people did assemble themselves together to mourn and to fast,"], ["i le falelauasiga o le faamasino sili maualuga o le ua fasiotia.", "at the burial of the great chief judge who had been slain."]]},
  {num:11,words:[["Ma sa faapea foi ona faapotopoto ane faatasi faamasino o e sa i ai i le faatoaga a Nifae,", "And thus also those judges who were at the garden of Nephi,"], ["ma faalogo i ana upu,", "and heard his words,"], ["i le falelauasiga.", "were also gathered together at the burial."]]},
  {num:12,words:[["Ma sa oo ina latou fesilisili i tagata,", "And it came to pass that they inquired among the people,"], ["ua fai atu:", "saying:"], ["O fea o i ai le toalima o e na auina atu e fesili e uiga i le faamasino sili pe ua oti o ia? Ma sa latou tali mai ma fai mai:", "Where are the five who were sent to inquire concerning the chief judge whether he was dead? And they answered and said:"], ["E uiga i lenei toalima o e na outou fai mai na outou auina mai,", "Concerning this five whom ye say ye have sent,"], ["matou te le iloa;", "we know not;"], ["ae e i ai se toalima o e na fasiotia o ia,", "but there are five who are the murderers,"], ["ua matou lafoina i le falepuipui.", "whom we have cast into prison."]]},
  {num:13,words:[["Ma sa oo ina mananao faamasino ia aumai i latou;", "And it came to pass that the judges desired that they should be brought;"], ["ma sa aumai i latou,", "and they were brought,"], ["ma faauta o i latou ia o le toalima o e na auina atu;", "and behold they were the five who were sent; and behold the judges inquired of them to know,"], ["ma faauta sa fesiligia i latou e faamasino ina ia latou iloa e uiga i le mataupu,", "concerning the matter,"], ["ma sa latou faamatala mai ia te i latou mea uma na latou faia,", "and they told them all that they had done,"], ["ua fai mai:", "saying:"]]},
  {num:14,words:[["Sa matou taufetuli ma o atu i le mea o i ai le nofoa-faamasino,", "We ran and came to the place of the judgment– seat,"], ["ma ina ua matou vaai atu i mea uma e pei ona sa molimau mai ai Nifae,", "and when we saw all things even as Nephi had testified,"], ["sa matou ofo tele sa oo ina matou pauu i le eleele; ma ina ua mavae atu lo matou ofo,", "we were astonished insomuch that we fell to the earth;"], ["faauta,", "and when we were recovered from our astonishment,"], ["ua latou lafo i matou i le falepuipui.", "behold they cast us into prison."]]},
  {num:15,words:[["O lenei,", "Now,"], ["e uiga i le fasiotiga o lenei tagata,", "as for the murder of this man,"], ["matou te le iloa po o ai na faia;", "we know not who has done it;"], ["ma ua nao le pau lenei o le mea ua matou iloa, sa matou taufetuli ma o mai e tusa ma lo outou manao,", "and only this much we know,"], ["ma faauta,", "we ran and came according as ye desired,"], ["ua oti o ia,", "and behold he was dead,"], ["e tusa ma upu a Nifae.", "according to the words of Nephi."]]},
  {num:16,words:[["Ma o lenei sa oo ina faamalamalama atu le mataupu e faamasino i tagata,", "And now it came to pass that the judges did expound the matter unto the people,"], ["ma alalaga e faasaga ia Nifae,", "and did cry out against Nephi,"], ["ua fai mai:", "saying:"], ["Faauta,", "Behold,"], ["ua matou iloa atonu sa faia e lenei Nifae se ioega faatasi ma se tasi e fasioti le faamasino,", "we know  that this Nephi must have agreed with someone to slay the judge,"], ["ma a uma ona ia tau mai lea ia te i tatou,", "and then he might declare it unto us,"], ["ina ia mafai e ia ona faaliliu atu i tatou i lana faatuatuaga,", "that he might convert us unto his faith,"], ["ina ia mafai ona ia sii ae o ia lava o se tagata maoae,", "that he might raise himself to be a great man,"], ["ua filifilia e le Atua,", "chosen of God,"], ["ma o se perofeta.", "and a prophet."]]},
  {num:17,words:[["Ma o lenei faauta,", "And now behold,"], ["o le a matou faaalia lenei tagata,", "we will detect this man,"], ["ma o le a ia tau mai lona sese ma faailoa mai ia te i tatou le tagata moni na fasiotia lenei faamasino.", "and he shall confess his fault and make known unto us the true murderer of this judge."]]},
  {num:18,words:[["Ma sa oo ina tatala saoloto le toalima i le aso o le falelauasiga. E ui i lea,", "And it came to pass that the five were liberated on the day of the burial. Nevertheless,"], ["sa latou tauseseina faamasino i upu na latou tautatala i ai faasaga ia Nifae,", "they did rebuke the judges in the words which they had spoken against Nephi,"], ["ma latou finau ma i latou taitoatasi,", "and did contend with them one by one,"], ["sa oo lava ina latou faafememeaiina i latou.", "insomuch that they did confound them."]]},
  {num:19,words:[["E ui i lea,", "Nevertheless,"], ["sa latou faatonu atu ia pue Nifae ma saisai ma aumai i luma o le motu o tagata,", "they caused that Nephi should be taken and bound and brought before the multitude,"], ["ma sa amata ona latou fesiligia o ia i ala eseese ina ia mafai ona latou faasese o ia,", "and they began to question him in divers ways that they might cross him,"], ["ina ia mafai ona latou tausalaina o ia ia oti—", "that they might accuse him to death—"]]},
  {num:20,words:[["Ua fai mai ia te ia:", "Saying unto him:"], ["O oe o se taupulepule;", "Thou art confederate;"], ["o ai lenei tagata na faia lenei fasiotiga tagata? O lenei ia tau mai ia te i matou,", "who is this man that hath done this murder? Now tell us,"], ["ma tautino mai lou sese;", "and acknowledge thy fault;"], ["fai mai:", "saying,"], ["Faauta o tupe nei;", "Behold here is money;"], ["ma o le a matou tuu atu foi ia te oe lou ola pe afai e te tau mai ia te i matou,", "and also we will grant unto thee thy life if thou wilt tell us,"], ["ma tautino mai le feagaiga lea na e faia faatasi ma ia.", "and acknowledge the agreement which thou hast made with him."]]},
  {num:21,words:[["Peitai sa fai atu Nifae ia te i latou:", "But Nephi said unto them:"], ["E,", "O ye fools,"], ["outou vale e, outou e ua le peritomeina i le loto,", "ye uncircumcised of heart,"], ["outou o tauaso,", "ye blind,"], ["ma outou tagata ua maaa,", "and ye stiffnecked people,"], ["tou te iloa ea o le a le umi o le a tuu ai outou e le Alii lo outou Atua ia outou o ai pea i lenei ala o lo outou agasala?", "do ye know how long the Lord your God will suffer you that ye shall go on in this your way of sin?"]]},
  {num:22,words:[["E,", "O ye ought to begin to howl and mourn,"], ["ua tatau lava ia te outou ona amata ona outou uio ma faavauvau , ona o le faafanoga tele lea ua faatalitali mai i le taimi nei ia te outou,", "because of the great destruction which at this time doth await you,"], ["vagana ai ua outou salamo.", "except ye shall repent."]]},
  {num:23,words:[["Faauta ua outou fai mai na ou ioe faatasi ma se tagata ia fasioti e ia Sesorama,", "Behold ye say that I have agreed with a man that he should murder Seezoram,"], ["lo tatou faamasino sili. Ae faauta,", "our chief judge. But behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua outou fai mai faapea ona sa ou molimau atu ia te outou ina ia mafai ona outou iloa e uiga i lenei mea;", "that this is because I have testified unto you that ye might know concerning this thing;"], ["ioe,", "yea,"], ["sa ou tau atu lava lenei mea o se molimau ia te outou,", "even for a witness unto you,"], ["ua ou iloa e uiga i le amioleaga ma mea inosia ia ua i ai i totonu ia te outou.", "that I did know of the wickedness and abominations which are among you."]]},
  {num:24,words:[["Ma ona ua ou faailoa atu lenei mea,", "And because I have done this,"], ["ua outou fai mai sa ou ioe faatasi ma se tagata ia ona faia lenei mea;", "ye say that I have agreed with a man that he should do this thing;"], ["ioe,", "yea,"], ["ona sa ou faaali atu ia te outou lenei faailoga ua outou feita mai ai ia te au,", "because I showed unto you this sign ye are angry with me,"], ["ma saili e faaumatia lou ola.", "and seek to destroy my life."]]},
  {num:25,words:[["Ma o lenei faauta,", "And now behold,"], ["o le a ou faaali atu ia te outou se isi faailoga,", "I will show unto you another sign,"], ["ma vaai pe o le a outou saili ai e faaumatia au i lenei mea.", "and see if ye will in this thing seek to destroy me."]]},
  {num:26,words:[["Faauta ou te fai atu ia te outou:", "Behold I say unto you:"], ["O i le fale o Seanetuma,", "Go to the house of Seantum,"], ["o le o le uso o Sesorama,", "who is the brother of Seezoram,"], ["ma fai atu ia te ia—", "and say unto him—"]]},
  {num:27,words:[["Pe na ioe ea Nifae,", "Has Nephi,"], ["le faatagā perofeta,", "the pretended prophet,"], ["o le ua ia vavalo mai se leaga e tele i lenei nuu,", "who doth prophesy so much evil concerning this people,"], ["faatasi ma oe,", "agreed with thee,"], ["i se ioega na e fasiotia ai Sesorama,", "in the which ye have murdered Seezoram,"], ["o lou uso?", "who is your brother?"]]},
  {num:28,words:[["Ma faauta,", "And behold,"], ["o le a fai mai o ia ia te outou,", "he shall say unto you,"], ["E leai.", "Nay."]]},
  {num:29,words:[["Ma ia outou fai atu ia te ia:", "And ye shall say unto him:"], ["Na e fasiotia lou uso?", "Have ye murdered your brother?"]]},
  {num:30,words:[["Ma o le a tu o ia ma le fefe,", "And he shall stand with fear,"], ["ma le iloa se upu e fai mai. Ma faauta,", "and wist not what to say. And behold,"], ["o le a faafiti mai o ia ia te outou;", "he shall deny unto you;"], ["ma o le a faia e ia e peiseai ua tei;", "and he shall make as if he were astonished;"], ["e ui i lea,", "nevertheless,"], ["o le a ia fai mai ia te outou ua mama o ia.", "he shall declare unto you that he is innocent."]]},
  {num:31,words:[["Ae faauta,", "But behold,"], ["ia outou suesue o ia,", "ye shall examine him,"], ["ma o le a outou maua le toto i le vaega i lalo o lona ofu pulupulu.", "and ye shall find blood upon the skirts of his cloak."]]},
  {num:32,words:[["Ma a uma ona outou vaai i lenei mea,", "And when ye have seen this,"], ["ia outou fai atu:", "ye shall say:"], ["E mai fea lenei toto? Matou te le iloa ea o le toto lenei o lou uso?", "From whence cometh this blood? Do we not know that it is the blood of your brother?"]]},
  {num:33,words:[["Ma a uma o le a gatete ai o ia,", "And then shall he tremble,"], ["ma foliga mai ua sesega,", "and shall look pale,"], ["e pei lava ua oo mai le oti i ona luga.", "even as if death had come upon him."]]},
  {num:34,words:[["Ma a uma ona outou fai atu lea ia te ia:", "And then shall ye say:"], ["Ona o lenei fefe ma lenei sesega lea ua oo mai i ou mata,", "Because of this fear and this paleness which has come upon your face,"], ["faauta,", "behold,"], ["ua matou iloa ua e sala.", "we know that thou art guilty."]]},
  {num:35,words:[["Ma a uma o le a oo mai se matau tele atu i ona luga;", "And then shall greater fear come upon him;"], ["ma ona ia tautino mai ai lea ia te outou,", "and then shall he confess unto you,"], ["ma ia le toe faafitia o ia lava na faia lenei fasiotiga tagata.", "and deny no more that he has done this murder."]]},
  {num:36,words:[["Ma a uma o le a fai mai o ia ia te outou,", "And then shall he say unto you,"], ["o au,", "that I,"], ["o Nifae,", "Nephi,"], ["ua ou le iloa se mea e uiga i le mataupu vagana ai ua tuuina mai ia te au e le mana o le Atua. Ma o le a outou iloa ai o au o se tagata faamaoni,", "know nothing concerning the matter save it were given unto me by the power of God. And then shall ye know that I am an honest man,"], ["ma ua auina mai au ia te outou mai le Atua.", "and that I am sent unto you from God."]]},
  {num:37,words:[["Ma sa oo ina latou o atu ma faia,", "And it came to pass that they went and did,"], ["e tusa lava e pei ona fai atu ai Nifae ia te i latou. Ma faauta,", "even according as Nephi had said unto them. And behold,"], ["sa moni upu na ia fai mai ai;", "the words which he had said were true;"], ["ona e tusa ma upu sa faafiti o ia;", "for according to the words he did deny;"], ["ma e tusa foi ma upu sa tautino mai o ia.", "and also according to the words he did confess."]]},
  {num:38,words:[["Ma sa aumai o ia e faamaonia o ia lava o le fasioti tagata lea,", "And he was brought to prove that he himself was the very murderer,"], ["sa oo ina tatala faasaoloto le toalima,", "insomuch that the five were set at liberty,"], ["faapea foi ma Nifae.", "and also was Nephi."]]},
  {num:39,words:[["Ma sa i ai ni isi o sa Nifaē o e na talitonu i upu a Nifae;", "And there were some of the Nephites who believed on the words of Nephi;"], ["ma sa i ai foi ni isi,", "and there were some also,"], ["o e na talitonu ona o le molimau a le toalima,", "who believed because of the testimony of the five,"], ["ona sa faaliliuina i latou ao latou i ai i le falepuipui.", "for they had been converted while they were in prison."]]},
  {num:40,words:[["Ma o lenei sa i ai ni isi i totonu o le nuu,", "And now there were some among the people,"], ["o e na fai mai o Nifae o se perofeta.", "who said that Nephi was a prophet."]]},
  {num:41,words:[["Ma sa i ai ni isi o e na fai mai:", "And there were others who said:"], ["Faauta,", "Behold,"], ["o ia o se atua,", "he is a god,"], ["ona vagana ai o ia o se atua po ua le mafai ona ia iloaina mea uma. Aua faauta,", "for except he was a god he could not know of all things. For behold,"], ["na ia tau mai ia te i tatou mafaufauga o o tatou loto,", "he has told us the thoughts of our hearts,"], ["ma sa ia tau mai foi mea ia te i tatou;", "and also has told us things;"], ["ma sa ia faailoa mai lava ia i tatou le tagata moni na fasiotia lo tatou faamasino sili.", "and even he has brought unto our knowledge the true murderer of our chief judge."]]},
];
renderVerseSet(he_ch_9_Verses, 'he-ch9-verses');

var he_ch_10_Verses = [
  {num:1,words:[["Ma sa oo ina tupu mai se fevaevaeaiga i totonu o tagata,", "And it came to pass that there arose a division among the people,"], ["sa oo ina fevaevaeai i latou i lea vaega ma lea vaega ma ua o ese atu i o latou ala,", "insomuch that they divided hither and thither and went their ways,"], ["a ua tuu ai Nifae nao ia,", "leaving Nephi alone,"], ["ao tu o ia i le lotolotoi o i latou.", "as he was standing in the midst of them."]]},
  {num:2,words:[["Ma sa oo ina alu atu Nifae i lona ala e agai atu i lona lava fale,", "And it came to pass that Nephi went his way towards his own house,"], ["ma manatunatu loloto i mea na faaali mai e le Alii ia te ia.", "pondering upon the things which the Lord had shown unto him."]]},
  {num:3,words:[["Ma sa oo ina ao faapea ona manatunatu loloto o ia—ma le faanoanoa tele ona o le amioleaga o tagata sa Nifaē,", "And it came to pass as he was thus pondering being much cast down because of the  wickedness of the people of the Nephites,"], ["a latou galuega faalilolilo o le pouliuli,", "their secret works of darkness,"], ["ma a latou fasiotiga tagata,", "and their murderings,"], ["ma a latou vetega, ma amioletonu eseese uma—ma sa oo ao faapea ona manatunatu loloto o ia i lona loto,", "and their plunderings,"], ["faauta,", "and all manner of iniquities—and it came to pass as he was thus pondering in his heart,"], ["sa oo mai se siufofoga ia te ia,", "behold,"], ["ua fetalai mai:", "a voice came unto him saying:"]]},
  {num:4,words:[["Amuia lava oe Nifae,", "Blessed art thou, Nephi,"], ["ona o ia mea na e faia;", "for those things which thou hast done;"], ["ona ua ou vaai i lou talai atu ma le le faavaivai o le upu na ou tuuina atu ia te oe,", "for I have beheld how thou hast with unwearyingness declared the word,"], ["i lenei nuu.", "which I have given unto thee, unto this people."], ["Ma sa e le fefe ia te i latou,", "And thou hast not feared them,"], ["ma sa e le sailia lou lava ola,", "and hast not sought thine own life,"], ["ae sa e saili lo'u loto ,", "but hast sought my will,"], ["ma ia tausia au poloaiga.", "and to keep my commandments."]]},
  {num:5,words:[["Ma o lenei,", "And now,"], ["ona ua e faia lenei mea ma le le faavaivai,", "because thou hast done this with such unwearyingness,"], ["faauta,", "behold,"], ["o le a ou faamanuiaina oe e faavavau;", "I will bless thee forever;"], ["ma o le a ou faamamanaina oe i le upu ma mea e fai,", "and I will make thee mighty in word and in deed,"], ["i le faatuatua ma galuega;", "in faith and in works;"], ["ioe,", "yea,"], ["e oo lava i le faia o mea uma ia te oe e tusa ai ma lau upu ,", "even that all things shall be done unto thee according to thy word,"], ["ona e te le ole mai i se mea ua le tusa ai ma lo'u loto.", "for thou shalt not ask that which is contrary to my will."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["o oe o Nifae,", "thou art Nephi,"], ["ma o au o le Atua. Faauta,", "and I am God. Behold,"], ["ou te tautino atu le mea lenei ia te oe i luma o au agelu,", "I declare it unto thee in the presence of mine angels,"], ["o le a ia te oe le mana i luga o lenei nuu,", "that ye shall have power over this people,"], ["ma o le a e taia le eleele i le oge ,", "and shall smite the earth with famine,"], ["ma le faamai,", "and with pestilence,"], ["ma le faafanoga,", "and destruction,"], ["e tusa ma le amioleaga o lenei nuu.", "according to the wickedness of this people."]]},
  {num:7,words:[["Faauta,", "Behold,"], ["ou te tuu atu ia te oe le mana,", "I give unto you power,"], ["o soo se mea e te faamaufaailogaina i luga o le lalolagi o le a faamaufaailogaina i le lagi;", "that whatso ever ye shall seal on earth shall be sealed in heaven;"], ["ma o soo se mea e te tatalaina i le lalolagi o le a tatalaina i le lagi;", "and whatsoever ye shall loose n earth shall be loosed in heaven;"], ["ma o le a faapea ona ia te oe le mana i totonu o lenei nuu.", "and thus shall ye have power among this people."]]},
  {num:8,words:[["Ma e faapea lava,", "And thus,"], ["afai e te fai atu i lenei malumalu ia vaeluaina,", "if ye shall say unto this temple it shall be rent in twain,"], ["o le a faia lava.", "it shall be done."]]},
  {num:9,words:[["Ma afai e te fai atu i lenei mauga ,", "And if ye shall say unto this mountain,"], ["Ia lafo oe i lalo ma ia laugatasi,", "Be thou cast down and become smooth,"], ["o le a faia lava.", "it shall be done."]]},
  {num:10,words:[["Ma faauta,", "And behold,"], ["afai e te fai atu o le a taia lenei nuu e le Atua,", "if ye shall say that God shall smite this people,"], ["o le a faataunuuina lava.", "it shall come to pass."]]},
  {num:11,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te poloai atu ia te oe,", "I command you,"], ["ia e alu atu ma tau atu i lenei nuu,", "that ye shall go and declare unto this people,"], ["ua faapea ona fetalai mai o le Alii le Atua,", "that thus saith the Lord God,"], ["o le ua Malosi Silisili:", "who is the Almighty:"], ["Vagana ai ua outou salamo o le a taia outou,", "Except ye repent ye shall be smitten,"], ["e oo lava ina faaumatia .", "even unto destruction."]]},
  {num:12,words:[["Ma faauta,", "And behold,"], ["o lenei sa oo ina ua uma ona fetalai mai e le Alii o nei upu ia Nifae,", "now it came to pass that when the Lord had spoken these words unto Nephi,"], ["sa tu o ia ma sa le alu atu i lona lava fale,", "he did stop and did not go unto his own house,"], ["ae ua toe foi atu i motu o tagata o e sa salalau solo i luga o le laueleele,", "but did return unto the multitudes who were scattered about upon the face of the land,"], ["ma amata ona talai atu ia te i latou le afioga a le Alii lea na fetalai mai ia te ia,", "and began to declare unto them the word of the Lord which had been spoken unto him,"], ["e uiga i le faaumatiaga o i latou pe afai latou te le salamo.", "concerning their destruction if they did not repent."]]},
  {num:13,words:[["O lenei faauta,", "Now behold,"], ["e ui i lea vavega tele na faia e Nifae i le tau atu ia te i latou e uiga i le maliu o le faamasino sili,", "notwithstanding that great miracle which Nephi had done in telling them concerning the death of the chief judge,"], ["sa latou faamaaa o latou loto ma le faalogo i fetalaiga a le Alii.", "they did harden their hearts and did not hearken unto the words of the Lord."]]},
  {num:14,words:[["O lea na talai atu ai e Nifae ia te i latou le afioga a le Alii,", "Therefore Nephi did declare unto them the word of the Lord,"], ["ua fai atu:", "saying:"], ["Ua faapea ona fetalai mai o le Alii,", "Except ye repent,"], ["vagana ai ua outou salamo,", "thus  saith the Lord,"], ["o le a taia outou e oo lava ina faaumatia.", "ye shall be smitten even unto destruction."]]},
  {num:15,words:[["Ma sa oo ina ua uma ona talai atu e Nifae le afioga ia te i latou,", "And it came to pass that when Nephi had declared unto them the word,"], ["faauta,", "behold,"], ["sa latou faamaaa pea o latou loto ma le fia faalogo mai i ana upu;", "they did still harden their hearts and would not hearken unto his words;"], ["o lea na latou faifai ai e faasaga mai ia te ia,", "therefore they did revile against him,"], ["ma saili e fetagofi mai o latou lima i luga ia te ia ina ia mafai ona latou lafo o ia i le falepuipui.", "and did seek to lay their hands upon him that they might cast him into prison."]]},
  {num:16,words:[["Ae faauta,", "But behold,"], ["sa faatasi le mana o le Atua ma ia,", "the power of God was with him,"], ["ma sa le mafai ona latou ave o ia e lafo i le falepuipui,", "and they could not take him to cast him into prison,"], ["ona sa ave o ia e le Agaga ma segia ese atu o ia i fafo mai totonu ia te i latou.", "for he was taken by the Spirit and conveyed away out of the midst of them."]]},
  {num:17,words:[["Ma sa oo ina faapea ona alu atu o ia i le Agaga,", "And it came to pass that thus he did go forth in the Spirit,"], ["mai lea motu o tagata i lea motu o tagata,", "from multitude to multitude,"], ["e talai atu le afioga a le Atua,", "declaring the word of God,"], ["seia oo lava ina uma ona ia talaia atu ia te i latou uma,", "even until he had declared it unto them all,"], ["pe auina atu i totonu o tagata uma.", "or sent it forth among all the people."]]},
  {num:18,words:[["Ma sa oo ina sa latou le fia faalogo i ana upu;", "And it came to pass that they would not hearken unto his words;"], ["ma sa amata ona i ai o finauga,", "and there began to be contentions,"], ["sa oo ina latou fevaevaeai e faasaga ia i latou lava ma amata ona latou fasioti o le tasi i le pelu.", "insomuch that they were divided against themselves and began to slay one another with the sword."]]},
  {num:19,words:[["Ma sa faapea ona iu o le fitusefulu ma le tasi o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the seventy and first year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(he_ch_10_Verses, 'he-ch10-verses');

var he_ch_11_Verses = [
  {num:1,words:[["Ma o lenei sa oo i le fitusefulu ma le lua o tausaga o le nofoaiga a faamasino sa faateteleina finauga,", "And now it came to pass in the seventy and second year of the reign of the judges that the contentions did increase,"], ["sa oo ina i ai taua i le laueleele atoa i totonu o tagata uma o Nifae.", "insomuch that there were wars throughout all the land among all the people of Nephi."]]},
  {num:2,words:[["Ma o lenei vaega faalilolilo o le au faomea o i latou ia o e na faia pea lenei galuega o le faafanoga ma le amioleaga. Ma sa faia lenei taua i lena tausaga atoa;", "And it was this secret band of robbers who did carry on this work of destruction and wickedness. And this war did last all that year;"], ["ma sa faia foi i le tausaga atoa e fitusefulu ma le tolu.", "and in the seventy and third year it did also last."]]},
  {num:3,words:[["Ma sa oo i le tausaga lenei, na tagi atu ai Nifae i le Alii,", "And it came to pass that in this year Nephi did cry unto the Lord,"], ["ua fai atu:", "saying:"]]},
  {num:4,words:[["Le Alii e,", "O Lord,"], ["aua e te tuuina lenei nuu ia faaumatia i le pelu;", "do not suffer that this people shall be destroyed by the sword;"], ["ae le Alii e,", "but O Lord,"], ["ia tuu mai ia i ai se oge i le laueleele,", "rather let there be a famine in the land,"], ["e faaosoina ai i latou ia latou manatua le Alii lo latou Atua,", "to stir them up in remembrance of the Lord their God,"], ["ma atonu o le a latou salamo ai ma liliu mai ia te oe.", "and perhaps they will repent and turn unto thee."]]},
  {num:5,words:[["Ma sa faapea lava ona faia,", "And so it was done,"], ["e tusa ma upu a Nifae. Ma sa i ai se oge tele na oo mai i luga o le laueleele,", "according to the words of Nephi. And there was a great famine upon the land,"], ["i totonu o tagata uma o Nifae. Ma sa faapea ona faaauau pea o le oge i le fitusefulu ma le fa o tausaga,", "among all the people of Nephi. And thus in the seventy and fourth year the famine did continue,"], ["ma sa oo ina taofia le galuega o le faafanoga i le pelu a ua sili atu ona tetele i le oge.", "and the work of destruction did cease by the sword but became sore by famine."]]},
  {num:6,words:[["Ma o lenei galuega o le faafanoga sa faaauau foi i le tausaga e fitusefulu ma le lima. Ona sa taia le laueleele sa oo ina matutu,", "And this work of destruction did also continue in the seventy and fifth year. For the earth was smitten that it was dry,"], ["ma sa le fua mai saito i le tau o saito;", "and did not yield forth grain in the season of grain;"], ["ma sa taia le laueleele atoa,", "and the whole earth was smitten,"], ["e oo lava i totonu o sa Lamanā faapea foi i totonu o sa Nifaē,", "even among the Lamanites as well as among the Nephites,"], ["sa oo ina taia i latou ma fano ai afe ma afe o i latou i vaega sili ona amioleaga o le laueleele.", "so that they were smitten that they did perish by thousands in the more wicked parts of the land."]]},
  {num:7,words:[["Ma sa oo ina vaai tagata o le a fano i latou i le oge,", "And it came to pass that the people saw that they were about to perish by famine,"], ["ma sa amata ona latou manatua le Alii lo latou Atua;", "and they began to remember the Lord their God;"], ["ma sa amata ona latou manatua upu a Nifae.", "and they began to remember the words of Nephi."]]},
  {num:8,words:[["Ma sa amata ona aioi atu tagata i o latou faamasino sili ma o latou taitai,", "And the people began to plead with their chief judges and their leaders,"], ["ina ia latou fai atu ia Nifae:", "that they would say unto Nephi:"], ["Faauta,", "Behold,"], ["ua matou iloa o oe o se tagata o le Atua,", "we know that thou art a man of God,"], ["o lea ia e ole atu i le Alii lo tatou Atua ia aveese lenei oge mai ia te i tatou,", "and therefore cry unto the Lord our God that he turn away from us this famine,"], ["nei faataunuuina upu uma na e fai mai ai e uiga i le faaumatiaga o i matou.", "lest all the words which thou hast spoken concern– ing our destruction be fulfilled."]]},
  {num:9,words:[["Ma sa oo ina fai atu faamasino ia Nifae e tusa ma upu ia na mananao i ai.", "And it came to pass that the judges did say unto Nephi, according to the words which had been desired."], ["Ma sa oo ina ua vaai Nifae ua salamo tagata ma ua latou faamaualalalo i latou lava i le ie talatala,", "And it came to pass that when Nephi saw that the people had repented and did humble themselves in sackcloth,"], ["sa toe ole atu o ia i le Alii,", "he cried again unto the Lord,"], ["ua fai atu:", "saying:"]]},
  {num:10,words:[["Le Alii e,", "O Lord,"], ["faauta ua salamo lenei nuu;", "behold this people repenteth;"], ["ma ua latou tafi ese le vaega a Katianetona mai totonu ia te i latou ua le toe i ai i latou,", "and they have swept away the band of Gadianton from amongst them insomuch that they have become extinct,"], ["ma ua latou natia a latou fuafuaga faalilolilo i le eleele.", "and they have concealed their secret plans in the earth."]]},
  {num:11,words:[["O lenei,", "Now,"], ["le Alii e,", "O Lord,"], ["ona o lo latou lotomaualalo lenei, sei e liliu ese lou toasa,", "because of this their humility wilt thou turn away thine anger,"], ["ma ia faamalieina lou toasa i le faaumatiaga o tagata amioleaga na o e ua uma ona e faaumatiaina.", "and let thine anger be appeased in the destruction of those wicked men whom thou hast already destroyed."]]},
  {num:12,words:[["Le Alii e,", "O Lord,"], ["sei e liliu ese lou toasa,", "wilt thou turn away thine anger,"], ["ioe,", "yea,"], ["lou toasa matautia,", "thy fierce anger,"], ["ma faia ia taofia lenei oge i lenei laueleele.", "and cause that this famine may cease in this land."]]},
  {num:13,words:[["Le Alii e,", "O Lord,"], ["sei e faafofoga mai ia te au,", "wilt thou hearken unto me,"], ["ma faia ia faia e tusa ma a'u upu,", "and cause that it may be done according to my words,"], ["ma auina mai le timu i luga o le eleele,", "and send forth rain upon the face of the earth,"], ["ina ia mafai ona ia aumai ona fua,", "that she may bring forth her fruit,"], ["ma ona saito i le tau o saito.", "and her grain in the season of grain."]]},
  {num:14,words:[["Le Alii e,", "O Lord,"], ["sa e faafofoga mai i au upu ina ua ou fai atu,", "thou didst hearken unto my words when I said,"], ["Ia i ai se oge,", "Let there be a famine,"], ["ina ia taofia le faamai o le pelu;", "that the pestilence of the sword might cease;"], ["ma ua ou mautinoa o le a e finagalo i lenei lava taimi,", "and I know that thou wilt,"], ["e faafofoga mai i a'u upu,", "even at this time,"], ["ona na e fetalai mai e faapea:", "hearken unto my words,"], ["Afai e salamo lenei nuu,", "for thou  dist that:"], ["o le a ou faasaoina i latou.", "If this people repent I will spare them."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["le Alii e,", "O Lord,"], ["ma ua e silasila mai ua latou salamo,", "and thou seest that they have repented,"], ["ona o le oge ma le faamai ma le faafanoga ua oo mai i o latou luga.", "because of the famine and the pestilence and destruction which has come unto them."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["le Alii e,", "O Lord,"], ["pe e te liliu ese ea lou toasa,", "wilt thou turn away thine anger,"], ["ma toe tofotofo i latou pe o le a latou auauna atu ia te oe? Afai o lea,", "and try again if they will serve thee? And if so,"], ["Le Alii e,", "O Lord,"], ["e mafai lava ona e faamanuiaina i latou e tusa ma au afioga ia na e fetalai mai ai.", "thou canst bless them according to thy words which thou hast said."]]},
  {num:17,words:[["Ma sa oo i le lona fitusefulu ma le ono o tausaga,", "And it came to pass that in the seventy and sixth year the Lord did turn away his anger from the people,"], ["sa liliu ese e le Alii lona toasa mai le nuu, ma ia faia ia pau ifo le timu i le eleele,", "and caused that rain should fall upon the earth,"], ["sa oo ina fua mai i ona fua i le tau e fua mai ai ona fua.", "insomuch that it did bring forth her fruit in the season of her fruit."], ["Ma sa oo ina fua mai ai e ia ona saito i le tau e fua mai ai ona saito.", "And it came to pass that it did bring forth her grain in the season of her grain."]]},
  {num:18,words:[["Ma faauta,", "And behold,"], ["sa olioli tagata ma vivii atu i le Atua,", "the people did rejoice and glorify God,"], ["ma sa tumu luga o le laueleele i le olioli;", "and the whole face of the land was filled with rejoicing;"], ["ma sa latou le toe saili e fasioti Nifae,", "and they did no more seek to destroy Nephi,"], ["ae ua latou ava ia te ia o se perofeta silisili,", "but they did esteem him as a  great prophet,"], ["ma o se tagata o le Atua,", "and a man of God,"], ["ua i ai le mana tele ma le pule na tuuina mai ia te ia mai le Atua.", "having great power and authority given unto him from God."]]},
  {num:19,words:[["Ma faauta,", "And behold,"], ["o Liae,", "Lehi,"], ["lona uso,", "his brother,"], ["sa le itiiti mai o ia i ona tua e faatatau i mea tau le amiotonu.", "was not a whit behind him as to things pertaining to righteousness."]]},
  {num:20,words:[["Ma sa faapea ona oo ina toe amata ona manuia o le nuu o Nifae i le laueleele,", "And thus it did come to pass that the people of Nephi began to prosper again in the land,"], ["ma amata ona latou toe atinae o latou nofoaga tuufua,", "and began to build up their waste places,"], ["ma amata ona faatoateleina ma salalau atu,", "and began to multiply and spread,"], ["seia oo ina latou faatumulia luga o le laueleele atoa,", "even until they did cover the whole face of the land,"], ["i le itu i matu ma le itu i saute,", "both on the north ward and on the southward,"], ["mai le sami i sisifo i le sami i sasae.", "from the sea west to the sea east."]]},
  {num:21,words:[["Ma sa oo ina iu le lona fitusefulu ma le ono o tausaga i le filemu. Ma sa amata le lona fitusefulu ma le fitu o tausaga i le filemu;", "And it came to pass that the seventy and sixth year did end in peace. And the seventy and seventh year began in peace;"], ["ma sa sosolo atu le ekalesia i luga o le laueleele atoa;", "and the church did spread throughout the face of all the land;"], ["ma o le vaega toatele o tagata,", "and the more part of the people,"], ["o sa Nifaē ma sa Lamanā,", "both the Nephites and the Lamanites,"], ["sa auai i le ekalesia;", "did belong to the church;"], ["ma sa latou maua le filemu tele i le laueleele;", "and they did have exceedingly great peace in the land;"], ["ma sa faapea ona iu o le fitusefulu ma le fitu o tausaga.", "and thus ended the seventy and seventh year."]]},
  {num:22,words:[["Ma sa latou maua foi le filemu i le lona fitusefulu ma le valu o tausaga,", "And also they had peace in the seventy and eighth year,"], ["vagana ai ni finauga itiiti e faatatau i matautu o le mataupu faavae lea na faataatia mai e perofeta.", "save it were a few contentions concerning the points of doctrine which had been laid down by the prophets."]]},
  {num:23,words:[["Ma i le tausaga e fitusefulu ma le iva sa amata ona i ai o finauga e tele. Peitai o Nifae ma Liae,", "And in the seventy and ninth year there began to be much strife. But it came to pass that Nephi and Lehi,"], ["ma le toatele o o laua uso o e sa malamalama e uiga i matautu moni o le mataupu faavae,", "and many of their brethren who knew concerning the true points of doctrine,"], ["ona sa latou maua faaaliga e tele i aso taitasi,", "having many revelations daily,"], ["sa oo ina latou talai atu i le nuu,", "therefore they did preach unto the people,"], ["ma o lea na oo ai ina latou faaumaina lo latou finau i lena lava tausaga.", "insomuch that they did put an end to their strife in that same year."]]},
  {num:24,words:[["Ma sa oo i le tausaga e valusefulu o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And it came to pass that in the eightieth year of the reign of the judges over the people of Nephi,"], ["sa i ai se aofai o tagata faatuiese mai le nuu o Nifae,", "there were a certain number of the dissenters from the people of Nephi,"], ["o e na o atu i sa Lamanā i ni tausaga ua mavae,", "who had some years before gone over unto the Lamanites,"], ["ma latou ave i o latou lava luga le igoa o sa Lamanā,", "and taken upon themselves the name of Lamanites,"], ["ma se aofai foi o e o ni o sa Lamanā moni i lo latou tupuga mai,", "and also a certain number who were real descendants of the Lamanites,"], ["na faaosoina i latou i le ita e i latou,", "being stirred up to anger by them,"], ["po o e na tagata faatuiese,", "or by those dissenters,"], ["o lea na latou amata ai se taua ma o latou uso.", "therefore they commenced a war with their brethren."]]},
  {num:25,words:[["Ma sa latou faia le fasioti tagata ma le vete;", "And they did commit murder and plunder;"], ["ma ona latou sosola lea i tua i mauga,", "and then they would retreat back into the mountains,"], ["ma i le vao ma nofoaga faalilolilo,", "and into the wilderness and secret places,"], ["ma faalalafi i latou lava ina ia le mafai ona maua i latou,", "hiding themselves that they could not be discovered,"], ["ma latou maua se faaopoopoga i lo latou aofai i aso taitasi,", "receiving daily an addition to their numbers,"], ["ona sa i ai tagata faatuiese na o atu ia te i latou.", "inasmuch as there were dissenters that went forth unto them."]]},
  {num:26,words:[["Ma sa faapea ona oo,", "And thus in time,"], ["ioe,", "yea,"], ["i se va lava o ni nai tausaga,", "even in the space of not many years,"], ["na avea o i latou ma se vaega faomea e sili ona toatele;", "they became an exceedingly great band of robbers;"], ["ma sa latou suesueina fuafuaga faalilolilo uma a Katianetona;", "and they did search out all the secret plans of Gadianton;"], ["ma sa faapea ona avea i latou ma faomea a Katianetona.", "and thus they became robbers of Gadianton."]]},
  {num:27,words:[["O lenei faauta,", "Now behold,"], ["sa faia e nei faomea se faatamaiga tele,", "these robbers did make great havoc,"], ["ioe,", "yea,"], ["se faafanoga tele lava i totonu o le nuu o Nifae,", "even great destruction among the people of Nephi,"], ["ma i totonu foi o tagata o sa Lamanā.", "and also among the people of the Lamanites."]]},
  {num:28,words:[["Ma sa oo ina tatau ona taofia lenei galuega o le faafanoga;", "And it came to pass that it was expedient that there should be a stop put to this work of destruction;"], ["o lea na latou aauina atu ai se autau o ni tagata malolosi i le vao ma luga o mauga e saili lenei vaega o faomea,", "therefore they sent an army of strong men into the wilderness and upon the mountains to search out this band of robbers,"], ["ma faaumatia i latou.", "and to destroy them."]]},
  {num:29,words:[["Peitai faauta,", "But behold,"], ["sa oo ina toe tutulia mai i latou i tua i o latou lava laueleele i lena lava tausaga. Ma sa faapea ona iu o le tausaga e valusefulu o le nofoaiga a faamasino i luga o le nuu o Nifae.", "it came to pass that in that same year they were driven back even into their own lands. And thus ended the eightieth year of the reign of the judges over the people of Nephi."]]},
  {num:30,words:[["Ma sa oo i le amataga o le tausaga e valusefulu ma le tasi sa latou toe o atu e faasaga i lenei vaega o faomea,", "And it came to pass in the commencement of the eighty and first year they did go forth again against this band of robbers,"], ["ma sa latou faaumatiaina le toatele;", "and did destroy many;"], ["ma sa asia foi i latou i se faaumatiaga tele.", "and they were also visited with much destruction."]]},
  {num:31,words:[["Ma sa toe faamalosia i latou e foi mai i fafo o le vao ma i fafo o mauga i o latou lava laueleele,", "And they were again obliged to return out of the wilderness and out of the mountains unto their own lands,"], ["ona o le toatele naua o le aofai o ia faomea o e na nonofo taatele i mauga ma le vao.", "because of the exceeding greatness of the numbers of those robbers who infested the mountains and the wilderness."]]},
  {num:32,words:[["Ma sa oo ina faapea ona iu o lenei tausaga. Ma sa faatoateleina pea le au faomea ma solo malolosi,", "And it came to pass that thus ended this year. And the robbers did still increase and wax strong,"], ["sa oo ina latou luia autau uma a sa Nifaē,", "insomuch that they did defy the whole armies of the Nephites,"], ["ma autau foi a sa Lamanā;", "and also of the Lamanites;"], ["ma sa latou faatupuina se matau tele ia oo mai i tagata i luga o le laueleele atoa.", "and they did cause great fear to come unto the people upon all the face of the land."]]},
  {num:33,words:[["Ioe,", "Yea,"], ["ona sa latou asia le tele o vaega o le laueleele,", "for they did visit many parts of the land,"], ["ma faia faaumatiaga tetele ia te i latou;", "and did do great destruction unto them;"], ["ioe,", "yea,"], ["sa latou fasiotia le toatele,", "did kill many,"], ["ma ave isi faatagataotaua i le vao,", "and did carry away others captive into the wilderness,"], ["ioe,", "yea,"], ["ma aemaise lava o o latou fafine ma a latou fanau.", "and more especially their women and their children."]]},
  {num:34,words:[["O lenei,", "Now this great evil,"], ["o lenei leaga tele, lea na oo mai i tagata ona o lo latou amioletonu,", "which came unto the people because of their iniquity,"], ["sa toe faaosoina ai i latou ia latou manatua le Alii lo latou Atua.", "did stir them up again in remembrance of the Lord their God."]]},
  {num:35,words:[["Ma sa faapea ona iu o le tausaga e valusefulu ma le tasi o le nofoaiga a faamasino.", "And thus ended the eighty and first year of the reign of the judges."]]},
  {num:36,words:[["Ma i le tausaga e valusefulu ma le lua sa toe amata ona galo ia te i latou le Alii lo latou Atua. Ma i le tausaga e valusefulu ma le tolu sa amata ona latou solo malolosi i le amioletonu. Ma i le tausaga e valusefulu ma le fa sa latou le faasaosaoina o latou ala.", "And in the eighty and second year they began again to forget the Lord their God. And in the eighty and third year they began to wax strong in iniquity. And in the eighty and fourth year they did not mend their ways."]]},
  {num:37,words:[["Ma sa oo i le tausaga e valusefulu ma le lima sa latou solo malolosi ma atili malolosi i lo latou faamaualuluga,", "And it came to pass in the eighty and fifth year they did wax stronger and stronger in their pride,"], ["ma i lo latou amioleaga;", "and in their wickedness;"], ["ma sa faapea ona latou toe matutua mo le faafanoga.", "and thus they were ripening again for destruction."]]},
  {num:38,words:[["Ma sa faapea ona iu o le tausaga e valusefulu ma le lima.", "And thus ended the eighty and fifth year."]]},
];
renderVerseSet(he_ch_11_Verses, 'he-ch11-verses');

var he_ch_12_Verses = [
  {num:1,words:[["Ma ua faapea ona mafai ona tatou vaai i le sese, ma le le maumaututu foi o loto o le fanauga a tagata;", "And thus we can behold how false,"], ["ioe,", "and also the unsteadiness of the hearts of the children of men;"], ["ua mafai ona tatou vaai e faamanuia ma faatamaoaiga e le Alii,", "yea,"], ["i lona agalelei silisili le tuaoia, i latou o e e tuu atu lo latou faalagolago ia te ia.", "we can see that the Lord in his great infinite goodness doth bless and prosper those who put their trust in him."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["ma e mafai ona tatou vaai o le taimi lava e faamanuiaina ai e ia ona tagata,", "and we may see at the very time when he doth prosper his people,"], ["ioe,", "yea,"], ["i le fua tele mai o o latou fanua,", "in the increase of their fields,"], ["a latou lafu ma a latou fagaga,", "their flocks and their herds,"], ["ma i auro,", "and in gold,"], ["ma ario,", "and in silver,"], ["ma mea taua uiga eseese uma o ituaiga taitasi ma teuga;", "and in all manner of precious  things of every kind and art;"], ["i le faasaoina o o latou ola,", "sparing their lives,"], ["ma laveai i latou i fafo mai lima o o latou fili;", "and delivering them out of the hands of their enemies;"], ["i le faamaluluina o loto o o latou fili ina ia latou le sii taua faasaga mai ia te i latou;", "softening the hearts of their enemies that they should not declare wars against them;"], ["ioe,", "yea,"], ["ma i se aotelega,", "and in fine,"], ["i le faia o mea uma mo le manuia ma le fiafia o ona tagata;", "doing all things for the welfare and happiness of his people;"], ["ioe,", "yea,"], ["o le taimi lena latou te faamaaa ai o latou loto,", "then is the time that they do harden their hearts,"], ["ma galo ai ia i latou le Alii lo latou Atua,", "and do forget the Lord their God,"], ["ma soli i lalo o o latou vae le Paia e Toatasi—ioe,", "and do trample under their feet the Holy One—yea,"], ["ma o le pogai ona o lo latou le popole,", "and this because of their ease,"], ["ma lo latou tamaoaiga tele.", "and their exceedingly great prosperity."]]},
  {num:3,words:[["Ma ua faapea ona tatou vaai ai vagana ai ua aoaiina e le Alii ona tagata i puapuaga e tele,", "And thus we see that except the Lord doth chasten his people with many afflictions,"], ["ioe,", "yea,"], ["vagana ai ua asiasi mai o ia ia te i latou i le oti ma le faafefe,", "except he doth visit them with death and with terror,"], ["ma le oge ma faamai uiga eseese uma,", "and with famine and with all manner of pestilence,"], ["latou te le manatua o ia.", "they will not remember him."]]},
  {num:4,words:[["E,", "O how foolish,"], ["ua ese lava le valelea,", "and how vain,"], ["ma ese lava le fiatagata,", "and how evil,"], ["ma ese lava le leaga,", "and devilish,"], ["ma le faaletiapolo, o le fanauga a tagata,", "and how quick to do iniquity,"], ["ma ese lava le vave ona latou faia o le amioletonu,", "and how slow to do good,"], ["ma gese lava ona latou faia o le lelei;", "are the children of men;"], ["ioe,", "yea,"], ["ua ese lava le vave ona faalogo i upu a le ua leaga,", "how quick to hearken unto the words of the evil one,"], ["ma tuu atu o latou loto i luga o mea le aoga o le lalolagi.", "and to set their hearts upon the vain things of the world!"]]},
  {num:5,words:[["Ioe,", "Yea,"], ["ua ese lava le vave ona faafefeteina i le faamaualuga ;", "how quick to be lifted up in pride;"], ["ioe,", "yea,"], ["ua ese lava le vave ona mitamitavale,", "how quick to boast,"], ["ma fai mea uiga eseese uma ua amioletonu;", "and do all manner of that which is iniquity;"], ["ma ua ese lava ona gese ia te i latou ona manatua o le Alii lo latou Atua,", "and how slow are they to remember the Lord their God,"], ["ma uai atu o latou taliga i ana fautuaga,", "and to give ear unto his counsels,"], ["ioe,", "yea,"], ["ua ese lava le gese ona latou savavali i ala o le poto.", "how slow to walk in wisdom’s paths!"]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ua latou le mananao i le Alii lo latou Atua,", "they do not desire that the Lord their God,"], ["o le na faia i latou,", "who hath created them,"], ["ia pule ma nofotupu i a i latou;", "should rule and reign over them;"], ["e ui lava i lona agalelei tele ma lona alofa mutimutivale ia te i latou,", "notwithstanding his great goodness and his mercy towards them,"], ["ua latou tuu faameanoa ana fautuaga,", "they do set at naught his counsels,"], ["ma ua latou le mananao e avea o ia ma o latou taitai.", "and they will not that he should be their guide."]]},
  {num:7,words:[["E,", "O how great is the nothingness of the children of men;"], ["ua matua tele lava le aunoa ma se mea o le fanauga a tagata; ioe,", "yea,"], ["e oo i le efuefu o le eleele ua latou maualalalo ifo ai.", "even they are less than the dust of the earth."]]},
  {num:8,words:[["Aua faauta,", "For behold,"], ["o le efuefu o le eleele e alu ese i i ma o,", "the dust of the earth moveth hither and thither,"], ["i le vavaeina i lea mea ma lea mea,", "to the dividing asunder,"], ["i le poloaiga a lo tatou Atua silisili ma tumau-faavavau.", "at the command of our great and everlasting God."]]},
  {num:9,words:[["Ioe, faauta,", "Yea,"], ["o lona siufofoga e gatete ma luluina ai maupuepue ma mauga.", "behold at his voice do the hills and the mountains tremble and quake."]]},
  {num:10,words:[["Ma o le mana o lona siufofoga e nutililiina ai i latou,", "And by the power of his voice they are broken up,"], ["ma faalaugatasi ai,", "and become smooth,"], ["ioe,", "yea,"], ["e pei lava o se vanu.", "even like unto a valley."]]},
  {num:11,words:[["Ioe,", "Yea,"], ["o le mana o lona siufofoga e luluina ai le lalolagi atoa;", "by the power of his voice doth the whole earth shake;"]]},
  {num:12,words:[["Ioe,", "Yea,"], ["o le mana o lona siufofoga e luluina ai le papa o faavae,", "by the power of his voice, do the foundations rock,"], ["e oo lava i le totonugalemu.", "even to the very center."]]},
  {num:13,words:[["Ioe,", "Yea,"], ["ma afai e fetalai atu o ia i le lalolagi—Alu ese—e alu ese lava.", "and if he say unto the earth—Move—it is moved."]]},
  {num:14,words:[["Ioe,", "Yea,"], ["afai e fetalai atu o ia i le lalolagi —Ia e toe alu i tua,", "if he say unto the earth—Thou shalt go back,"], ["ina ia faaumiumi ai le aso mo ni itula e tele—e faia lava.", "that it lengthen out the day for many hours—it is done;"]]},
  {num:15,words:[["Ma ua faapea lava,", "And thus,"], ["ona toe alu i tua o le lalolagi,", "according to his word the earth goeth back,"], ["e tusa ma lana fetalaiga,", "and it appeareth unto man that the sun standeth still;"], ["ma foliga ai i le tagata ua tu le gaoioi le la; ioe,", "yea,"], ["ma faauta,", "and behold,"], ["ua faapea lava;", "this is so;"], ["aua e moni o le lalolagi e alu ae le o le la.", "for surely it is the earth that moveth and not the sun."]]},
  {num:16,words:[["Ma faauta,", "And behold,"], ["afai e fetalai atu foi o ia i vai o le moana loloto— Ia matutu oe,", "also,"], ["e faia lava.", "if he say unto the waters of the great deep—Be thou dried up—it is done."]]},
  {num:17,words:[["Faauta,", "Behold,"], ["afai e fetalai atu o ia i lenei mauga—Ia sii ae oe i luga ma sau i luga ma pau i luga o lena aai,", "if he say unto this mountain—Be thou raised up, and come over and fall upon that city,"], ["ina ia tanumia ai—faauta e faia lava.", "that it be buried up—behold it is done."]]},
  {num:18,words:[["Ma faauta,", "And behold,"], ["afai e nana e se tagata se oa i le eleele,", "if a man hide up a treasure in the earth,"], ["ma o le a fetalai mai le Alii—Ia fetuuina lena oa,", "and the Lord shall say—Let it be accursed,"], ["ona o le amioletonu a le na ia natiaina—faauta,", "because of the iniquity of him who hath hid it up—behold,"], ["o le a fetuuina lava.", "it shall be accursed."]]},
  {num:19,words:[["Ma afai e fetalai mai le Alii—Ia fetuuina oe,", "And if the Lord shall say—Be thou accursed,"], ["ina ia le maua oe e se tagata mai i le taimi nei e oo i le faavavau—faauta,", "that no man shall find thee from this time henceforth and forever—behold,"], ["e leai se tagata na te mauaina lena oa mai lena taimi e oo i le faavavau.", "no man getteth it henceforth and forever."]]},
  {num:20,words:[["Ma faauta,", "And behold,"], ["afai e fetalai mai le Alii i se tagata—Ona o au amioletonu,", "if the Lord shall say unto a man—Because of thine iniquities,"], ["o le a fetuuina oe e faavavau—o le a faia lava.", "thou shalt be accursed forever—it shall be done."]]},
  {num:21,words:[["Ma afai e fetalai mai le Alii—Ona o au amioletonu o le a vavae ese ai oe mai ou luma—o le a ia faia ina ia faataunuuina lava.", "And if the Lord shall say—Because of thine iniquities thou shalt be cut off from my presence—he will cause that it shall be so."]]},
  {num:22,words:[["Ma oi talofa ia te ia o le o le a ia fetalai atu i ai lenei mea,", "And wo unto him to whom he shall say this,"], ["ona o le a oo atu ia te ia o le o le a ia faia le amioletonu,", "for it shall be unto him that will do iniquity,"], ["ma o le a le mafai ona faaolaina o ia;", "and he cannot be saved;"], ["o lea,", "therefore,"], ["ona o lenei pogai,", "for this cause,"], ["ina ia mafai ona faaolaina o tagata,", "that men might be saved,"], ["ua talai atu ai le salamo.", "hath repentance been declared."]]},
  {num:23,words:[["O lea,", "Therefore,"], ["amuia lava i latou o e o le a salamo ma faalogo i le siufofoga o le Alii lo latou Atua;", "blessed are they who will repent and hearken unto the voice of the Lord their God;"], ["ona o i latou ia o e o le a faaolaina .", "for these are they that shall be saved."]]},
  {num:24,words:[["Ma ia tuuina mai e le Atua,", "And may God grant,"], ["i lona atoatoa silisili,", "in his great fulness,"], ["ina ia mafai ona aumai o tagata i le salamo ma galuega lelei,", "that men might be brought unto repentance and good works,"], ["ina ia mafai ona toefuataiina ia i latou le alofa tunoa mo le alofa tunoa,", "that they might be restored unto grace for grace,"], ["e tusa ma a latou galuega.", "according to their works."]]},
  {num:25,words:[["Ma ou te manao ia faaolaina tagata uma.", "And I would that all men might be saved."], ["Peitai ua tatou faitau e faapea i le aso tele ma mulimuli,", "But we read that in the great and last day there are some who shall be cast out,"], ["e i ai ni isi o le a tutulia i fafo, ioe,", "yea,"], ["o e o le a tutuli ese mai luma o le Alii;", "who shall be cast off from the presence of the Lord;"]]},
  {num:26,words:[["Ioe,", "Yea,"], ["o e o le a tuu i se tulaga o le pagatia e le gata,", "who shall be consigned to a state of endless misery,"], ["e faataunuu ai upu ua fai ai: O i latou o e na faia le lelei,", "fulfilling the words which say:"], ["o le a latou maua le ola faavavau;", "They that have done good shall have everlasting life;"], ["ma o i latou o e na faia le leaga o le a latou maua le faasalaga tumau-faavavau.", "and they that have done evil shall have everlasting damnation."], ["Ma ua faapea lava.", "And thus it is."], ["Amene.", "Amen."]]},
];
renderVerseSet(he_ch_12_Verses, 'he-ch12-verses');

var he_ch_13_Verses = [
  {num:1,words:[["Ma lenei sa oo i le tausaga e valusefulu ma le ono,", "And now it came to pass in the eighty and sixth year,"], ["sa tumau pea sa Nifaē i le amioleaga,", "the Nephites did still remain in wicked– ness,"], ["ioe, i le amioleaga tele,", "yea in great wickedness,"], ["ao sa Lamanā sa latou tausisi aiai e tausi poloaiga a le Atua,", "while the Lamanites did observe strictly to keep the commandments of God,"], ["e tusa ma le tulafono a Mose.", "according to the law of Moses."]]},
  {num:2,words:[["Ma sa oo i le tausaga lenei,", "And it came to pass that in this year there was one Samuel,"], ["sa i ai se tasi e igoa ia Samuelu,", "a Lamanite,"], ["o se sa Lamanā,", "came into the land of Zarahemla,"], ["na sau i le laueleele o Sara'emila,", "and began to preach unto the people. And it came to pass that he did preach,"], ["ma amata ona talai atu i tagata. Ma sa oo ina talai atu e ia,", "many days,"], ["i aso e tele le salamo i le nuu,", "repentance unto the people,"], ["ma sa latou tuli ese o ia i fafo,", "and they did cast him out,"], ["ma sa fai o le a foi atu o ia i lona lava laueleele.", "and he was about to return to his own land."]]},
  {num:3,words:[["Ae faauta,", "But behold,"], ["sa oo mai le siufofoga o le Alii ia te ia,", "the voice of the Lord came unto him,"], ["e tatau ona ia toe foi,", "that he should return again,"], ["ma vavalo atu i le nuu i soo se mea e oo mai i lona loto .", "and prophesy  unto the people whatsoever things should come into his heart."]]},
  {num:4,words:[["Ma sa oo ina latou le mananao e tuu atu ia ulu mai o ia i le aai;", "And it came to pass that they would not suffer that he should enter into the city;"], ["o lea na alu atu ai o ia ma ua alu ae i luga o le pa o le aai,", "therefore he went and got upon the wall thereof,"], ["ma ua faaloaloa atu lona lima, ma ua alaga atu i se leo tele,", "and stretched forth his hand and cried with a loud voice,"], ["ma ua vavalo atu i le nuu i soo se mea lava na tuu mai e le Alii i lona loto.", "and prophesied unto the people whatsoever things the Lord put into his heart."]]},
  {num:5,words:[["Ma sa ia fai atu ia te i latou:", "And he said unto them:"], ["Faauta,", "Behold,"], ["o au o Samuelu,", "I,"], ["o se sa Lamanā,", "Samuel,"], ["ou te tautala atu i afioga a le Alii ua ia tuuina mai i lou loto;", "a Lamanite,"], ["ma faauta,", "do speak the words of the Lord which he doth put into my heart;"], ["ua ia tuuina mai i lou loto e fai atu i lenei nuu ua tautau ifo le pelu o le faamasinoga i luga o lenei nuu;", "and behold he hath put it into my heart to say unto this people that the sword of justice hangeth over this people;"], ["ma e le mavae atu tausaga e fa selau ae pau ifo le pelu o le faamasinoga i luga o lenei nuu.", "and four hundred years pass not away save the sword of justice falleth upon this people."]]},
  {num:6,words:[["Ioe,", "Yea,"], ["ua faatalitali mai faafanoga mamafa i lenei nuu,", "heavy destruction awaiteth this people,"], ["ma o le a mautinoa ona oo mai i lenei nuu,", "and it surely cometh unto this people,"], ["ma o le a leai se mea e mafai ona faaolaina ai lenei nuu vagana ai le salamo ma le faatuatua i le Alii o Iesu Keriso,", "and nothing can save this people save it be repentance and faith on the Lord Jesus Christ,"], ["o le ua mautinoa o le a afio mai i le lalolagi,", "who surely shall come into the world,"], ["ma o le a mafatia i mea e tele ma o le a fasia mo ona tagata.", "and shall suffer many things and shall be slain for his people."]]},
  {num:7,words:[["Ma faauta,", "And behold,"], ["o se agelu a le Alii na ia ta'u mai nei mea ia te a'u,", "an angel of the Lord hath declared it unto me,"], ["ma sa ia aumai tala fiafia i lo'u agaga.", "and he did bring glad tidings to my soul."], ["Ma faauta,", "And behold,"], ["sa auina mai a'u e ta'u atu foi ia mea ia te outou,", "I was sent unto you to declare it unto you also,"], ["ina ia outou maua tala fiafia; ae faauta,", "that ye might have glad tidings;"], ["ua outou le talia a'u.", "but behold ye would not receive me."]]},
  {num:8,words:[["O lea,", "Therefore,"], ["ua faapea ona fetalai mai o le Alii:", "thus saith the Lord:"], ["Ona o le maaa o loto o tagata sa Nifaē,", "Because of the hardness of the hearts of the people of the Nephites,"], ["vagana ai ua latou salamo, o le a ou aveese lau upu mai ia te i latou,", "except they repent I will take away my word from them,"], ["ma o le ou aveese lou Agaga mai ia te i latou,", "and I will withdraw my Spirit from them,"], ["ma o le a ou le toe onosaia i latou,", "and I will suffer them no longer,"], ["ma o le a ou liliu mai loto o o latou uso e faasaga ia te i latou.", "and I will turn the hearts of their brethren against them."]]},
  {num:9,words:[["Ma o le a le mavae atu le fa selau o tausaga ae o le a ou faia ia taiaina i latou;", "And four hundred years shall not pass away before I will cause that they shall be smitten;"], ["ioe,", "yea,"], ["o le a ou asiasi atu ia te i latou i le pelu ma le oge ma le faamai.", "I will visit them with the sword and with famine and with pestilence."]]},
  {num:10,words:[["Ioe,", "Yea,"], ["o le a ou asiasi atu ia te i latou i lou ita tele,", "I will visit them in my fierce anger,"], ["ma o le a i ai i latou o le tupulaga lona fa , o o outou fili,", "and there shall be those of the fourth generation who shall live,"], ["o le a ola,", "of your enemies,"], ["e vaai i lo outou faaumatiaga atoa;", "to behold your utter destruction;"], ["ma ua mautinoa o le a oo mai lenei mea, vagana ai ua outou salamo,", "and this shall surely come except ye repent,"], ["ua fetalai mai ai le Alii;", "saith the Lord;"], ["ma o i latou o le tupulaga lona fa o le a aumaia lo outou faaumatiaga.", "and those of the fourth generation shall visit your destruction."]]},
  {num:11,words:[["Ae afai tou te salamo ma foi mai i le Alii lo outou Atua,", "But if ye will repent and return unto the Lord your God I will turn away mine anger,"], ["o le a ou liliu ese lou ita,", "saith the Lord;"], ["ua fetalai mai ai le Alii; ioe,", "yea,"], ["ua faapea ona fetalai mai o le Alii,", "thus saith the Lord,"], ["amuia lava i latou o e e salamo ma liliu mai ia te au,", "blessed are they who will repent and turn unto me,"], ["ae talofa ia te ia o le e le salamo.", "but wo unto him that repenteth not."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["oi talofa i lenei aai tele o Sara'emila;", "wo unto this great city of Zarahemla;"], ["ona faauta,", "for behold,"], ["ua faasaoina ona o i latou o e ua amiotonu;", "it is because of those who are righteous that it is saved;"], ["ioe,", "yea,"], ["oi talofa i lenei aai tele,", "wo unto this great city,"], ["ua fetalai mai ai le Alii,", "for I perceive, saith the Lord,"], ["ona ua ou iloa o i ai le toatele,", "that there are many,"], ["ioe,", "yea,"], ["le vaega toatele atu o lenei aai tele,", "even the more part of this great city,"], ["o le a latou faamaaa o latou loto faasaga mai ia te au,", "that will harden their hearts against me,"], ["ua fetalai mai ai le Alii.", "saith the Lord."]]},
  {num:13,words:[["Ae amuia lava i latou o e o le a salamo,", "But blessed are they who will repent,"], ["ona o i latou ia o le a ou faasaoina. Ae faauta,", "for them will I spare. But behold,"], ["a na leai e amiotonu o loo i ai i totonu o lenei aai tele,", "if it were not for the righteous who are in this great city,"], ["faauta,", "behold,"], ["po ua ou faia ia sau le afi mai le lagi ma faaumatiaina o ia.", "I would cause that fire should come down out of heaven and destroy it."]]},
  {num:14,words:[["Ae faauta,", "But behold,"], ["ua faasaoina ona o e ua amiotonu. Peitai faauta,", "it is for the righteous’ sake that it is spared. But behold,"], ["e oo mai le taimi,", "the time cometh,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["pe a outou tutuli ese e ua amiotonu mai totonu ia te outou,", "that when ye shall cast out the righteous from among you,"], ["o le taimi lena o le a outou matua ai mo le faafanoga;", "then shall ye be ripe for destruction;"], ["ioe,", "yea,"], ["oi talofa i lenei aai tele,", "wo be unto this great city,"], ["ona o le amioleaga ma mea inosia o i ai ia te ia.", "because of the wickedness and abominations which are in her."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["ma oi talofa i le aai o Kitiona,", "and wo be unto the city of Gideon,"], ["ona o le amioleaga ma mea inosia o i ai ia te ia.", "for the wickedness and abominations which are in her."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["ma oi talofa i aai uma o loo i ai i le laueleele faataamilo,", "and wo be unto all the cities which are in the land round about,"], ["ia o loo umia e sa Nifaē,", "which are possessed by the Nephites,"], ["ona o le amioleaga ma mea inosia o i ai ia te i latou.", "because of the wickedness and abominations which are in them."]]},
  {num:17,words:[["Ma faauta,", "And behold,"], ["o le a oo mai se fetuu i luga o le laueleele,", "a curse shall come upon the land,"], ["ua fetalai mai ai le Alii o Au,", "saith the Lord of Hosts,"], ["ona o tagata o i ai i luga o le laueleele,", "because of the people’s sake who are upon the land,"], ["ioe,", "yea,"], ["ona o lo latou amioleaga ma a latou mea inosia.", "because of their wickedness and their abominations."]]},
  {num:18,words:[["Ma o le a oo mai,", "And it shall come to pass,"], ["ua fetalai mai ai le Alii o Au,", "saith the Lord of Hosts,"], ["ioe,", "yea,"], ["lo tatou Atua silisili ma faamaoni,", "our great and true God,"], ["soo se tasi na te natiaina oa i le eleele e le toe mauaina e ia,", "that whoso shall hide up treasures in the earth shall find them again no more,"], ["ona o le fetuu tele o le laueleele,", "because of the great curse of the land,"], ["vagana ai o ia o se tagata amiotonu ma o le a ia natiaina mo le Alii.", "save he be a righteous man and shall hide it up unto the Lord."]]},
  {num:19,words:[["Ona ou te loto,", "For I will,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["ia latou natiaina a latou oa mo au;", "that they shall hide up their treasures unto me;"], ["ma e fetuuina lava i latou o e e le natiaina a latou oa mo au;", "and cursed be they who hide not up their treasures unto me;"], ["ona e leai ni isi e natiaina a latou oa mo au, vagana ai i latou o e ua amiotonu;", "for none hideth up their treasures unto me save it be the righteous;"], ["ma o le na te le natiaina ana oa mo au,", "and he that hideth not up his treasures unto me,"], ["e fetuuina lava o ia,", "cursed is he,"], ["ma le oa foi,", "and also the treasure,"], ["ma o le a leai se tasi na te toe mauaina ona o le fetuu o le laueleele.", "and none shall redeem it because of the curse of the land."]]},
  {num:20,words:[["Ma o le a oo mai le aso o le a latou natia ai a latou oa,", "And the day shall come that they shall hide up their treasures,"], ["auā ua tuuina atu e i latou o latou loto i oa;", "because they have set their hearts upon riches;"], ["ma ona ua latou tuuina atu o latou loto ia latou oa,", "and because they have set their hearts upon their riches,"], ["ma o le a latou natia ai a latou oa pe a latou sosola i luma o o latou fili;", "and will hide up their treasures when they shall flee before their enemies;"], ["ona o le a latou le natia ai ia oa mo au,", "because they will not hide them up unto me,"], ["e fetuuina i latou atoa ma a latou oa;", "cursed be they and also their treasures;"], ["ma i lena aso o le a taia ai i latou,", "and in that day shall they be smitten,"], ["ua fetalai mai ai le Alii.", "saith the Lord."]]},
  {num:21,words:[["Faauta mai ia outou,", "Behold ye,"], ["o tagata o lenei aai tele,", "the people of this great city,"], ["ma faalogo mai i au upu;", "and hearken unto my words;"], ["ioe,", "yea,"], ["faalogo mai i upu ia ua fetalai mai ai le Alii;", "hearken unto the words which the Lord saith;"], ["aua faauta,", "for behold,"], ["ua fetalai mai o ia ua fetuuina outou ona o a outou oa,", "he saith that ye are cursed because of your riches,"], ["ma ua fetuuina foi a outou oa ona ua outou tuu atu o outou loto i luga o i latou,", "and also are your riches cursed because ye have set your hearts upon them,"], ["ma ua outou le faalogo i afioga a le na ia tuuina mai ia i latou ia te outou.", "and have not hearkened unto the words of him who gave them unto you."]]},
  {num:22,words:[["Ua outou le manatua le Alii lo outou Atua i mea ua ia faamanuiaina ai outou,", "Ye do not remember the Lord your God in the things with which he hath blessed you,"], ["ae ua outou manatua pea a outou oa ,", "but ye do always remember your riches,"], ["a ua le faafetai atu i le Alii lo outou Atua mo i latou;", "not to thank the Lord your God for them;"], ["ioe, ua le tosina atu o outou loto i le Alii,", "yea,"], ["ae ua faafefeteina i latou i le faamaualuga tele,", "your hearts are not drawn out unto the Lord,"], ["e oo i le mitamitavale,", "but they do swell with great pride,"], ["ma oo i le faafefeteina tele,", "unto boasting,"], ["mataua ,", "and unto great  swelling,"], ["finauga,", "envyings,"], ["femisaa'i, felotoai,", "strifes,"], ["sauaga,", "malice,"], ["ma fasiotiga tagata,", "persecutions and murders,"], ["ma amioletonu uiga eseese uma.", "and all manner of iniquities."]]},
  {num:23,words:[["O le pogai lenei na faia ai e le Alii le Atua ia oo mai se fetuu i luga o le laueleele,", "For this cause hath the Lord God caused that a curse should come upon the land,"], ["ma luga foi o a outou oa,", "and also upon your riches,"], ["ma ua pogai lenei mea ona o a outou amioletonu.", "and this because of your iniquities."]]},
  {num:24,words:[["Ioe,", "Yea,"], ["oi talofa i lenei nuu,", "wo unto this people,"], ["ona o lenei taimi ua oo mai,", "because of this time which has arrived,"], ["ua outou tutuli ese ai perofeta i fafo,", "that ye do cast out the prophets,"], ["ma faatauemu ia te i latou,", "and do mock them,"], ["ma fetogi maa ia te i latou,", "and cast stones at them,"], ["ma fasioti i latou,", "and do slay them,"], ["ma fai amioletonu uiga eseese uma ia te i latou,", "and do all manner of iniquity unto them,"], ["e pei lava ona faia e i latou anamua.", "even as they did of old time."]]},
  {num:25,words:[["Ma o lenei pe a outou tautatala,", "And now when ye talk,"], ["ua outou fai mai:", "ye say:"], ["A na i ai o tatou aso i aso o o tatou tamā anamua,", "If our days had been in the days of our fathers of old,"], ["po ua tatou le fasiotia perofeta;", "we would not have slain the prophets;"], ["po ua tatou le fetogia i latou,", "we would not have stoned them,"], ["ma tutuli ese i latou i fafo.", "and cast them out."]]},
  {num:26,words:[["Faauta ua sili lo outou leaga nai lo i latou;", "Behold ye are worse than they;"], ["ona e pei ona soifua le Alii,", "for as the Lord liveth,"], ["afai e sau se perofeta ia te outou ma talai atu ia te outou le afioga a le Alii,", "if a prophet come among you and declareth unto you the word of the Lord,"], ["ia ua molimau e uiga ia outou agasala ma amioletonu,", "which testifieth of your sins and iniquities,"], ["ua outou feita ia te ia,", "ye are angry with him,"], ["ma tuli ese o ia i fafo ma saili ala eseese uma e faaumatia ai o ia;", "and cast him out and seek all manner of ways to destroy him;"], ["ioe,", "yea,"], ["tou te fai mai o ia o se perofeta pepelo,", "you will say that he is a false prophet,"], ["ma o ia o se tagata agasala,", "and that he is a sinner,"], ["ma ua mai le tiapolo,", "and of the devil,"], ["ona ua molimau atu o ia ua leaga a outou galuega.", "because he testifieth that your deeds are evil."]]},
  {num:27,words:[["Ae faauta,", "But behold,"], ["afai e sau se tagata i totonu ia te outou ma fai atu:", "if a man shall come among you and shall say:"], ["Fai le mea lenei,", "Do this,"], ["ma ua leai se amioletonu o i ai;", "and there is no iniquity;"], ["fai le mea lena ma o le a outou le mafatia ai;", "do that and ye shall not suffer;"], ["ioe,", "yea,"], ["o le a fai atu o ia:", "he will say:"], ["Savavali e tusa ma le faamaualuluga o o outou lava loto;", "Walk after the pride of your own hearts;"], ["ioe,", "yea,"], ["savavali e tusa ma le faamaualuluga o o outou lava mata,", "walk after the pride of your eyes,"], ["ma fai soo se mea e mananao i ai o outou loto—ma afai e sau se tagata i totonu ia te outou ma fai atu nei mea,", "and do whatsoever your heart desireth—and if a man shall come among you and say this,"], ["tou te talia o ia,", "ye will receive him,"], ["ma fai mai o ia o se perofeta .", "and say that he is a prophet."]]},
  {num:28,words:[["Ioe,", "Yea,"], ["tou te sii o ia i luga,", "ye will lift him up,"], ["ma tou avatu ia te ia ni isi o a outou mea;", "and ye will give unto him of your substance;"], ["tou te avatu ia te ia mai ia outou auro,", "ye will give unto him of your gold,"], ["ma a outou ario,", "and of your silver,"], ["ma tou faaofuina o ia i ofu taugata;", "and ye will clothe him with costly apparel;"], ["ma ona e tautala mai o ia ia te outou i upu faaviivii,", "and because he speaketh flattering words unto you,"], ["ma fai atu o ia ua lelei mea uma,", "and he saith that all is well,"], ["ona outou le saili masei ai lea ia te ia.", "then ye will not find fault with him."]]},
  {num:29,words:[["E,", "O ye wicked and ye perverse generation;"], ["outou e le tupulaga amioleaga ma faapiopio;", "ye hardened and ye stiffnecked people,"], ["outou e tagata maaa ma ua maaa, o le a ea le umi tou te manatu o le a onosaia ai outou e le Alii? Ioe,", "how long will ye suppose that the Lord will suffer you? Yea,"], ["o le a ea le umi tou te tuu ai outou lava e taitaiina e taitai valelea ma tauaso ? Ioe,", "how long will ye suffer yourselves to be led by foolish and blind guides? Yea,"], ["o le a ea le umi tou te filifili ai le pouliuli nai lo le malamalama ?", "how long will ye choose darkness rather than light?"]]},
  {num:30,words:[["Ioe,", "Yea,"], ["faauta,", "behold,"], ["ua uma nei ona faamumu ae o le toasa o le Alii e faasaga ia te outou;", "the anger of the Lord is already kindled against you;"], ["faauta,", "behold,"], ["ua ia fetuuina le laueleele ona o lo outou amioletonu.", "he hath cursed the land because of your iniquity."]]},
  {num:31,words:[["Ma faauta,", "And behold,"], ["e oo mai le taimi o le a ia fetuu ai a outou oa,", "the time cometh that he curseth your riches,"], ["ina ia latou maseesee ,", "that they become slippery,"], ["ia le mafai ona outou umia i latou;", "that ye cannot hold them;"], ["ma o le a le mafai ona outou taofia i latou i aso o lo outou mativa.", "and in the days of your poverty ye cannot retain them."]]},
  {num:32,words:[["Ma i aso o lo outou mativa o le a outou tagi atu ai i le Alii;", "And in the days of your poverty ye shall cry unto the Lord;"], ["ma o le a le aoga la outou tagi atu,", "and in vain shall ye cry,"], ["ona ua oo mai i o outou luga lo outou faatafunaga,", "for your desolation is already come upon you,"], ["ma ua mautinoa lo outou faafanoga;", "and your destruction is made sure;"], ["ma ona outou fetagisi ma uio ai lea i lena aso,", "and then shall ye weep and howl in that day,"], ["ua fetalai mai ai le Alii o Au. Ma ona outou laue lea,", "saith the Lord of Hosts. And then shall ye lament,"], ["ma fai mai:", "and say:"]]},
  {num:33,words:[["E,", "O that I had repented,"], ["pe a na ou salamo,", "and had not killed the prophets,"], ["ma ou le fasiotia perofeta, ma fetogi i latou,", "and stoned them,"], ["ma tutuli ese i latou i fafo.", "and cast them out."], ["Ioe,", "Yea,"], ["i lena aso o le a outou fai mai ai:", "in that day ye shall say:"], ["E pe a na tatou manatuaina le Alii lo tatou Atua i le aso na ia tuuina mai ai ia te i tatou a tatou oa,", "O that we had remembered the Lord our God in the day that he gave us our riches,"], ["semanu ua le maseesee i latou ua toesea atu ai mai ia te i tatou;", "and then they would not have become slippery that we should lose them;"], ["aua faauta,", "for behold,"], ["ua o ese atu a tatou oa mai ia te i tatou.", "our riches are gone from us."]]},
  {num:34,words:[["Faauta,", "Behold,"], ["tatou te tuu se meafaigaluega iinei ae malama ae le taeao ua leai;", "we lay a tool here and on the morrow it is gone;"], ["ma faauta,", "and behold,"], ["ua aveesea a tatou pelu mai ia te i tatou i le aso na tatou sailia ai i latou mo le taua.", "our swords are taken from us in the day we have sought them for battle."]]},
  {num:35,words:[["Ioe,", "Yea,"], ["sa tatou natiaina a tatou oa ma ua see ese atu mai ia te i tatou,", "we have hid up our treasures and they have slipped away from us,"], ["ona o le fetuu o le laueleele.", "because of the curse of the land."]]},
  {num:36,words:[["E, pe a na tatou salamo i le aso na oo mai ai le afioga a le Alii ia te i tatou;", "O that we had repented in the day that the word of the Lord came unto us;"], ["aua faauta,", "for behold the land is cursed,"], ["ua fetuuina le laueleele,", "and all things are become slippery,"], ["ma ua maseesee mea uma, ma ua le mafai ona tatou taofia.", "and we cannot hold them."]]},
  {num:37,words:[["Faauta,", "Behold,"], ["ua siomia i tatou e temoni,", "we are surrounded by demons,"], ["ioe,", "yea,"], ["ua lio i tatou e agelu a le ua saili e faaumatia o tatou agaga. Faauta,", "we are encircled about by the angels of him who hath sought to destroy our souls. Behold,"], ["ua tetele lava a tatou amioletonu. Le Alii e,", "our iniquities are great. O Lord,"], ["pe le mafai ea ona e liliu ese lou toasa mai ia te i matou? Ma o la outou gagana lea i na aso.", "canst thou not turn away thine anger from us? And this shall be your language in those days."]]},
  {num:38,words:[["Ae faauta,", "But behold,"], ["ua mavae aso o lo outou vaavaaiga;", "your days of probation are past;"], ["ua outou faatuatuanai le aso o lo outou olataga seia oo ina matua tuai lava e tumau-faavavau,", "ye have procrastinated the day of your salvation until it is everlastingly too late,"], ["ma ua mautinoa lo outou faafanoga;", "and your destruction is made sure;"], ["ioe,", "yea,"], ["ona sa outou saili i aso uma o o outou olaga mo le mea e le mafai ona outou maua;", "for ye have sought all the days of your lives for that which ye could not obtain;"], ["ma sa outou saili mo le fiafia i le fai o le amioletonu,", "and ye have sought for happiness in doing iniquity,"], ["o se mea lea ua le tusa ai ma le natura o lena amiotonu lea o loo i lo tatou Ao silisili ma Faavavau.", "which thing is contrary to the nature of that righteousness which is in our great and Eternal Head."]]},
  {num:39,words:[["E,", "O ye people of the land,"], ["outou e tagata o le laueleele, pe a na outou faalogo mai i au upu! Ma ou te tatalo ina ia liliu ese le toasa o le Alii mai ia te outou,", "that ye would hear my words! And I pray that the anger of the Lord be turned away from you,"], ["ma ina ia outou salamo ma faaolaina ai.", "and that ye would repent and be saved."]]},
];
renderVerseSet(he_ch_13_Verses, 'he-ch13-verses');

var he_ch_14_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina valoia e Samuelu ,", "And now it came to pass that Samuel,"], ["le sa Lamanā,", "the Lamanite,"], ["i ni isi mea tetele sili atu e le mafai ona tusia.", "did prophesy a great many more things which cannot be written."]]},
  {num:2,words:[["Ma faauta sa fai atu o ia ia te i latou:", "And behold,"], ["Faauta,", "he said unto them:"], ["ou te tuu atu ia te outou se faailoga;", "Behold, I give unto you a sign;"], ["ona toe lima ni tausaga,", "for five years more cometh,"], ["ma faauta,", "and behold,"], ["ona afio mai ai lea le Alo o le Atua e togiola i latou uma o e e faatuatua i lona suafa.", "then cometh the Son of God to redeem all those who shall believe on his name."]]},
  {num:3,words:[["Ma faauta,", "And behold,"], ["o le mea lenei ou te tuu atu ia te outou mo se faailoga i le taimi o lona afio mai;", "this will I give unto you for a sign at the time of his coming;"], ["aua faauta,", "for behold,"], ["o le a i ai malamalama tetele i le lagi,", "there shall be great lights in heaven,"], ["e oo ina leai se pogisa i le po ae lei afio mai o ia,", "insomuch that in the night before he cometh there shall be no darkness,"], ["e oo ina foliga mai i le tagata e peiseai o le ao.", "insomuch that it shall appear unto man as if it was day."]]},
  {num:4,words:[["O lea,", "Therefore,"], ["o le a i ai se ao e tasi ma se po ma se ao,", "there shall be one day and a night and a day,"], ["e peiseai ua tasi le ao ma ua leai se po;", "as if it were one day and there were no night;"], ["ma o lenei mea o le a avea mo se faailoga ia te outou;", "and this shall be unto you for a sign;"], ["ona o le a outou iloa le oso ae o le la ma lona goto ifo foi;", "for ye shall know of the rising of the sun and also of its setting;"], ["o lea o le a latou iloa mautinoa ai o le a i ai ni ao e lua ma se po;", "therefore they shall know of a surety that there shall be two days and a night;"], ["e ui i lea o le a le pogisa le po;", "nevertheless the night shall not be darkened;"], ["ma o le po lea ae lei soifua mai o ia.", "and it shall be the night before he is born."]]},
  {num:5,words:[["Ma faauta,", "And behold,"], ["o le a i ai se fetu fou e oso mai,", "there shall a new star arise,"], ["o se ituaiga o fetu tou te lei vaai lava i ai;", "such an one as ye never have beheld;"], ["ma o lea foi o le a avea mo se faailoga ia te outou.", "and this also shall be a sign unto you."]]},
  {num:6,words:[["Ma faauta ua le ona pau lea,", "And behold this is not all,"], ["o le a tele faailoga ma mea ofoofogia o le a i ai i le lagi.", "there shall be many signs and wonders in heaven."]]},
  {num:7,words:[["Ma o le a oo mai o le a outou meia uma,", "And it shall come to pass that ye shall all be amazed,"], ["ma taufaiofo,", "and wonder,"], ["e oo ina outou pauu i le eleele.", "insomuch that ye shall fall to the earth."]]},
  {num:8,words:[["Ma o le a oo mai, o soo se tasi e talitonu i le Alo o le Atua,", "And it shall come to pass that whosoever shall believe on the Son of God,"], ["o ia lava lea o le a mauaina le ola faavavau.", "the same shall have everlasting life."]]},
  {num:9,words:[["Ma faauta,", "And behold,"], ["ua faapea ona poloaiina o au e le Alii,", "thus hath the Lord commanded me,"], ["e ala i lana agelu,", "by his angel,"], ["ia ou sau ma tau atu lenei mea ia te outou;", "that I should come and tell this thing unto you;"], ["ioe,", "yea,"], ["ua ia poloaia au e tatau ona ou vavalo atu nei mea ia te outou;", "he hath commanded that I should prophesy these things unto you;"], ["ioe,", "yea,"], ["na ia fetalai mai ia te au:", "he hath said unto me:"], ["Alaga atu i lenei nuu,", "Cry unto this people,"], ["ia salamo ma saunia le ala o le Alii.", "repent and prepare the way of the Lord."]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["ona o au o se sa Lamanā,", "because I am a Lamanite,"], ["ma ua ou tautala atu ia te outou upu ia na poloaiina ai au e le Alii,", "and have spoken unto you the words which the Lord hath commanded me,"], ["ma talu ai ona ua faigata e faasaga ia te outou,", "and because it was hard against you,"], ["ua outou feita mai ia te au ma outou saili e faaumatia au,", "ye are angry with me and do seek to destroy me,"], ["ma ua outou tuli ese au i fafo mai totonu ia te outou.", "and have cast me out from among you."]]},
  {num:11,words:[["Ma o le a outou faalogo i au upu,", "And ye shall hear my words,"], ["ona,", "for,"], ["o le faamoemoe lenei ua ou sau ai i luga o pa o lenei aai,", "for this intent have I come up upon the walls of this city,"], ["ina ia mafai ona outou faalogo ma iloa faamasinoga a le Atua ia ua faatalitali mai ia te outou ona o a outou amioletonu,", "that ye might hear and know of the judgments of God which do await you because of your iniquities,"], ["ma ina ia outou iloa foi tuutuuga o le salamo.", "and also that ye might know the conditions of repentance;"]]},
  {num:12,words:[["Ma ina ia mafai foi ona outou iloa e uiga i le afio mai o Iesu Keriso,", "And also that ye might know of the coming of Jesus Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["o le Tamā o le lagi ma le lalolagi,", "the Father of heaven and of earth,"], ["o le Foafoa o mea uma mai le amataga;", "the Creator of all things from the beginning;"], ["ma ina ia mafai ona outou iloa e uiga i faailoga o lona afio mai,", "and that ye might know of the signs of his coming,"], ["i le faamoemoe ia mafai ona outou talitonu ai i lona suafa.", "to the intent that ye might believe on his name."]]},
  {num:13,words:[["Ma afai tou te talitonu i lona suafa o le a outou salamo ia outou agasala uma,", "And if ye believe on his name ye will repent of all your sins,"], ["ina ia mafai ai ona outou maua o se faamagaloga o a outou agasala e ala i ana galuega .", "that thereby ye may have a remission of them through his merits."]]},
  {num:14,words:[["Ma faauta,", "And behold,"], ["ou te toe avatu se tasi faailoga ia te outou,", "again,"], ["ioe,", "another sign I give unto you, yea,"], ["o se faailoga o lona maliu.", "a sign of his death."]]},
  {num:15,words:[["Aua faauta,", "For behold,"], ["e tatau moni lava ona maliu o ia,", "he surely must die that salvation may come;"], ["ina ia mafai ona oo mai o le olataga ; ioe,", "yea,"], ["e ao ia te ia ma e tatau ia te ia ona maliu o ia,", "it behooveth him and becometh expedient that he dieth,"], ["e aumai ai le toetutu mai o e ua oti,", "to bring to pass the resurrection of the dead,"], ["ina ia mafai ai ona aumai o tagata i luma o le Alii.", "that thereby men may be brought into the presence of the Lord."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["faauta,", "behold,"], ["o lenei maliu e aumai ai le toetutu mai,", "this death bringeth to pass the resurrection,"], ["ma togiola ai tagata uma mai le oti muamua—le oti faaleagaga lena;", "and redeemeth all mankind from the first death—that spiritual death;"], ["ona ua vavae ese tagata uma, i le pau o Atamu,", "for all mankind,"], ["mai luma o le Alii,", "by the fall of Adam being cut off from the presence of the Lord,"], ["ma ua faapea ua feoti ,", "are considered as dead,"], ["e faatatau i mea faaletino ma mea faaleagaga.", "both as to things temporal and to things spiritual."]]},
  {num:17,words:[["Ae faauta,", "But behold,"], ["o le toetu mai o Keriso ua togiolaina ai tagata,", "the resurrection of Christ redeemeth mankind,"], ["ioe,", "yea,"], ["o tagata uma,", "even all mankind,"], ["ma toe aumai ai i latou i luma o le Alii.", "and bringeth them back into the presence of the Lord."]]},
  {num:18,words:[["Ioe,", "Yea,"], ["ma ua faataunuu ai le tuutuuga o le salamo,", "and it bringeth to pass the condition of repentance,"], ["o soo se tasi e salamo o le a le tatuuina i lalo ma lafo i le afi;", "that whosoever repenteth the same is not hewn down and cast into the fire;"], ["ae o soo se tasi e le salamo o le a tatuuina i lalo ma lafo i le afi;", "but  whosoever repenteth not is hewn down and cast into the fire;"], ["ma toe oo mai i luga o i latou se oti faaleagaga,", "and there cometh upon them again a spiritual death,"], ["ioe,", "yea,"], ["o se oti faalua lea,", "a second death,"], ["ona ua toe vavae ese i latou mai mea e faatatau i le amiotonu.", "for they are cut off again as to things pertaining to righteousness."]]},
  {num:19,words:[["O lea ia outou salamo ai,", "Therefore repent ye,"], ["ia outou salamo,", "repent ye,"], ["nei o outou tuu atu outou lava i lalo o le faasalaga i le tou iloa o nei mea a ua le faia,", "lest by knowing these things and not doing them ye shall suffer yourselves to come under condemnation,"], ["ma aumai ai outou i lalo i lenei oti faalua.", "and ye are brought down unto this second death."]]},
  {num:20,words:[["Ae faauta,", "But behold,"], ["e pei ona ou fai atu ia te outou e uiga i se tasi faailoga ,", "as I said unto you concerning another sign,"], ["o se faailoga o lona maliu,", "a sign of his death,"], ["faauta,", "behold,"], ["i lena aso o le a mafatia ai o ia i le oti, o le a faapouliuligia ai le la ma musu e tuu mai lona malamalama ia te outou;", "in that day that he shall suffer death the sun shall be darkened and refuse to give his light unto you;"], ["ma o le a foi le masina ma fetu;", "and also the moon and the stars;"], ["ma o le a leai se malamalama i luga o le laueleele lenei,", "and there shall be no light upon the face of this land,"], ["mai lava i le taimi o le a mafatia ai o ia i le oti,", "even from the time that he shall suffer death,"], ["mo le va o aso e tolu,", "for the space of three days,"], ["e oo atu i le taimi o le a toetu mai ai o ia mai le oti.", "to the time that he shall rise again from the dead."]]},
  {num:21,words:[["Ioe,", "Yea,"], ["i le taimi o le a to atu ai e ia le agaga,", "at the time that he shall yield up the ghost there shall be thunderings and lightnings for the space of many hours,"], ["o le a i ai faititili ma uila mo le va o itula e tele,", "and the earth shall shake and tremble;"], ["ma o le a luluina eleele ma gatete;", "and the rocks which are upon the face of this earth,"], ["ma o papa o loo i ai nei i luga o lenei eleele, ia o loo i luga ma lalo o le eleele,", "which are both above the earth and beneath,"], ["ia ua outou iloa i le taimi nei ua malolo,", "which ye know at this time are solid,"], ["po o sona vaega tele o se papa malo e tasi,", "or the more part of it is one solid mass,"], ["o le a nutililiiina ;", "shall be broken up;"]]},
  {num:22,words:[["Ioe,", "Yea,"], ["o le a vaeluaina i latou;", "they shall be rent in twain,"], ["ma o le a maua i taimi uma mai i le taimi lena i mavaevae ma taetaei,", "and shall ever after be found in seams and in cracks,"], ["ma i nutigamaa i luga o le eleele atoa,", "and in broken fragments upon the face of the whole earth,"], ["ioe,", "yea,"], ["i luga ma lalo o le eleele.", "both above the earth and beneath."]]},
  {num:23,words:[["Ma faauta,", "And behold,"], ["o le a i ai afa tetele,", "there shall be great tempests,"], ["ma o le a tele mauga o i ai o le a soloia maualalalo,", "and there shall be many mountains laid low,"], ["e pei o se vanu,", "like unto a valley,"], ["ma e i ai nofoaga e tele ia ua taua nei o vanu o le a avea ma mauga,", "and there shall be many places which are now called valleys which shall become mountains,"], ["o lo latou uumi o le a maualuluga lava.", "whose height is great."]]},
  {num:24,words:[["Ma e tele aualatele o le a mavaevae,", "And many highways shall be broken up,"], ["ma e tele aai o le a tuufuaina.", "and many cities shall become desolate."]]},
  {num:25,words:[["Ma e tele tuugamau o le a lagaina,", "And many graves shall be opened,"], ["ma o le a latou tatala mai le toatele o a latou tagata oti;", "and shall yield up many of their dead;"], ["ma e toatele le au paia o le a faaali mai i le toatele.", "and many saints shall appear unto many."]]},
  {num:26,words:[["Ma faauta,", "And behold,"], ["sa faapea ona fetalai mai o le agelu ia te au;", "thus hath the angel spoken unto me;"], ["ona sa ia fetalai mai ia te au o le a i ai faititili ma uila mo le va o itula e tele.", "for he said unto me that there should be thunderings and lightnings for the space of many hours."]]},
  {num:27,words:[["Ma sa ia fetalai mai ia te au faapea ao i ai pea le faititili ma le uila,", "And he said unto me that while the thunder and the lightning lasted,"], ["ma le afa,", "and the tempest,"], ["o le a oo mai ia mea,", "that these things should be,"], ["ma o le a ufitia le eleele atoa i le pogisa mo le va o aso e tolu.", "and that darkness should cover the face of the whole earth for the space of three days."]]},
  {num:28,words:[["Ma sa fetalai mai le agelu ia te au e toatele o le a vaai i mea e sili atu i lo nei,", "And the angel said unto me that many shall see greater things than these,"], ["i le faamoemoe ia mafai ai ona latou talitonu o le a faataunuuina nei faailoga ma nei mea ofoofogia i luga o le laueleele atoa lenei,", "to the intent that they might believe that these signs and these wonders should come to pass upon all the face of this land,"], ["i le faamoemoe ia leai se pogai mo le le talitonu i totonu o le fanauga a tagata—", "to the intent that there should be no cause for unbelief among the children of men—"]]},
  {num:29,words:[["Ma ua faia nei mea i le faamoemoe ia mafai ai ona faaolaina o soo se tasi e talitonu,", "And this to the intent that whosoever will believe might be saved,"], ["ma ina ia mafai ai ona oo mai i luga o soo se tasi o i latou e le talitonu se faamasinoga amiotonu;", "and that whosoever will not believe,"], ["o lenei foi afai e tausalaina i latou,", "a righteous judgment might come upon them;"], ["ua latou aumai i o latou lava luga lo latou lava tausalaga.", "and also if they are condemned they bring upon themselves their own condem– nation."]]},
  {num:30,words:[["Ma o lenei ia outou manatua,", "And now remember,"], ["ia outou manatua,", "remember,"], ["ou uso e,", "my brethren,"], ["o soo se tasi e fano,", "that whosoever perisheth,"], ["e fano ia te ia lava;", "perisheth unto him– self;"], ["ma o soo se tasi na te faia le amioletonu,", "and whosoever doeth iniquity,"], ["e faia e ia ia te ia lava;", "doeth it unto himself;"], ["aua faauta,", "for behold,"], ["ua outou saoloto ;", "ye are free;"], ["ua faatagaina outou tou te fai mo outou lava;", "ye are permitted to act for yourselves;"], ["aua faauta,", "for behold,"], ["ua tuuina mai e le Atua ia te outou se malamalama ma ua ia faia outou ia outou saoloto.", "God hath given unto you a knowledge and he hath made you free."]]},
  {num:31,words:[["Ua ia tuuina mai ia te outou ia mafai ona outou iloa o le lelei mai le leaga,", "He hath given unto you that ye might know good from evil,"], ["ma ua ia tuuina mai ia te outou ia mafai ona outou filifili le ola po o le oti;", "and he hath given unto you that ye might choose life or death;"], ["ma e mafai ona outou faia le lelei ma toefuataia outou i le mea ua lelei,", "and ye can do good and be restored unto that which is good,"], ["pe toefuatai mai le mea lelei ia te outou;", "or have that which is good restored unto you;"], ["pe mafai foi ona outou faia le leaga,", "or ye can do evil,"], ["ma toefuatai mai le mea ua leaga ia te outou.", "and have that which is evil restored unto you."]]},
];
renderVerseSet(he_ch_14_Verses, 'he-ch14-verses');

var he_ch_15_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["ou uso pele e,", "my beloved brethren,"], ["faauta,", "behold,"], ["ou te tau atu ia te outou vagana ai ua outou salamo o le a tuua o outou fale ua tuufuaina mai ia te outou.", "I declare unto you that except ye shall repent your houses shall be left unto you desolate."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["vagana ai ua outou salamo o le a i ai se pogai tele o le a faanoanoa ai o outou fafine i le aso latou te failele ai;", "except ye repent,"], ["ona o le a outou taumafai e sosola ma o le a leai se mea tou te sulufai i ai;", "your women shall have great cause to mourn in the day that they shall give suck;"], ["ioe,", "for ye shall attempt  to flee and there shall be no place for refuge;"], ["ma oi talofa i e e maitaga ,", "yea, and wo unto them which are with child,"], ["ona o le a latou mamafa ma le mafai ona sosola;", "for they shall be heavy and cannot flee;"], ["o lea,", "therefore,"], ["o le a soli i latou i lalo ma o le a tuu e fano.", "they shall be trodden down and shall be left to perish."]]},
  {num:3,words:[["Ioe,", "Yea,"], ["oi talofa i lenei nuu o e ua taua o le nuu o Nifae pe a latou vaai i nei faailoga uma ma mea ofoofogia vagana ai ua latou salamo;", "wo unto this people who are called the people of Nephi except they shall repent,"], ["aua faauta,", "when they shall see all these signs and wonders which shall be showed unto them;"], ["sa avea i latou o ni tagata filifilia o le Alii;", "for behold,"], ["ioe,", "they have been a chosen people of the Lord; yea,"], ["sa alofa o ia i tagata o Nifae,", "the people of Nephi hath he loved,"], ["ma sa ia aoaiina foi i latou;", "and also hath he chastened them;"], ["ioe,", "yea,"], ["sa ia aoaiina i latou i aso o lo latou amioletonu ona e alofa o ia ia te i latou.", "in the days of their iniquities hath he chastened them because he loveth them."]]},
  {num:4,words:[["Ae faauta,", "But behold my brethren,"], ["ou uso e, sa inoino o ia ia sa Lamanā ona sa leaga e le aunoa a latou mea sa fai,", "the Lamanites hath he hated because their deeds have been evil continually,"], ["ma o le pogai o lenei mea ona o le amioletonu o le uputuu a o latou tamā.", "and this because of the iniquity of the tradition of their fathers."], ["Ae faauta,", "But behold,"], ["ua oo mai le olataga ia te i latou ona o le talaiga a sa Nifaē;", "salvation hath come unto them through the preaching of the Nephites;"], ["ma o le faamoemoe lenei na faalevalevaina ai e le Alii o latou aso.", "and for this intent hath the Lord prolonged their days."]]},
  {num:5,words:[["Ma ou te manao ina ia outou vaai o le vaega tele o i latou o loo i ai i le ala o lo latou tiute,", "And I would that ye should behold that the more part of them are in the path of their duty,"], ["ma ua latou savavali ma le migao i luma o le Atua, ma ua latou tausisi e tausi ana poloaiga ma ana tulafono ma ana faamasinoga,", "and they do walk circumspectly before God,"], ["e tusa ma le tulafono a Mose.", "and they do observe to keep his command– ments and his statutes and his judgments according to the law of Moses."]]},
  {num:6,words:[["Ioe,", "Yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o le vaega tele o i latou o loo latou faia lenei mea,", "that the more part of them are doing this,"], ["ma o loo latou taumafai ma le filiga e le faavaivai ina ia mafai ona latou aumai o e o totoe o o latou uso i le malamalama o le upumoni;", "and they are striving with unwearied diligence that they may bring the remainder of their brethren to the knowledge of  the truth;"], ["o lea e toatele e ua faaopoopo i lo latou aofai i aso taitasi.", "therefore there are many who do add to their numbers daily."]]},
  {num:7,words:[["Ma faauta,", "And behold,"], ["ua outou iloa mo outou lava,", "ye do know of yourselves,"], ["ona ua outou molimauina,", "for ye have witnessed it,"], ["o le toatele o i latou o e ua aumai i le malamalama o le upumoni,", "that as many of them as are brought to the knowledge of the truth,"], ["ma ia latou iloa le leaga ma le inosia o uputuu a o latou tamā,", "and to know of the wicked and abominable traditions of their fathers,"], ["ma ua taitai atu ia talitonu i tusitusiga paia,", "and are led to believe the holy scriptures,"], ["ioe,", "yea,"], ["i valoaga a perofeta paia,", "the prophecies of the holy prophets,"], ["ia ua tusia,", "which are written,"], ["ia ua taitai atu ai i latou i le faatuatua i le Alii,", "which leadeth them to faith on the Lord,"], ["ma i le salamo,", "and unto repentance,"], ["le faatuatua ma le salamo lea ua aumai ai se liliuga o le loto ia te i latou—", "which faith and repentance bringeth a change of heart unto them—"]]},
  {num:8,words:[["O lea,", "Therefore,"], ["o le toatele o i latou ua o mai i lenei malamalama o le upumoni,", "as many as have come to this,"], ["ua outou iloa mo outou lava ua tutumau ma mausali i latou i le faatuatua,", "ye know of yourselves are firm and steadfast in the faith,"], ["ma i mea ia ua faasaolotoina ai i latou.", "and in the thing wherewith they have been made free."]]},
  {num:9,words:[["Ma ua outou iloa foi ua latou tanumia a latou auupega o taua,", "And ye know also that they have buried their weapons of war,"], ["ma ua latou fefefe e fetagofi i ai nei i ai se ala o le a latou agasala ai;", "and they fear to take them up lest by any means they should sin;"], ["ioe,", "yea,"], ["e mafai ona outou vaai ua latou fefefe e agasala—aua faauta o le a latou tuu atu i latou lava ia soli i lalo ma fasioti e o latou fili,", "ye can see that they fear to sin—for behold they will suffer themselves that they be trodden down and slain by their enemies,"], ["ma o le a latou le sii ae a latou pelu e faasaga ia te i latou,", "and will not lift their swords against them,"], ["ma ua latou faia lenei mea ona o lo latou faatuatua ia Keriso.", "and this because of their faith in Christ."]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["ona o lo latou mausali ina ua latou talitonu i lena mea ua latou talitonu i ai,", "because of their steadfastness when they do believe in that thing which they do believe,"], ["ona o lo latou tutumau ina ua faamalamalama i latou,", "for because of their firmness when they are once enlightened,"], ["faauta,", "behold,"], ["o le a faamanuiaina i latou e le Alii ma ia faalevalevaina o latou aso,", "the Lord shall bless them and prolong their days,"], ["e ui i lo latou amioletonu—", "notwithstanding their iniquity—"]]},
  {num:11,words:[["Ioe,", "Yea,"], ["e tusa pe o le a faaitiitia i latou i le le talitonu,", "even if they should dwindle in unbelief the Lord shall prolong their days,"], ["o le a faalevalevaina e le Alii o latou aso,", "until the time shall come which hath been spoken of by our fathers,"], ["seia oo ina oo mai le taimi lea na tautatala i ai o tatou tamā,", "and also by the prophet Zenos,"], ["ma le perofeta foi o Senosa , ma le toatele o isi perofeta,", "and many other prophets,"], ["e faatatau i le toefuataiga o o tatou uso,", "concerning the restoration of our brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["i le malamalama o le upumoni—", "again to the knowledge of the truth—"]]},
  {num:12,words:[["Ioe,", "Yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua faaoo atu i aso e gata ai folafolaga a le Alii i o tatou uso,", "that in the latter times the promises of the Lord have been extended to our brethren,"], ["o sa Lamanā;", "the Lamanites;"], ["ma e ui i le tele o puapuaga ia o le a oo ia te i latou,", "and notwithstanding the many afflictions which they shall have,"], ["ma e ui ina o le a tutulia i latou i lea mea ma lea mea i luga o le eleele,", "and notwithstanding they shall be driven to and fro upon the face of the earth,"], ["ma sailia,", "and be hunted,"], ["ma o le a taiaina ma faataapeape solo,", "and shall be smitten and scattered abroad,"], ["ua leai se mea mo i latou e sulu i ai,", "having no place for refuge,"], ["o le a alofa mutimutivale le Alii ia te i latou.", "the Lord shall be merciful unto them."]]},
  {num:13,words:[["Ma ua tusa ai lenei mea ma le valoaga,", "And this is according to the prophecy,"], ["e faapea o le a toe aumai i latou i le malamalama moni,", "that they shall again be brought to the true know– ledge,"], ["o le malamalama lea o lo latou Togiola,", "which is knowledge of their Redeemer,"], ["ma lo latou leoleo mamoe sili ma le faamaoni,", "and their great and true shepherd,"], ["ma faitauina i totonu o ana mamoe.", "and be numbered among his sheep."]]},
  {num:14,words:[["O lea ou te fai atu ai ia te outou,", "Therefore I say unto you,"], ["o le a sili ona lelei mo i latou nai lo outou vagana ai ua outou salamo.", "it shall be better for them than for you except ye repent."]]},
  {num:15,words:[["Aua faauta,", "For behold,"], ["pe a na faaali atu ia te i latou galuega mamana ia ua faaali atu ia te outou,", "had the mighty works been shown unto them which have been shown unto you,"], ["ioe,", "yea,"], ["ia te i latou o e ua faaitiitia i le le talitonu ona o uputuu a o latou tamā,", "unto them who have dwindled in unbelief because of the traditions of their fathers,"], ["e mafai ona outou vaai mo outou lava po ua le mafai ona toe faaitiitia i latou i le le talitonu.", "ye can see of yourselves that they never would again have dwindled in unbelief."]]},
  {num:16,words:[["O lea,", "Therefore,"], ["ua fetalai mai le Alii:", "saith the Lord:"], ["O le a ou le faaumatiaina atoa i latou,", "I will not utterly destroy them,"], ["ae o le a ou faia i le aso e tusa ai ma lou poto o le a latou toe foi mai ai ia te au,", "but I will cause that in the day of my wisdom they shall return again unto me,"], ["ua fetalai mai ai le Alii.", "saith the Lord."]]},
  {num:17,words:[["Ma o lenei faauta,", "And now behold,"], ["ua fetalai mai le Alii,", "saith the Lord,"], ["e faatatau i tagata o sa Nifaē: Afai latou te le salamo,", "concerning the people of the Nephites:"], ["ma tausisi e fai lou loto,", "If they will not repent,"], ["o le a ou faaumatia atoa i latou,", "and observe to do my will,"], ["ua fetalai mai ai le Alii,", "I will utterly destroy them,"], ["ona o lo latou le talitonu,", "saith the Lord,"], ["e ui i le tele o galuega mamana ua ou faia i totonu ia te i latou; ma e pei ona mautinoa o loo soifua le Alii,", "because of their unbelief notwithstanding the many mighty works which I have done among them;"], ["o le a faataunuuina lava nei mea,", "and as surely as the Lord liveth shall these things be,"], ["ua fetalai mai ai le Alii.", "saith the Lord."]]},
];
renderVerseSet(he_ch_15_Verses, 'he-ch15-verses');

var he_ch_16_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["sa oo ina sa toatele i latou o e na faalologo i upu a Samuelu,", "it came to pass that there were many who heard the words of Samuel,"], ["le sa Lamanā,", "the Lamanite,"], ["ia na ia tautala atu ai i luga o pa o le aai. Ma o le toatele o i latou o e na talitonu i ana upu sa o atu ma saili mo Nifae;", "which he spake upon the walls of the city. And as many as believed on his word went forth and sought for Nephi;"], ["ma ina ua latou o atu ma ua maua o ia sa latou tautau atu ia te ia a latou agasala ma latou le faafitia,", "and when they had come forth and found him they confessed unto him their sins and denied not,"], ["ua mananao ia papatisoina i latou mo le Alii.", "desiring that they might be baptized unto the Lord."]]},
  {num:2,words:[["Ae o le toatele o i latou sa i ai o e sa le talitonu i upu a Samuelu sa feita ia te ia;", "But as many as there were who did not believe in the words of Samuel were angry with him;"], ["ma sa latou fetogi atu maa ia te ia i luga o le pa,", "and they cast stones at him upon the wall,"], ["ma e toatele foi na latou tafana au ia te ia ao tu o ia i luga o le pa;", "and also many shot arrows at him as he stood upon the wall;"], ["peitai sa faatasi le Agaga o le Alii ma ia,", "but the Spirit of the Lord was with him,"], ["sa oo ina le mafai ona lavea o ia ia latou maa po o a latou au.", "insomuch that they could not hit him with their stones neither with their arrows."]]},
  {num:3,words:[["O lenei ina ua latou vaai ua le mafai ona lavea o ia ia i latou,", "Now when they saw that they could not hit him,"], ["sa i ai ni isi e toatele atu o e sa talitonu i ana upu,", "there were many more who did believe on his words,"], ["sa oo ina latou o atu ia Nifae ina ia papatisoina i latou.", "insomuch that they went away unto Nephi to be baptized."]]},
  {num:4,words:[["Aua faauta,", "For behold,"], ["o le taimi lea o papatiso atu Nifae,", "Nephi was baptizing,"], ["ma vavalo atu,", "and prophesying,"], ["ma talai atu,", "and preaching,"], ["ma alaga atu le salamo i tagata,", "crying repentance unto the people,"], ["ma faaali atu faailoga ma mea ofoofogia,", "showing signs and wonders,"], ["ma faia vavega i totonu o tagata,", "working miracles among the people,"], ["ina ia latou iloa ai ua lata ona afio mai o Keriso—", "that they might know that the Christ must shortly come—"]]},
  {num:5,words:[["Ma tau atu ia te i latou mea ua lata ona oo mai,", "Telling them of things which must shortly come,"], ["ina ia latou iloa ma manatua i le taimi o lo latou oo mai, sa faailoa atu ia te i latou ae lei oo mai,", "that they might know and remember at the time of their coming that they had been made known unto them beforehand,"], ["i le faamoemoe ia latou talitonu ai;", "to the intent that they might believe;"], ["o lea na o atu ai ia te ia le toatele o i latou o e na talitonu i upu a Samuelu, ina ia papatiso,", "therefore as many as believed on the words of Samuel went forth unto him to be baptized,"], ["ona sa latou o mai ma le salamo ma le tautino mai o a latou agasala.", "for they came repenting and confessing their sins."]]},
  {num:6,words:[["Ae o le vaega toatele atu o i latou sa le talitonu i upu a Samuelu;", "But the more part of them did not believe in the words of Samuel;"], ["o lea ina ua latou vaai atu ua le mafai ona lavea o ia ia latou maa ma a latou au,", "therefore when they saw that they could not hit him with their stones and their arrows,"], ["sa latou valaau atu i o latou kapeteni,", "they cried unto their captains,"], ["ua fai atu:", "saying:"], ["Ave le tagata lenei ma saisai o ia,", "Take this fellow and bind him,"], ["ona faauta ua ia te ia se tiapolo;", "for behold he hath a devil;"], ["ma ona o le mana o le tiapolo lea ua ia te ia ua le mafai ai ona lavea o ia ia matou maa ma a matou au;", "and because of the power of the devil which is in him we cannot hit him with our stones and our arrows;"], ["o lea ia ave o ia ma saisai o ia,", "therefore take him and bind him,"], ["ma aveese atu.", "and away with him."]]},
  {num:7,words:[["Ma ina ua latou o atu e fetagofi atu o latou lima ia te ia,", "And as they went forth to lay their hands on him,"], ["faauta,", "behold,"], ["sa oso ifo o ia i lalo mai le pa,", "he did cast himself down from the wall,"], ["ma sola atu i fafo mai lo latou laueleele,", "and did flee out of their lands,"], ["ioe,", "yea,"], ["i lona lava atunuu,", "even  unto his own country,"], ["ma amata ona talai ma vavalo atu i totonu o ona lava tagata.", "and began to preach and to prophesy among his own people."]]},
  {num:8,words:[["Ma faauta,", "And behold,"], ["sa le toe faalogoina lava o ia i totonu o tagata sa Nifaē;", "he was never heard of more among the Nephites;"], ["ma sa faapea mataupu sa i ai i le nuu.", "and thus were the affairs of the people."]]},
  {num:9,words:[["Ma sa faapea ona iu o le tausaga e valusefulu ma le ono o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the eighty and sixth year of the reign of the judges over the people of Nephi."]]},
  {num:10,words:[["Ma sa faapea foi ona iu o le tausaga e valusefulu ma le fitu o le nofoaiga a faamasino,", "And thus ended also the eighty and seventh year of the reign of the judges,"], ["o le vaega toatele o tagata sa tutumau pea i lo latou faamaualuluga ma le amioleaga,", "the more part of the people remaining in their pride and wickedness,"], ["ma o le vaega toaitiiti sa savavali ma le migao i luma o le Atua.", "and the lesser part walking more circumspectly before God."]]},
  {num:11,words:[["Ma o tulaga foi ia,", "And these were the conditions also,"], ["i le tausaga e valusefulu ma le valu o le nofoaiga a faamasino.", "in the eighty and eighth year of the reign of the judges."]]},
  {num:12,words:[["Ma sa nao sina suiga itiiti sa i ai i mataupu o le nuu,", "And there was but little alteration in the affairs of the people,"], ["vagana ai le amata ona atili maaa o tagata i le amioletonu,", "save it were the people began to be more hardened in iniquity,"], ["ma fai ma saga fai tele o mea sa le talafeagai ma poloaiga a le Atua,", "and do more and more of that which was contrary to the commandments of God,"], ["i le tausaga e valusefulu ma le iva o le nofoaiga a faamasino.", "in the eighty and ninth year of the reign of the judges."]]},
  {num:13,words:[["Peitai sa oo i le tausaga e ivasefulu o le nofoaiga a faamasino,", "But it came to pass in the ninetieth year of the reign of the judges,"], ["sa i ai faailoga tetele ma mea ofoofogia na tuuina mai i tagata;", "there were great signs given unto the people, and wonders;"], ["ma sa amata ona faataunuuina upu a perofeta.", "and the words of the prophets began to be fulfilled."]]},
  {num:14,words:[["Ma sa oo mai agelu i tagata,", "And angels did appear unto men,"], ["o tagata popoto,", "wise men,"], ["ma sa talai mai ia te i latou tala fiafia o le olioli tele;", "and did declare unto them glad tidings of great joy;"], ["sa faapea ona amata i le tausaga lenei ona faataunuuina o tusitusiga paia.", "thus in this year the scriptures began to be fulfilled."]]},
  {num:15,words:[["E ui i lea,", "Nevertheless,"], ["sa amata ona faamaaa e tagata o latou loto,", "the people began to harden their hearts,"], ["tagata uma ia vagana ai le vaega sa sili ona talitonu o i latou,", "all save it were the most believing part of them,"], ["o sa Nifaē ma sa Lamanā foi,", "both of the Nephites and also of the Lamanites,"], ["ma amata ona latou faalagolago i lo latou lava malolosi ma lo latou lava popoto,", "and began to depend upon their own strength and upon their own wisdom,"], ["fai mai:", "saying:"]]},
  {num:16,words:[["Atonu e i ai ni isi mea sa latou mateina sao,", "Some things they may have guessed right,"], ["mai totonu o mea e tele;", "among so many;"], ["ae faauta,", "but behold,"], ["ua matou iloa e le mafai ona faataunuuina o nei galuega uma tetele ma ofoofogia,", "we know that all these great and marvelous works cannot come to pass,"], ["ia ua taua.", "of which has been spoken."]]},
  {num:17,words:[["Ma sa amata ona latou talanoa ma fefinauai i totonu ia te i latou lava,", "And they began to reason and to contend among themselves,"], ["fai mai:", "saying:"]]},
  {num:18,words:[["E lē o se mea ua tonu i le mafaufau le afio mai o se tagata ua faapea o se Keriso;", "That it is not reasonable that such a being as a Christ shall come;"], ["afai e i ai,", "if so,"], ["ma o ia o le Alo o le Atua,", "and he be the Son of God,"], ["le Tamā o le lagi ma le lalolagi,", "the Father of heaven and of earth,"], ["e pei ona taua mai,", "as it has been spoken,"], ["aisea e le faaali mai ai e ia o ia lava ia te i tatou e faapei foi ia te i latou o e o le a i ai i Ierusalema?", "why will he not show himself unto us as well as unto them who shall be at Jerusalem?"]]},
  {num:19,words:[["Ioe,", "Yea,"], ["aisea o le a ia le faaali mai ai o ia lava i lenei laueleele e faapei foi i le laueleele o Ierusalema?", "why will he not show himself in this land as well as in the land of Jerusalem?"]]},
  {num:20,words:[["Ae faauta,", "But behold,"], ["ua tatou iloa o se uputuu amioleaga lenei,", "we know that this is a wicked tradition,"], ["lea na tuulima faasolo mai ia te i tatou e o tatou tamā,", "which has been handed down unto us by our fathers,"], ["e tosina ai i tatou ia tatou talitonu i ni mea maoae ma ofoofogia o le a oo mai,", "to cause us that we should believe in some great and marvelous thing which should come to pass,"], ["ae le i totonu ia te i tatou,", "but not among us,"], ["ae i se laueleele ua mamao lava,", "but in a land which is far distant,"], ["o se laueleele ua tatou le iloa;", "a land which we know not;"], ["o lea e mafai ai ona latou taofia i tatou i le valea,", "therefore they can keep us in ignorance,"], ["ona e le mafai ona tatou molimauina i o tatou lava mata ua moni i latou.", "for we cannot witness with our own eyes that they are true."]]},
  {num:21,words:[["Ma o le a latou faia ai,", "And they will,"], ["e ala i le faitogafiti ma tomai faalilolilo o le ua leaga,", "by the cunning and the mysterious arts of the evil one,"], ["se mea lilo tele e le mafai ona tatou malamalama i ai,", "work some great mystery which we cannot understand,"], ["lea o le a taofia ai i tatou i lalo e avea ma ni auauna ia latou upu,", "which will keep us down to be servants to their words,"], ["ma ni auauna foi ia te i latou,", "and also servants unto them,"], ["ona ua tatou faalagolago ia te i latou e aoao mai ia te i tatou le afioga;", "for we depend upon them to teach us the word;"], ["ma o le a faapea ona latou taofia ai i tatou i le valea pe afai tatou te tuu atu i tatou lava ia te i latou,", "and thus will they keep us in ignorance if we will yield ourselves unto them,"], ["i aso uma o o tatou olaga.", "all the days of our lives."]]},
  {num:22,words:[["Ma e tele atu isi mea sa mafaufauina e tagata i o latou loto,", "And many more things did the people imagine up in their hearts,"], ["o mea valea ma le le aoga;", "which were foolish and vain;"], ["ma sa latou louloua tele,", "and they were much disturbed,"], ["ona sa faaosoina i latou e Satani e fai le amioletonu e le aunoa;", "for Satan did stir them up to do iniquity continually;"], ["ioe,", "yea,"], ["sa ia fealuai ma faasalalau fafatala ma finauga i luga o le laueleele atoa,", "he did go about spreading rumors and contentions upon all the face of the land,"], ["ina ia mafai ona ia faamaaaina loto o tagata e faasaga i mea lelei ma faasaga i mea o le a oo mai.", "that he might harden the hearts of the people against that which was good and against that which should come."]]},
  {num:23,words:[["Ma e ui i faailoga ma mea ofoofogia ia na faia i totonu o tagata o le Alii,", "And notwithstanding the signs and the wonders which were wrought among the people of the Lord,"], ["ma le tele o vavega na latou faia,", "and the many miracles which they did,"], ["sa malosi tele le uu a Satani i loto o tagata i luga o le laueleele atoa.", "Satan did get great hold upon the hearts of the people upon all the face of the land."]]},
  {num:24,words:[["Ma sa faapea ona iu o le tausaga e ivasefulu o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the ninetieth year of the reign of the judges over the people of Nephi."]]},
  {num:25,words:[["Ma ua faapea ona iu o le tusi", "and thus then attain the book"], ["a Helamana,", "but Helaman"], ["e tusa ma le talafaamaumau", "to according to and the record"], ["a Helamana", "but Helaman"], ["ma ona atalii.", "and then son"]]},
];
renderVerseSet(he_ch_16_Verses, 'he-ch16-verses');

})();